"use strict";(globalThis.webpackChunkmy_blog=globalThis.webpackChunkmy_blog||[]).push([[5795],{72021(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/doc-to-rag-benchmark","metadata":{"permalink":"/projects/doc-to-rag-benchmark","source":"@site/projects/doc-to-rag-benchmark.md","title":"Doc-to-RAG Benchmark","description":"Doc-to-Text\uc5d0\uc11c \ud3c9\uac00 \uac00\ub2a5\ud55c RAG \ub370\uc774\ud130\uae4c\uc9c0 | Meta Llama Academy \uc6cc\ud06c\uc20d\uc5d0\uc11c \uc9c4\ud589\ud55c PDF \uae30\ubc18 Doc-to-RAG Benchmark \uad6c\ucd95 \ud504\ub85c\uc81d\ud2b8 \ud68c\uace0","date":"2026-06-28T23:16:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"Doc-to-RAG Benchmark","description":"Doc-to-Text\uc5d0\uc11c \ud3c9\uac00 \uac00\ub2a5\ud55c RAG \ub370\uc774\ud130\uae4c\uc9c0 | Meta Llama Academy \uc6cc\ud06c\uc20d\uc5d0\uc11c \uc9c4\ud589\ud55c PDF \uae30\ubc18 Doc-to-RAG Benchmark \uad6c\ucd95 \ud504\ub85c\uc81d\ud2b8 \ud68c\uace0","role":"AI Engineer","timeline":"Sep 2025 - Oct 2025","stack":["LangGraph","Upstage API","Solar Pro 2","Llama 3.2","PDF Parsing","QLoRA"],"category":"Team Project","image":"/img/projects/doc-to-rag-benchmark/experience/experience-01-expanded.png","hide_table_of_contents":false},"unlisted":false,"nextItem":{"title":"nano-vllm","permalink":"/projects/nano-vllm"}},"content":"{/* truncate */}\\n\\n# Doc-to-RAG Benchmark\\n\\n## \uc65c \uc774 \ud504\ub85c\uc81d\ud2b8\ub97c \uc2dc\uc791\ud588\ub294\uac00\\n\\n\uc6cc\ud06c\uc20d \ucd08\ubc18\uc5d0 \uac00\uc7a5 \ud06c\uac8c \ub290\ub080 \ubb38\uc81c\ub294 \ub2e8\uc21c\ud588\ub2e4. RAG \uc131\ub2a5 \ube44\uad50\ub97c \ud558\ub824\uba74 \uba3c\uc800 \\"\ube44\uad50 \uac00\ub2a5\ud55c \ub370\uc774\ud130\\"\uac00 \uc788\uc5b4\uc57c \ud558\ub294\ub370, PDF \ubb38\uc11c\ub294 \ud30c\uc11c\ub9c8\ub2e4 \uacb0\uacfc\uac00 \ub2ec\ub77c\uc11c \uac19\uc740 \uc9c8\ubb38\uc5d0\ub3c4 \uae30\uc900\uc774 \ud754\ub4e4\ub838\ub2e4.\\n\\n\ub0b4\uac00 \ud300\uc5d0\uc11c \ud569\uc758\ud55c \ubc29\ud5a5\uc740 \\"\ubaa8\ub378 \uc790\ub791\\"\uc774 \uc544\ub2c8\ub77c \\"\ud3c9\uac00 \uae30\uc900 \uace0\uc815\\"\uc774\uc5c8\ub2e4. \ubb38\uc11c \ucd94\ucd9c\ubd80\ud130 QA \uc0dd\uc131, Judge \uac80\uc99d, \ub370\uc774\ud130\uc14b \uc800\uc7a5\uae4c\uc9c0 \ud55c \ud750\ub984\uc73c\ub85c \ubb36\uc5b4\uc57c \uc7ac\ud604 \uac00\ub2a5\ud55c \uc2e4\ud5d8\uc774 \ub41c\ub2e4\uace0 \ubd24\ub2e4.\\n\\n## \ud300 \uad6c\uc131\uacfc \uc5ed\ud560\\n\\n\ud300\uc740 \uc544\ub798\ucc98\ub7fc \ub098\ub220\uc11c \uc77c\ud588\ub2e4.\\n\\n1. \ud504\ub85c\uc81d\ud2b8 \ucd1d\uad04 \ub9ac\ub354: \ubc29\ud5a5\uc131, \uc6b0\uc120\uc21c\uc704, \uc77c\uc815 \uad00\ub9ac\\n2. \ud504\ub860\ud2b8\uc5d4\ub4dc + \ubc31\uc5d4\ub4dc: \ub370\ubaa8 \ubc0f \uc11c\ube44\uc2a4 \uc5f0\uacb0\\n3. \uba40\ud2f0 \uc5d0\uc774\uc804\ud2b8 \uad6c\ud604: \ud30c\uc2f1/\uc815\uc81c \uadf8\ub798\ud504 \uc124\uacc4\\n4. \ub370\uc774\ud130/\ud3c9\uac00 \ud30c\uc774\ud504\ub77c\uc778: \ucd94\ucd9c \ud14d\uc2a4\ud2b8 \uae30\ubc18 \ubca4\uce58\ub9c8\ud06c + LLM Judge + Hugging Face \uc5c5\ub85c\ub4dc\\n5. \ub098: QLoRA \uae30\ubc18 \ud30c\uc778\ud29c\ub2dd \uc2e4\ud5d8 \uc124\uacc4 \ubc0f \uc6b4\uc601\\n\\n\ub0b4\uac00 \ub9e1\uc740 \ube44\uc911\uc740 5\ubc88\uc774 \uac00\uc7a5 \ucef8\ub2e4. \ud504\ub85c\uc81d\ud2b8 \uc804\uccb4 \uc131\ub2a5\uc5d0\uc11c \ud30c\uc778\ud29c\ub2dd\uc774 \uc2e4\uc81c\ub85c \uc758\ubbf8 \uc788\ub294 \uac1c\uc120\uc744 \ub0b4\ub294\uc9c0, \uadf8\ub9ac\uace0 \uadf8 \uacb0\uacfc\ub97c \uc6b4\uc601 \uac00\ub2a5\ud55c \ud615\ud0dc\ub85c \ub0a8\uae30\ub294 \ub370 \uc9d1\uc911\ud588\ub2e4.\\n\\n## \ud300 \uc5ed\ud560\ubcc4 \uc0c1\uc138 \uc124\uba85(\ub0b4 \uc5ed\ud560 \uc678)\\n\\n\ucd08\uae30 \ubb38\uc11c\uc5d0\uc11c \uac15\uc870\ud588\ub358 \uac83\ucc98\ub7fc, \uc774 \ud504\ub85c\uc81d\ud2b8\ub294 \ud55c \uc0ac\ub78c\uc758 \ubaa8\ub378 \uc2e4\ud5d8\uc73c\ub85c \uc644\uc131\ub41c \uac8c \uc544\ub2c8\ub77c \uac01 \ucd95\uc774 \ub9de\ubb3c\ub824\uc11c \ub3cc\uc544\uac04 \uacb0\uacfc\uc600\ub2e4. \uadf8\ub798\uc11c \ub0b4 \uc5ed\ud560 \uc678\uc758 \ucd95\ub3c4 \uad6c\ud604 \uad00\uc810\uc73c\ub85c \uc815\ub9ac\ud574 \ub450\ub294 \uac8c \ub9de\ub2e4.\\n\\n### 1) \ud504\ub85c\uc81d\ud2b8 \ucd1d\uad04 \ub9ac\ub354: \ubc29\ud5a5\uc131\uacfc \uc758\uc0ac\uacb0\uc815 \ud504\ub808\uc784 \uace0\uc815\\n\\n\ucd1d\uad04 \ub9ac\ub354\ub294 \ub2e8\uc21c \uc77c\uc815 \uad00\ub9ac\uac00 \uc544\ub2c8\ub77c, \uc6b0\ub9ac\uac00 \\"\ubb34\uc5c7\uc744 \uc131\uacf5\uc73c\ub85c \ubcfc\uc9c0\\"\ub97c \uba3c\uc800 \uace0\uc815\ud588\ub2e4.\\n\\n1. \ubaa9\ud45c\ub97c \\"\ucd5c\uace0 \uc131\ub2a5 \ubaa8\ub378 \ucc3e\uae30\\"\uac00 \uc544\ub2c8\ub77c \\"\uc7ac\ud604 \uac00\ub2a5\ud55c Doc-to-RAG \ud30c\uc774\ud504\ub77c\uc778 \uad6c\ucd95\\"\uc73c\ub85c \uc815\ub82c\\n2. \uc6b0\uc120\uc21c\uc704\ub97c \uae30\ub2a5 \ub098\uc5f4\uc774 \uc544\ub2c8\ub77c \ubcd1\ubaa9 \ud574\uc18c \uc21c\uc11c(\ucd94\ucd9c -> \uac80\uc99d -> \uc815\uc81c -> \ud3c9\uac00)\ub85c \uc124\uc815\\n3. \ubc1c\ud45c/\ub370\ubaa8 \uba54\uc2dc\uc9c0\ub97c \uc218\uce58 \uacfc\uc2dc\ubcf4\ub2e4 \uc6b4\uc601 \uac00\ub2a5\uc131(\ube44\uc6a9/\uc18d\ub3c4/\ud488\uc9c8 \uade0\ud615) \uc911\uc2ec\uc73c\ub85c \ud1b5\uc77c\\n\\n\uc774 \uc815\ub82c \ub355\ubd84\uc5d0 \ud300\uc774 \uac01\uc790 \ub2e4\ub978 \ubaa8\ub4c8\uc744 \uac1c\ubc1c\ud574\ub3c4 \ucd5c\uc885 \uc0b0\ucd9c\ubb3c\uc774 \ud55c \ubc29\ud5a5\uc73c\ub85c \uc218\ub834\ud588\ub2e4.\\n\\n### 2) \ud504\ub860\ud2b8\uc5d4\ub4dc + \ubc31\uc5d4\ub4dc: \ub370\ubaa8\ub97c \\"\uc2e4\uc81c \ub3d9\uc791 \ud750\ub984\\"\uc73c\ub85c \uc5f0\uacb0\\n\\n\ud504\ub860\ud2b8/\ubc31\uc5d4\ub4dc \ub2f4\ub2f9\uc790\ub294 \ud30c\uc774\ud504\ub77c\uc778 \ub2e8\uacc4\ub97c \ud654\uba74\uc5d0\uc11c \ub04a\uae40 \uc5c6\uc774 \ud655\uc778\ud560 \uc218 \uc788\uac8c \ubb36\uc5c8\ub2e4.\\n\\n1. \uc785\ub825 \ubb38\uc11c\ubd80\ud130 \ucd94\ucd9c \uacb0\uacfc, \uac80\uc99d \uc0c1\ud0dc, \uc815\uc81c \uacb0\uacfc, \ucd5c\uc885 \uc120\ud0dd \uacb0\uacfc\uae4c\uc9c0 \ub2e8\uacc4\ubcc4\ub85c \uc2dc\uac01\ud654\\n2. \ubc31\uc5d4\ub4dc\uc5d0\uc11c \uac01 \ub2e8\uacc4 \uc0b0\ucd9c\ubb3c(JSON/\ub85c\uadf8)\uc744 \ud504\ub860\ud2b8\uc5d0\uc11c \uc7ac\uc0ac\uc6a9 \uac00\ub2a5\ud55c \ud3ec\ub9f7\uc73c\ub85c \uc804\ub2ec\\n3. \ub370\ubaa8 \uc2dc\ub098\ub9ac\uc624 \uae30\uc900\uc73c\ub85c \uc2e4\ud328 \ucf00\uc774\uc2a4\uc640 \uc131\uacf5 \ucf00\uc774\uc2a4\ub97c \uac19\uc740 \ud750\ub984\uc5d0\uc11c \ube44\uad50 \uac00\ub2a5\ud558\uac8c \uad6c\uc131\\n\\n\uacb0\uacfc\uc801\uc73c\ub85c \ubc1c\ud45c \ub54c \\"\ubaa8\ub378\uc774 \uc88b\ub2e4\\"\uac00 \uc544\ub2c8\ub77c \\"\uc2dc\uc2a4\ud15c\uc774 \uc5b4\ub5bb\uac8c \uc758\uc0ac\uacb0\uc815\ud558\ub294\uc9c0\\"\ub97c \ubcf4\uc5ec\uc904 \uc218 \uc788\uc5c8\ub2e4.\\n\\n### 3) \uba40\ud2f0 \uc5d0\uc774\uc804\ud2b8 \uad6c\ud604: \ud30c\uc2f1/\uc815\uc81c \uadf8\ub798\ud504\ub97c \uc6b4\uc601 \uac00\ub2a5\ud55c \uad6c\uc870\ub85c \uad6c\ud604\\n\\n\uba40\ud2f0 \uc5d0\uc774\uc804\ud2b8 \ub2f4\ub2f9\uc790\ub294 LangGraph \uae30\ubc18\uc73c\ub85c \ub450 \ucd95\uc744 \ubd84\ub9ac\ud588\ub2e4.\\n\\n1. OCR/\ud30c\uc2f1 \uc804\ub7b5 \uc120\ud0dd \uadf8\ub798\ud504: \uae30\ubcf8 \ucd94\ucd9c -> \uc720\ud6a8\uc131 \uac80\uc99d -> Judge -> \ucd5c\uc885 \uc120\ud0dd\\n2. Refine \uadf8\ub798\ud504: \uc815\uc81c \ud544\uc694 \uc5ec\ubd80 \ud310\ub2e8 -> \ud544\uc694\ud55c \ud398\uc774\uc9c0\ub9cc \uc815\uc81c -> \uc7ac\uac80\uc99d\\n\\n\ud575\uc2ec \uad6c\ud604 \ud3ec\uc778\ud2b8\ub294 \ud398\uc774\uc9c0 \ub2e8\uc704 \ud3f4\ubc31\uacfc \uc870\uae30 \uc911\ub2e8\uc774\uc5c8\ub2e4.\\n\\n1. \uc804\uccb4 \ubb38\uc11c\uac00 \uc544\ub2c8\ub77c Fail \ud398\uc774\uc9c0\uc5d0\ub9cc \ud6c4\ucc98\ub9ac\ub97c \uc801\uc6a9\\n2. \uac1c\uc120\uc774 \uc5c6\uc73c\uba74 \ub2e4\uc74c \ub2e8\uacc4\ub85c \ub118\uc5b4\uac00\uc9c0 \uc54a\uace0 \uc911\ub2e8\\n3. \ud488\uc9c8 \uc810\uc218\uc640 \ucc98\ub9ac \uc18d\ub3c4\ub97c \ud568\uaed8 \ubc18\uc601\ud55c \ubcf5\ud569 \uc810\uc218\ub85c \ucd5c\uc885 \uc120\ud0dd\\n\\n\uc774 \uc124\uacc4\uac00 \uc5c6\uc73c\uba74 \uc815\ud655\ub3c4\ub294 \uc624\ub97c \uc218 \uc788\uc5b4\ub3c4 \ube44\uc6a9\uacfc \uc9c0\uc5f0\uc2dc\uac04\uc774 \uae09\uaca9\ud788 \ucee4\uc9c4\ub2e4.\\n\\n### 4) \ub370\uc774\ud130/\ud3c9\uac00 \ud30c\uc774\ud504\ub77c\uc778: \ubca4\uce58\ub9c8\ud06c\ub97c \uc7ac\uc0ac\uc6a9 \uac00\ub2a5\ud55c \uc790\uc0b0\uc73c\ub85c \uc804\ud658\\n\\n\ub370\uc774\ud130/\ud3c9\uac00 \ub2f4\ub2f9\uc790\ub294 \ucd94\ucd9c \ud14d\uc2a4\ud2b8\ub97c \\"\ud55c \ubc88 \uc4f0\uace0 \ubc84\ub9ac\ub294 \uacb0\uacfc\\"\uac00 \uc544\ub2c8\ub77c \\"\ubc18\ubcf5 \uc2e4\ud5d8\uc6a9 \ub370\uc774\ud130\uc14b\\"\uc73c\ub85c \ubc14\uafe8\ub2e4.\\n\\n1. \ucd94\ucd9c \ud14d\uc2a4\ud2b8 \uae30\ubc18 QA \uc0dd\uc131 \ud30c\uc774\ud504\ub77c\uc778 \uad6c\ucd95\\n2. LLM Judge\ub97c \uac80\uc99d \ub2e8\uacc4\uc640 \ud3c9\uac00 \ub2e8\uacc4\ub85c \ubd84\ub9ac\ud574 \uc5ed\ud560 \ud63c\uc120\uc744 \uc904\uc784\\n3. \uacb0\uacfc\ub97c CSV/JSON/\ub370\uc774\ud130\uc14b \ud615\ud0dc\ub85c \uc800\uc7a5\ud574 \ub2e4\uc74c \uc2e4\ud5d8\uc5d0\uc11c \ubc14\ub85c \uc7ac\uc0ac\uc6a9 \uac00\ub2a5\ud558\uac8c \uad6c\uc131\\n4. Hugging Face \uc5c5\ub85c\ub4dc\uae4c\uc9c0 \uc5f0\uacb0\ud574 \ud300 \uc678\ubd80\uc5d0\uc11c\ub3c4 \ub3d9\uc77c \ud3ec\ub9f7\uc73c\ub85c \uc7ac\ud604 \uac00\ub2a5\ud558\uac8c \uc815\ub9ac\\n\\n\uc774 \ucd95\uc774 \uc788\uc5c8\uae30 \ub54c\ubb38\uc5d0 \ud30c\uc778\ud29c\ub2dd \uacb0\uacfc\ub3c4 \ub2e8\ubc1c\uc131 \uc2e4\ud5d8\uc774 \uc544\ub2c8\ub77c, \uace0\uc815\ub41c \uae30\uc900 \uc704\uc5d0\uc11c \ube44\uad50\ud560 \uc218 \uc788\uc5c8\ub2e4.\\n\\n## \ud504\ub85c\uc81d\ud2b8 \uc124\uba85: \uc804\uccb4 \ud750\ub984\uc744 \uc5b4\ub5bb\uac8c \uc124\uacc4\ud588\ub294\uac00\\n\\n\ucc98\uc74c\uc5d0\ub294 \\"\ud30c\uc11c \ud558\ub098\ub97c \uc798 \uace0\ub974\uba74 \ub41c\ub2e4\\"\ub77c\uace0 \uc0dd\uac01\ud588\ub294\ub370, \uc2e4\uc81c\ub85c\ub294 \uadf8\ubcf4\ub2e4 \ud6e8\uc52c \ubcf5\ud569\uc801\uc774\uc5c8\ub2e4.  \\n\ubb38\uc11c \ucd94\ucd9c \ud488\uc9c8\uc774 \ud754\ub4e4\ub9ac\uba74 QA \uc0dd\uc131\uc774 \ud754\ub4e4\ub9ac\uace0, QA \ud488\uc9c8\uc774 \ud754\ub4e4\ub9ac\uba74 LLM Judge \uacb0\uacfc\ub3c4 \ud754\ub4e4\ub9b0\ub2e4.  \\n\uadf8\ub798\uc11c \uc774 \ud504\ub85c\uc81d\ud2b8\ub294 \uae30\ub2a5 \ub2e8\uc704\uac00 \uc544\ub2c8\ub77c \\"\ud30c\uc774\ud504\ub77c\uc778 \ub2e8\uc704\\"\ub85c \uc124\uacc4\ud588\ub2e4.\\n\\n### 1) \ucf54\ub4dc\ubca0\uc774\uc2a4\ub97c \uc138 \uac08\ub798\ub85c \ubd84\ub9ac\ud55c \uc774\uc720\\n\\n\uc2e4\ud5d8 \uc18d\ub3c4\uc640 \uc6b4\uc601 \uc548\uc815\uc131\uc744 \uac19\uc774 \uc7a1\uae30 \uc704\ud574 \uc5ed\ud560\ubcc4\ub85c \ub808\ud3ec\ub97c \ub098\ub234\ub2e4.\\n\\n1. `llamacpp`: \ud30c\uc778\ud29c\ub2dd/\ucd94\ub860/\ud3c9\uac00 \ub8e8\ud504\ub97c \ube60\ub974\uac8c \ubc18\ubcf5\ud558\uae30 \uc704\ud55c \uc2e4\ud5d8 \ucd95\\n2. `Doc-to-RAG-Benchmark`: \uc81c\ud488 \uad00\uc810\uc758 \ud750\ub984 \uc815\ub9ac, \ubc1c\ud45c/\ub370\ubaa8 \uad6c\uc131, \ud3c9\uac00 \uae30\uc900 \uc815\ub9ac \ucd95\\n3. `Doc-to-text_Parsing_Agent`: OCR/\ud30c\uc2f1 \uc804\ub7b5 \uc120\ud0dd + Refine \uc815\uc81c\ub97c \uc2e4\uc81c\ub85c \ub3cc\ub9ac\ub294 \uad6c\ud604 \ucd95\\n\\n\uc774\ub807\uac8c \ubd84\ub9ac\ud558\ub2c8, \ubaa8\ub378 \uc2e4\ud5d8\uc744 \ubc14\uafd4\ub3c4 \uc11c\ube44\uc2a4/\uc5d0\uc774\uc804\ud2b8 \ucf54\ub4dc\uc640 \ucda9\ub3cc\uc774 \uc801\uace0, \ubc18\ub300\ub85c \ud30c\uc2f1 \ub85c\uc9c1\uc744 \uace0\uccd0\ub3c4 \ud30c\uc778\ud29c\ub2dd \ub8e8\ud504\ub97c \uae68\uc9c0 \uc54a\uace0 \ub3c5\ub9bd\uc801\uc73c\ub85c \uac80\uc99d\ud560 \uc218 \uc788\uc5c8\ub2e4.\\n\\n### 2) \ud30c\uc2f1/\uc815\uc81c \uc2dc\uc2a4\ud15c\uc5d0\uc11c \uc911\uc694\ud55c \uc124\uacc4 \ud3ec\uc778\ud2b8\\n\\n\ud575\uc2ec\uc740 \\"\uc804 \ubb38\uc11c \uace0\ube44\uc6a9 \ucc98\ub9ac\\"\ub97c \ud53c\ud558\ub294 \uac83\uc774\uc5c8\ub2e4.\\n\\n1. \uae30\ubcf8 \ucd94\ucd9c \ub2e8\uacc4\uc5d0\uc11c\ub294 \uc5ec\ub7ec \ud30c\uc11c\ub97c \ubcd1\ub82c\ub85c \ub3cc\ub824 \ud6c4\ubcf4\ub97c \ub9cc\ub4e0\ub2e4.\\n2. \uac80\uc99d \ub2e8\uacc4\uc5d0\uc11c Pass/Fail\uc744 \ud310\ub2e8\ud55c\ub2e4.\\n3. Fail\uc778 \ud398\uc774\uc9c0\uc5d0\ub9cc \ud3f4\ubc31/\uc815\uc81c\ub97c \uc801\uc6a9\ud55c\ub2e4.\\n4. \ub2e4\uc2dc \uac80\uc99d\ud574 \uac1c\uc120 \uc5c6\uc73c\uba74 \uc911\ub2e8\ud55c\ub2e4.\\n\\n\uc774 \ubc29\uc2dd \ub355\ubd84\uc5d0 \ud488\uc9c8\uc744 \uc62c\ub9ac\uba74\uc11c\ub3c4 API \ube44\uc6a9\uacfc \ucc98\ub9ac \uc2dc\uac04\uc744 \ud1b5\uc81c\ud560 \uc218 \uc788\uc5c8\ub2e4.\\n\\n### 3) \ud3c9\uac00\ub97c \\"\uc810\uc218 \ud558\ub098\\"\ub85c \ub05d\ub0b4\uc9c0 \uc54a\uc740 \uc774\uc720\\n\\n\uc774 \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c \ud3c9\uac00\ub294 \ub2e8\uc21c \ub9ac\ub354\ubcf4\ub4dc\uc6a9\uc774 \uc544\ub2c8\ub77c, \ub2e4\uc74c \uc2e4\ud5d8\uc758 \uae30\uc900\uc810\uc744 \ub9cc\ub4dc\ub294 \uc77c\uc774\uc5c8\ub2e4.\\n\\n1. \ud488\uc9c8: \ucd94\ucd9c \uc815\ud655\ub3c4, \ub2f5\ubcc0 \uc77c\uad00\uc131, \ub178\uc774\uc988/\ud45c/\ubb38\uc7a5 \uad6c\uc870 \ubcf4\uc874\\n2. \uc18d\ub3c4: \ubb38\uc11c \ub2e8\uc704 \ucc98\ub9ac \uc2dc\uac04, \ubcd1\ubaa9 \uad6c\uac04\\n3. \ube44\uc6a9: \uc678\ubd80 LLM \ud638\ucd9c \ube48\ub3c4\uc640 \ud398\uc774\uc9c0 \ub2e8\uc704 \ube44\uc6a9\\n\\n\uc989, \\"\uc774\ubc88\uc5d0 \uc798 \ub098\uc654\ub2e4\\"\uac00 \uc544\ub2c8\ub77c \\"\ub2e4\uc74c\uc5d0\ub3c4 \uc7ac\ud604 \uac00\ub2a5\ud55c\uac00\\"\ub97c \uae30\uc900\uc73c\ub85c \ubd24\ub2e4.\\n\\n\uc2e4\uc81c \ud3c9\uac00 \uc6b4\uc601\uc5d0\uc11c\ub294 LLM Judge 5\ucd95 \uac00\uc911\uce58\ub97c \uc544\ub798\ucc98\ub7fc \uace0\uc815\ud574\uc11c \uc0ac\uc6a9\ud588\ub2e4.\\n\\n1. `S_read` 25%\\n2. `S_sent` 25%\\n3. `S_noise` 15%\\n4. `S_table` 25%\\n5. `S_fig` 10%\\n\\n\ucd5c\uc885 \uc120\ud0dd \ub2e8\uacc4\uc5d0\uc11c\ub294 \ud488\uc9c8 \uc810\uc218 80%\uc640 \ucc98\ub9ac \uc18d\ub3c4 20%\ub97c \ud569\uc0b0\ud574 \uc758\uc0ac\uacb0\uc815\ud588\ub2e4.\\n\\n## \ub0b4\uac00 \ub9e1\uc740 \ud575\uc2ec: \ud30c\uc778\ud29c\ub2dd \uc2e4\ud5d8 \uc124\uacc4\uc640 \uc6b4\uc601\\n\\n### 1) \ud559\uc2b5 \ub8e8\ud504\ub97c \uba3c\uc800 \uace0\uc815\ud588\ub2e4\\n\\n\ub0b4\uac00 \ucc98\uc74c \ud55c \uc77c\uc740 \\"\ud55c \ubc88 \ub3cc\uc544\uac00\uba74 \ub05d\\"\uc778 \uc2a4\ud06c\ub9bd\ud2b8\uac00 \uc544\ub2c8\ub77c, \ubc18\ubcf5 \uac00\ub2a5\ud55c \uc2e4\ud5d8 \ub8e8\ud504\ub97c \ub9cc\ub4dc\ub294 \uac83\uc774\uc5c8\ub2e4.\\n\\n1. \ubca0\uc774\uc2a4 \ubaa8\ub378: `meta-llama/Llama-3.2-1B-Instruct`\\n2. \ube44\uad50 \ubaa8\ub378: `meta-llama/Llama-3.2-3B-Instruct`\\n2. \ub370\uc774\ud130: KorQuAD v1 \uc815\uaddc\ud654 + validation \uc0d8\ud50c\ub9c1\\n3. \ubc29\ubc95: QLoRA(4bit NF4)\\n4. \ube44\uad50: \ubca0\uc774\uc2a4 vs \ud29c\ub2dd \ubaa8\ub378 \ub3d9\uc2dc \ucd94\ub860\\n5. \ud3c9\uac00: EM/F1 \uc911\uc2ec\uc73c\ub85c \uace0\uc815\\n6. \ubc30\ud3ec \uac80\uc99d: \ubcd1\ud569 \ud6c4 GGUF \ubcc0\ud658 + `llama.cpp` \ucd94\ub860\\n\\n\ud504\ub85c\uc81d\ud2b8\ub97c \uc9c4\ud589\ud558\uba74\uc11c 1B\uc640 3B\ub97c \ubcd1\ud589\ud574 \uc2e4\ud5d8\ud588\ub2e4.  \\n1B\ub294 \ube60\ub978 \ubc18\ubcf5 \uc2e4\ud5d8\uacfc \ud30c\ub77c\ubbf8\ud130 \ud0d0\uc0c9\uc5d0 \uc720\ub9ac\ud588\uace0, 3B\ub294 \ud488\uc9c8 \uc0c1\ud55c\uacfc \uac1c\uc120 \ud3ed\uc744 \ud655\uc778\ud558\ub294 \ube44\uad50 \ucd95\uc73c\ub85c \uc0ac\uc6a9\ud588\ub2e4.  \\n\ucd5c\uc885\uc801\uc73c\ub85c\ub294 \ud488\uc9c8\ub9cc\uc774 \uc544\ub2c8\ub77c \ucc98\ub9ac \uc2dc\uac04\uacfc \ub9ac\uc18c\uc2a4 \ube44\uc6a9\uae4c\uc9c0 \uac19\uc774 \ubcf4\uace0, \uc6b4\uc601 \ud658\uacbd\uc5d0\uc11c \uc0ac\uc6a9\ud560 \uad6c\uc131\uc744 \ud310\ub2e8\ud588\ub2e4.\\n\\n### 2) \\"\uc88b\uc740 \uc2e4\ud5d8\\"\ubcf4\ub2e4 \\"\uc9c0\uc18d \uac00\ub2a5\ud55c \uc2e4\ud5d8\\"\uc5d0 \uc9d1\uc911\ud588\ub2e4\\n\\n\uc131\ub2a5 \uc22b\uc790\ub9cc \ubaa8\uc73c\uba74 \ub2e4\uc74c \uc2e4\ud5d8\uc5d0\uc11c \ub2e4\uc2dc \ubb34\ub108\uc9c0\ub294 \uacbd\uc6b0\uac00 \ub9ce\uc544\uc11c, \uc6b4\uc601 \uc9c0\ud45c\ub97c \uac19\uc774 \ub0a8\uacbc\ub2e4.\\n\\n1. `TimeBudgetCallback`\uc73c\ub85c \ud559\uc2b5 \uc2dc\uac04 \uc0c1\ud55c \uad00\ub9ac\\n2. step \ub2e8\uc704 wall time/CUDA time/\uba54\ubaa8\ub9ac \uc0ac\uc6a9\ub7c9 CSV \uae30\ub85d\\n3. \ud559\uc2b5 \uc885\ub8cc \ud6c4 LoRA \ubcd1\ud569\uae4c\uc9c0 \uc2a4\ud06c\ub9bd\ud2b8 \ud55c \ubc88\uc73c\ub85c \ucc98\ub9ac\\n\\n\uc774\ub807\uac8c \ud574\ub450\ub2c8 \\"\uc131\ub2a5\uc774 \uc62c\ub790\ub2e4\\"\uac00 \uc544\ub2c8\ub77c \\"\uc65c \uc62c\ub790\ub294\uc9c0\\"\ub97c \ub2e4\uc74c \uc2e4\ud5d8\uc5d0\uc11c \ub2e4\uc2dc \uac80\uc99d\ud560 \uc218 \uc788\uc5c8\ub2e4.\\n\\n### 3) \ud30c\uc778\ud29c\ub2dd \ubaa9\ud45c\ub97c \uc881\uac8c \uc7a1\uc558\ub2e4\\n\\n\ubaa9\ud45c\ub294 \ubc94\uc6a9 \ub300\ud654 \uc131\ub2a5\uc774 \uc544\ub2c8\ub77c, \ubb38\uc11c \uae30\ubc18 QA\uc5d0\uc11c \ub2f5\ubcc0 \uc77c\uad00\uc131\uacfc \uadfc\uac70 \ud68c\uc218\uc728\uc744 \ub192\uc774\ub294 \uac83\uc774\uc5c8\ub2e4. \uadf8\ub798\uc11c \ub370\uc774\ud130 \ud3ec\ub9f7, \ud504\ub86c\ud504\ud2b8 \ud15c\ud50c\ub9bf, \ud3c9\uac00 \ub8e8\ud2f4\uc744 \ubc14\uafb8\uc9c0 \uc54a\uace0 \uc720\uc9c0\ud588\ub2e4.\\n\\n## \ud30c\uc778\ud29c\ub2dd\uacfc \uc804\uccb4 \ud30c\uc774\ud504\ub77c\uc778\uc744 \uc5b4\ub5bb\uac8c \uc5f0\uacb0\ud588\ub294\uac00\\n\\n\ub0b4\uac00 \ubcf8 \ud575\uc2ec\uc740 \uc774\uac70\uc600\ub2e4. RAG\ub294 \ud55c \ucef4\ud3ec\ub10c\ud2b8\ub9cc \uc88b\uc544\uc838\ub3c4 \uc804\uccb4\uac00 \uc88b\uc544\uc9c0\uc9c0 \uc54a\ub294\ub2e4.\\n\\n1. \ud30c\uc2f1 \ud488\uc9c8\uc774 \ub0ae\uc73c\uba74 \uac80\uc0c9\uc774 \ud754\ub4e4\ub9b0\ub2e4.\\n2. \uac80\uc0c9\uc774 \ud754\ub4e4\ub9ac\uba74 \uc0dd\uc131 \ubaa8\ub378\uc774 \uc88b\uc544\ub3c4 \ud658\uac01\uc774 \ub298\uc5b4\ub09c\ub2e4.\\n3. \uadf8\ub798\uc11c \ud30c\uc778\ud29c\ub2dd\uc740 \\"\ub9c8\uc9c0\ub9c9 \ub2e8\uacc4 \ubcf4\uc815\\" \uc5ed\ud560\ub85c \ub450\uace0, \uc55e\ub2e8 \ud488\uc9c8 \uae30\uc900\uacfc \uac19\uc774 \uc6b4\uc601\ud574\uc57c \ud55c\ub2e4.\\n\\n\uacb0\ub860\uc801\uc73c\ub85c \ud30c\uc778\ud29c\ub2dd\uc740 \ub2e8\ub3c5 \ud574\ubc95\uc774 \uc544\ub2c8\ub77c, \ud30c\uc2f1/\ud3c9\uac00 \uae30\uc900\uc774 \uc815\ub3c8\ub41c \uc0c1\ud0dc\uc5d0\uc11c \ucd5c\uc885 \uc751\ub2f5 \ud488\uc9c8\uc744 \uc548\uc815\ud654\ud558\ub294 \ucd95\uc774\uc5c8\ub2e4.\\n\\n## \uc11c\ube44\uc2a4 \ud750\ub984(README \uae30\uc900)\\n\\n### \uc804\uccb4 \uad6c\uc870\\n\\n<img\\n  src=\\"/img/projects/doc-to-rag-benchmark/doc1-left.png\\"\\n  alt=\\"Doc-to-RAG \uc804\uccb4 \uac1c\uc694 (1)\\"\\n  style={{ width: \\"100%\\", maxWidth: \\"1100px\\", height: \\"auto\\", display: \\"block\\", margin: \\"0 auto\\" }}\\n/>\\n\\n<img\\n  src=\\"/img/projects/doc-to-rag-benchmark/doc1-right.png\\"\\n  alt=\\"Doc-to-RAG \uc804\uccb4 \uac1c\uc694 (2)\\"\\n  style={{ width: \\"100%\\", maxWidth: \\"1100px\\", height: \\"auto\\", display: \\"block\\", margin: \\"16px auto 0\\" }}\\n/>\\n\\n\uc774 \uadf8\ub9bc\uc744 \uae30\uc900\uc73c\ub85c \ud300 \ub0b4\ubd80\uc5d0\uc11c \uc5ed\ud560 \uacbd\uacc4\ub97c \uba3c\uc800 \uc815\ud588\ub2e4. \ubb38\uc11c \ud30c\uc2f1 \ucd5c\uc801\ud654\uc640 \ubca4\uce58\ub9c8\ud06c \uc790\ub3d9\ud654\ub97c \ubd84\ub9ac\ub41c \uc791\uc5c5\uc774 \uc544\ub2c8\ub77c \ud558\ub098\uc758 \ud30c\uc774\ud504\ub77c\uc778\uc73c\ub85c \ub2e4\ub8e8\ub294 \uac83\uc774 \ubaa9\ud45c\uc600\ub2e4.\\n\\n### \ubb38\uc81c \uc815\uc758\uc640 \uc811\uadfc \ubc29\ud5a5\\n\\n![\ubb38\uc81c \uc815\uc758](/img/projects/doc-to-rag-benchmark/doc2.png)\\n\\n\ud575\uc2ec\uc740 \\"\ubb38\uc11c\ub9c8\ub2e4 \ub2e4\ub978 \uad6c\uc870\\" \ub54c\ubb38\uc5d0 \uac19\uc740 \uc9c8\ubb38\uc5d0\uc11c\ub3c4 \ucd94\ucd9c \ud488\uc9c8\uc774 \ud06c\uac8c \ud754\ub4e4\ub9b0\ub2e4\ub294 \uc810\uc774\uc5c8\ub2e4. \uadf8\ub798\uc11c \ub2e8\uc77c \ud30c\uc11c \uace0\uc815\uc774 \uc544\ub2c8\ub77c, \ubb38\uc11c \ud2b9\uc131\uc744 \ubcf4\uace0 \uc804\ub7b5\uc744 \uc120\ud0dd\ud558\ub294 \uad6c\uc870\ub85c \uc124\uacc4\ud588\ub2e4.\\n\\n### OCR/\ud30c\uc2f1 \uc804\ub7b5 \uc120\ud0dd \uc2dc\uc2a4\ud15c\\n\\n![OCR/\ud30c\uc2f1 \uc804\ub7b5 \uc120\ud0dd](/img/projects/doc-to-rag-benchmark/doc3.png)\\n\\n\uc5ec\uae30\uc11c \uc911\uc694\ud55c \uc6b4\uc601 \uc6d0\uce59\uc740 \ud398\uc774\uc9c0 \ub2e8\uc704 \ud3f4\ubc31\uc774\uc5c8\ub2e4. Fail \ud398\uc774\uc9c0\uc5d0\ub9cc \ud6c4\ucc98\ub9ac\ub97c \ud0dc\uc6cc\uc11c \ud488\uc9c8\uc744 \ubcf4\uc815\ud558\uace0, \uc804 \ud398\uc774\uc9c0\uc5d0 \ubb34\uac70\uc6b4 \ucc98\ub9ac\ub97c \uac70\ub294 \ubc29\uc2dd\uc740 \ud53c\ud588\ub2e4.\\n\\n### \ubb38\uc11c \uc815\uc81c(Refine) \uc2dc\uc2a4\ud15c\\n\\n![\ubb38\uc11c \uc815\uc81c(Refine)](/img/projects/doc-to-rag-benchmark/doc4.png)\\n\\n\uc815\uc81c\ub3c4 \uac19\uc740 \uc6d0\uce59\uc73c\ub85c \ube44\uc6a9\uc744 \ud1b5\uc81c\ud588\ub2e4. On-device\ub85c \uba3c\uc800 \ud310\uc815\ud558\uace0, `Need Refine`\ub9cc Solar\ub85c \ub118\uaca8 \uc815\uc81c\ud588\ub2e4.\\n\\n### End-to-End \ud30c\uc774\ud504\ub77c\uc778\\n\\n<img\\n  src=\\"/img/projects/doc-to-rag-benchmark/doc5.png\\"\\n  alt=\\"End-to-End \ud30c\uc774\ud504\ub77c\uc778\\"\\n  style={{ width: \\"100%\\", maxWidth: \\"1100px\\", height: \\"auto\\", display: \\"block\\", margin: \\"0 auto\\" }}\\n/>\\n\\n\ucd94\ucd9c \uacb0\uacfc\uc640 \ud3c9\uac00 \uacb0\uacfc\ub97c \uac19\uc740 \uae30\uc900\uc73c\ub85c \ub204\uc801\ud574\uc11c, \\"\uc774\ubc88 \uc2e4\ud5d8\\"\uc774 \uc544\ub2c8\ub77c \\"\ub2e4\uc74c \uc2e4\ud5d8\uc5d0 \uc7ac\uc0ac\uc6a9 \uac00\ub2a5\ud55c \ub370\uc774\ud130\\"\ub85c \ub0a8\uae30\ub294 \ub370 \uc9d1\uc911\ud588\ub2e4.\\n\\n### \ud3c9\uac00 \uad00\uc810\uacfc \uacb0\uacfc \uc815\ub9ac\\n\\n<img\\n  src=\\"/img/projects/doc-to-rag-benchmark/doc6.png\\"\\n  alt=\\"\ud3c9\uac00 \uad00\uc810 1\\"\\n  style={{ width: \\"100%\\", maxWidth: \\"1100px\\", height: \\"auto\\", display: \\"block\\", margin: \\"0 auto\\" }}\\n/>\\n\\n<img\\n  src=\\"/img/projects/doc-to-rag-benchmark/doc7.png\\"\\n  alt=\\"\ud3c9\uac00 \uad00\uc810 2\\"\\n  style={{ width: \\"100%\\", maxWidth: \\"1100px\\", height: \\"auto\\", display: \\"block\\", margin: \\"16px auto 0\\" }}\\n/>\\n\\n\uc810\uc218 \ud558\ub098\ub85c \uacb0\ub860\ub0b4\uc9c0 \uc54a\uace0, \ud488\uc9c8/\uc18d\ub3c4/\ube44\uc6a9\uc744 \uac19\uc774 \ubd24\ub2e4. \uc774 \uae30\uc900\uc744 \uace0\uc815\ud574\ub450\ub2c8 \ud30c\uc778\ud29c\ub2dd \uacb0\uacfc\ub97c \ud574\uc11d\ud560 \ub54c\ub3c4 \ud300 \ub0b4 \ud569\uc758\uac00 \ube68\ub77c\uc84c\ub2e4.\\n\\n## \ub370\ubaa8 \ud654\uba74\\n\\n<img\\n  src=\\"/img/projects/doc-to-rag-benchmark/domo1.png\\"\\n  alt=\\"\ub370\ubaa8 \ud654\uba74 1\\"\\n  style={{ width: \\"100%\\", maxWidth: \\"1100px\\", height: \\"auto\\", display: \\"block\\", margin: \\"0 auto\\" }}\\n/>\\n\\n<img\\n  src=\\"/img/projects/doc-to-rag-benchmark/domo2.png\\"\\n  alt=\\"\ub370\ubaa8 \ud654\uba74 2\\"\\n  style={{ width: \\"100%\\", maxWidth: \\"1100px\\", height: \\"auto\\", display: \\"block\\", margin: \\"16px auto 0\\" }}\\n/>\\n\\n<img\\n  src=\\"/img/projects/doc-to-rag-benchmark/domo3.png\\"\\n  alt=\\"\ub370\ubaa8 \ud654\uba74 3\\"\\n  style={{ width: \\"100%\\", maxWidth: \\"1100px\\", height: \\"auto\\", display: \\"block\\", margin: \\"16px auto 0\\" }}\\n/>\\n\\n<img\\n  src=\\"/img/projects/doc-to-rag-benchmark/domo4.png\\"\\n  alt=\\"\ub370\ubaa8 \ud654\uba74 4\\"\\n  style={{ width: \\"100%\\", maxWidth: \\"1100px\\", height: \\"auto\\", display: \\"block\\", margin: \\"16px auto 0\\" }}\\n/>\\n\\n![\ub370\ubaa8 \ud654\uba74 5](/img/projects/doc-to-rag-benchmark/domo5.png)\\n\\n\ub370\ubaa8 \uad6c\uac04\uc740 \\"\uc120\ud0dd -> \uac80\uc99d -> \uc815\uc81c -> \ud3c9\uac00\\"\uac00 \uc2e4\uc81c\ub85c \uc5b4\ub5bb\uac8c \ubcf4\uc774\ub294\uc9c0\ub97c \ubcf4\uc5ec\uc8fc\ub294 \uc6a9\ub3c4\ub85c \uc815\ub9ac\ud588\ub2e4. \ubc1c\ud45c\uc5d0\uc11c \ubaa8\ub378 \uc131\ub2a5 \uc218\uce58\ub9cc \ubcf4\uc5ec\uc8fc\uc9c0 \uc54a\uace0, \uc6b4\uc601 \ud750\ub984\uc774 \uc5b4\ub5bb\uac8c \uc7ac\ud604\ub418\ub294\uc9c0 \uc124\uba85\ud558\ub294 \ub370 \uc720\uc6a9\ud588\ub2e4.\\n\\n### The Experience\\n\\n<div\\n  style={{\\n    display: \\"grid\\",\\n    gridTemplateColumns: \\"repeat(auto-fit, minmax(220px, 1fr))\\",\\n    gap: \\"12px\\",\\n    alignItems: \\"start\\",\\n  }}\\n>\\n  <img\\n    src=\\"/img/projects/doc-to-rag-benchmark/experience/experience-01.jpeg\\"\\n    alt=\\"The experience 1\\"\\n    style={{ width: \\"100%\\", height: \\"auto\\", display: \\"block\\", borderRadius: \\"8px\\" }}\\n  />\\n  <img\\n    src=\\"/img/projects/doc-to-rag-benchmark/experience/experience-02.jpeg\\"\\n    alt=\\"The experience 2\\"\\n    style={{ width: \\"100%\\", height: \\"auto\\", display: \\"block\\", borderRadius: \\"8px\\" }}\\n  />\\n  <img\\n    src=\\"/img/projects/doc-to-rag-benchmark/experience/experience-03.jpeg\\"\\n    alt=\\"The experience 3\\"\\n    style={{ width: \\"100%\\", height: \\"auto\\", display: \\"block\\", borderRadius: \\"8px\\" }}\\n  />\\n  <img\\n    src=\\"/img/projects/doc-to-rag-benchmark/experience/experience-04.jpeg\\"\\n    alt=\\"The experience 4\\"\\n    style={{ width: \\"100%\\", height: \\"auto\\", display: \\"block\\", borderRadius: \\"8px\\" }}\\n  />\\n  <img\\n    src=\\"/img/projects/doc-to-rag-benchmark/experience/experience-05.jpeg\\"\\n    alt=\\"The experience 5\\"\\n    style={{ width: \\"100%\\", height: \\"auto\\", display: \\"block\\", borderRadius: \\"8px\\" }}\\n  />\\n  <img\\n    src=\\"/img/projects/doc-to-rag-benchmark/experience/experience-06.jpeg\\"\\n    alt=\\"The experience 6\\"\\n    style={{ width: \\"100%\\", height: \\"auto\\", display: \\"block\\", borderRadius: \\"8px\\" }}\\n  />\\n</div>\\n\\n## \ud504\ub85c\uc81d\ud2b8\ub97c \ud558\uba70 \uae68\ub2ec\uc740 \uc810\\n\\n\uc774 \ud504\ub85c\uc81d\ud2b8\ub97c \ud558\uba70 \uac00\uc7a5 \ud06c\uac8c \uae68\ub2ec\uc740 \uac74 \ubd84\uba85\ud588\ub2e4. RAG \uc131\ub2a5\uc744 \uc548\uc815\uc801\uc73c\ub85c \ub04c\uc5b4\uc62c\ub9ac\ub294 \ub370\uc5d0\ub294 \\"\uc88b\uc740 \ubaa8\ub378 \ud558\ub098\\"\ubcf4\ub2e4 \\"\uc2e0\ub8b0\ud560 \uc218 \uc788\ub294 \ud3c9\uac00 \ub370\uc774\ud130\uc640 \uc120\ud0dd \uae30\uc900\\"\uc774 \ub354 \uc911\uc694\ud588\ub2e4.\\n\\n\ub0b4 \uc5ed\ud560 \uae30\uc900\uc73c\ub85c\ub3c4, \ud30c\uc778\ud29c\ub2dd \uc131\ub2a5 \uc790\uccb4\ub97c \uc62c\ub9ac\ub294 \uac83\ubcf4\ub2e4 \uc2e4\ud5d8 \ub8e8\ud504\ub97c \uace0\uc815\ud558\uace0 \uacb0\uacfc\ub97c \uc7ac\ud604 \uac00\ub2a5\ud55c \ud615\ud0dc\ub85c \ub0a8\uae34 \uc77c\uc774 \uc774\ud6c4 \uac1c\uc120 \uc18d\ub3c4\ub97c \ub354 \ud06c\uac8c \ub04c\uc5b4\uc62c\ub838\ub2e4.\\n\\n## \ub2e4\uc74c\uc5d0 \ubc14\ub85c \uac1c\uc120\ud558\uace0 \uc2f6\uc740 \uac83\\n\\n1. \ub3c4\uba54\uc778\ubcc4 Judge \ud504\ub86c\ud504\ud2b8 \uc790\ub3d9 \uc120\ud0dd\\n2. \ubca4\uce58\ub9c8\ud06c \uc0b0\ucd9c\ubb3c\uc744 Hugging Face \ud3ec\ub9f7\uc73c\ub85c \uc77c\uad00 \ucd9c\ub825\\n3. \ud30c\uc2f1 \uc2e4\ud328/\uc815\uc81c \uc5ed\ud6a8\uacfc \ucf00\uc774\uc2a4\ub97c \ud68c\uadc0 \ud14c\uc2a4\ud2b8\ub85c \uc0c1\uc2dc \uad00\ub9ac"},{"id":"/nano-vllm","metadata":{"permalink":"/projects/nano-vllm","source":"@site/projects/nano-vllm.md","title":"nano-vllm","description":"AER Labs\uc5d0\uc11c 4\uba85\uc774 \ud568\uaed8 \uc9c4\ud589\ud55c C++ \uae30\ubc18 \uad50\uc721\uc6a9 LLM inference engine \ud504\ub85c\uc81d\ud2b8\ub85c, continuous batching scheduler\uc640 GPU benchmark \ubb38\uc11c\ud654\ub97c \uad6c\ud604\ud55c \ud300 \ud504\ub85c\uc81d\ud2b8","date":"2026-06-28T23:16:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"nano-vllm","description":"AER Labs\uc5d0\uc11c 4\uba85\uc774 \ud568\uaed8 \uc9c4\ud589\ud55c C++ \uae30\ubc18 \uad50\uc721\uc6a9 LLM inference engine \ud504\ub85c\uc81d\ud2b8\ub85c, continuous batching scheduler\uc640 GPU benchmark \ubb38\uc11c\ud654\ub97c \uad6c\ud604\ud55c \ud300 \ud504\ub85c\uc81d\ud2b8","role":"LLM Systems Contributor","timeline":"Feb 2026 - Mar 2026","stack":["C++","LLM Serving","Scheduling","Benchmarking"],"category":"Team Project","image":"/img/projects/nano-vllm/nano-vllm-github-card.png","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"Doc-to-RAG Benchmark","permalink":"/projects/doc-to-rag-benchmark"},"nextItem":{"title":"Optiver \\"Trading at the Close\\" \ub300\ud68c","permalink":"/projects/optiver-kaggle"}},"content":"{/* truncate */}\\n\\n# nano-vllm\\n\\n## nano-vllm\uc740 \uc5b4\ub5a4 \ud504\ub85c\uc81d\ud2b8\uc778\uac00\\n\\n[nano-vllm](https://github.com/aerlabsAI/nano-vllm)\uc740 AER Labs\uc5d0\uc11c \ub098\ub97c \ud3ec\ud568\ud55c 4\uba85\uc774 \ud568\uaed8 \uc9c4\ud589\ud55c C++ \uae30\ubc18 \uad50\uc721\uc6a9 LLM inference engine \ud504\ub85c\uc81d\ud2b8\ub2e4. tokenizer, model, attention, sampler, scheduler, benchmark utility\ub97c \uc791\uc740 \ucf54\ub4dc\ubca0\uc774\uc2a4 \uc548\uc5d0 \uc9c1\uc811 \uad6c\ud604\ud574 LLM serving \ub0b4\ubd80 \uad6c\uc870\ub97c \ud559\uc2b5\ud560 \uc218 \uc788\uac8c \ub9cc\ub4e0 \ud504\ub85c\uc81d\ud2b8\ub2e4.\\n\\n\ud504\ub85c\uc81d\ud2b8\uc758 \ubaa9\ud45c\ub294 \uc774\ubbf8 \uc788\ub294 inference engine\uc744 \ub2e8\uc21c\ud788 \uc0ac\uc6a9\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, PagedAttention, KV cache, continuous batching, chunked prefill \uac19\uc740 \uac1c\ub150\uc774 \uc2e4\uc81c \uc2e4\ud589 \ud750\ub984\uc5d0\uc11c \uc5b4\ub5bb\uac8c \ub9de\ubb3c\ub9ac\ub294\uc9c0 \uc9c1\uc811 \uad6c\ud604\ud558\uba74\uc11c \uc774\ud574\ud558\ub294 \uac83\uc774\uc5c8\ub2e4. 2026\ub144 3\uc6d4 22\uc77c AER Labs \ube14\ub85c\uadf8\uc5d0 \uc62c\ub77c\uc628 [Part 1](https://aerlabs.tech/blogs/nano-vllm-part1)\uacfc [Part 2](https://aerlabs.tech/blogs/nano-vllm-part2)\ub294 \uc774 \ud504\ub85c\uc81d\ud2b8\ub97c \uad6c\ud604\ud55c \ub4a4 4\uba85\uc774 \ud568\uaed8 \uc815\ub9ac\ud55c \uacf5\uac1c \uae30\uc220 \uae00\uc774\ub2e4.\\n\\n## \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c \ub9e1\uc740 \uc791\uc5c5\\n\\n- Repository: [aerlabsAI/nano-vllm](https://github.com/aerlabsAI/nano-vllm)\\n- Feature PR: [PR #37](https://github.com/aerlabsAI/nano-vllm/pull/37) `Implement continuous batching scheduler`, merged\\n- Docs PR: [PR #50](https://github.com/aerlabsAI/nano-vllm/pull/50) `Add section 9.6 GPU benchmark after CPU analysis`, merged\\n- AER Labs blog: [Building an LLM Inference Engine from Scratch Part 1](https://aerlabs.tech/blogs/nano-vllm-part1), [Part 2](https://aerlabs.tech/blogs/nano-vllm-part2)\\n\\n[PR #37](https://github.com/aerlabsAI/nano-vllm/pull/37)\uc5d0\uc11c\ub294 continuous batching scheduler\ub97c \uad6c\ud604\ud588\ub2e4. \uc774 PR\uc740 2026\ub144 2\uc6d4 11\uc77c merge\ub410\uace0, local git \uae30\uc900\uc73c\ub85c 10\uac1c \ud30c\uc77c\uc5d0 728 lines \ucd94\uac00, 146 lines \uc0ad\uc81c\uac00 \uc788\uc5c8\ub2e4. \uc8fc\uc694 \ubcc0\uacbd\uc740 `Scheduler`, `Request`, `BatchedRunner`, `AsyncRequestQueue`, `RequestSubmitter`, JSON benchmark input path\uc600\ub2e4.\\n\\n\ud6c4\uc18d\uc73c\ub85c [PR #50](https://github.com/aerlabsAI/nano-vllm/pull/50)\uc5d0\uc11c\ub294 CPU benchmark \ub4a4\uc5d0 GPU benchmark \uc139\uc158\uc744 \ucd94\uac00\ud588\ub2e4. \uc774 PR\uc740 2026\ub144 2\uc6d4 27\uc77c merge\ub410\ub2e4. \ucc98\uc74c\uc5d0\ub294 vLLM\uc758 `max-num-seqs`, `max-num-batched-tokens` sweep \uacb0\uacfc\ub97c \uc815\ub9ac\ud588\uc9c0\ub9cc, \ub9ac\ubdf0\uc5d0\uc11c \uc774\uac83\ub9cc\uc73c\ub85c\ub294 request-level static batching\uacfc continuous batching\uc758 \ucc28\uc774\ub97c \uc9c1\uc811 \ubcf4\uc5ec\uc8fc\uae30 \uc5b4\ub835\ub2e4\ub294 \ud53c\ub4dc\ubc31\uc774 \uc788\uc5c8\ub2e4. \uadf8\ub798\uc11c raw JSON benchmark \uacb0\uacfc\ub97c \ub2e4\uc2dc \ub0a8\uae30\uace0, vanilla Hugging Face \uae30\ubc18 request-level static batching vs continuous slot reuse control experiment\ub97c \ucd94\uac00\ud588\ub2e4.\\n\\n\uc774\ud6c4 AER Labs \ube14\ub85c\uadf8 \uae00\uc5d0\uc11c\ub294 \uc774 \uad6c\ud604 \uacbd\ud5d8\uc744 \ubc14\ud0d5\uc73c\ub85c Part 1\uc5d0\uc11c core inference flow\uc640 PagedAttention\uc744 \uc124\uba85\ud558\uace0, Part 2\uc5d0\uc11c continuous batching, chunked prefill, GPU/CPU benchmark \uacb0\uacfc\ub97c \uc815\ub9ac\ud588\ub2e4. \uc989 \ube14\ub85c\uadf8 \uae00\uc740 \ub0b4\uac00 \uba3c\uc800 \uc77d\uace0 \ub530\ub77c \uad6c\ud604\ud55c \uc790\ub8cc\uac00 \uc544\ub2c8\ub77c, \uad6c\ud604\uacfc \uc2e4\ud5d8\uc744 \ub9c8\uce5c \ub4a4 \ud504\ub85c\uc81d\ud2b8 \ub0b4\uc6a9\uc744 \uc678\ubd80\uc5d0 \uc124\uba85\ud558\uae30 \uc704\ud574 \uc815\ub9ac\ud55c \uacb0\uacfc\ubb3c\uc774\ub2e4.\\n\\n## \ubb38\uc81c \uc815\uc758\\n\\n\uae30\uc874 \uc2e4\ud589 \ud750\ub984\uc740 \uc694\uccad\uc744 \uc21c\ucc28\uc801\uc73c\ub85c \ucc98\ub9ac\ud558\uac70\ub098, \ud55c \ubc88 \uc7a1\uc740 batch\uac00 \ub05d\ub0a0 \ub54c\uae4c\uc9c0 \uae30\ub2e4\ub9ac\ub294 \uad6c\uc870\uc5d0 \uac00\uae4c\uc6e0\ub2e4. \uc774 \ubc29\uc2dd\uc740 \uae38\uc774\uac00 \uc11c\ub85c \ub2e4\ub978 \uc694\uccad\uc774 \uc11e\uc77c \ub54c \ube44\ud6a8\uc728\uc774 \uc0dd\uae34\ub2e4. \uc9e7\uc740 \uc694\uccad\uc774 \uba3c\uc800 \ub05d\ub098\ub3c4 \uae34 \uc694\uccad\uc774 batch\ub97c \uacc4\uc18d \ubd99\uc7a1\uace0 \uc788\uc73c\uba74, \ube44\uc5b4 \uc788\ub294 slot\uc744 \ub2e4\uc74c \uc694\uccad\uc5d0 \ubc14\ub85c \uc7ac\uc0ac\uc6a9\ud558\uc9c0 \ubabb\ud55c\ub2e4.\\n\\nLLM serving\uc5d0\uc11c \uc774 \ubb38\uc81c\ub294 \ub2e8\uc21c\ud55c \uad6c\ud604 \ub514\ud14c\uc77c\uc774 \uc544\ub2c8\ub2e4. decode \ub2e8\uacc4\ub294 \ud1a0\ud070\uc744 \ud55c \ubc88\uc5d0 \ud558\ub098\uc529 \uc0dd\uc131\ud558\ubbc0\ub85c, \ub9e4 iteration\ub9c8\ub2e4 \uc5b4\ub5a4 \uc694\uccad\uc744 \uac19\uc774 \uc2e4\ud589\ud560\uc9c0 \ub2e4\uc2dc \uace0\ub974\ub294 scheduler\uac00 \uc911\uc694\ud558\ub2e4. continuous batching\uc740 request \ub2e8\uc704\uac00 \uc544\ub2c8\ub77c iteration \ub2e8\uc704\ub85c batch\ub97c \ub2e4\uc2dc \uad6c\uc131\ud574, \ub05d\ub09c \uc694\uccad\uc758 slot\uc744 \ubc14\ub85c \ud68c\uc218\ud558\uace0 \ub300\uae30 \uc911\uc778 \uc694\uccad\uc744 \ud22c\uc785\ud558\ub294 \ubc29\uc2dd\uc774\ub2e4.\\n\\n## \uad6c\ud604\ud55c \ubc94\uc704\\n\\n### Continuous batching scheduler\\n\\n`Request`\uc5d0 \uc0c1\ud0dc\uc640 prefill \uc9c4\ud589 \uc0c1\ud0dc\ub97c \ub450\uace0, \uc694\uccad\uc774 `PENDING`, `PREFILLING`, `DECODING`, `FINISHED` \ud750\ub984\uc744 \uac16\ub3c4\ub85d \uc815\ub9ac\ud588\ub2e4. `Scheduler`\ub294 \ub9e4 iteration\ub9c8\ub2e4 token budget\uacfc max batch size\ub97c \uae30\uc900\uc73c\ub85c \uc2e4\ud589\ud560 request\ub97c \uace0\ub978\ub2e4.\\n\\n\uae34 prompt\ub294 \ud55c \ubc88\uc5d0 \ubaa8\ub450 prefill\ud558\uc9c0 \uc54a\uace0 chunk\ub85c \ub098\ub20c \uc218 \uc788\uac8c \ud588\ub2e4. `prefill_cursor`\ub85c \uc9c4\ud589 \uc704\uce58\ub97c \ucd94\uc801\ud558\uace0, token budget\uc774 \ub0a8\ub294 \ub9cc\ud07c\ub9cc prefill chunk\ub97c schedule\ud55c\ub2e4. decode \uc694\uccad\uc740 iteration\ub9c8\ub2e4 \uacc4\uc18d \ub4e4\uc5b4\uc62c \uc218 \uc788\uc73c\ubbc0\ub85c, prefill\uc774 \uae34 \uc694\uccad \ud558\ub098\uac00 \uc804\uccb4 decode \ud750\ub984\uc744 \ub9c9\uc9c0 \uc54a\uac8c \ud558\ub294 \uac83\uc774 \ud575\uc2ec\uc774\uc5c8\ub2e4.\\n\\n### Async arrivals\uc640 benchmark \uc785\ub825\\n\\n\uc2e4\uc81c serving\uc5d0\uc11c\ub294 \ubaa8\ub4e0 \uc694\uccad\uc774 \ub3d9\uc2dc\uc5d0 \ub4e4\uc5b4\uc624\uc9c0 \uc54a\ub294\ub2e4. \uadf8\ub798\uc11c async arrival workload\ub97c \uc77d\uc744 \uc218 \uc788\ub294 path\ub97c \ucd94\uac00\ud588\ub2e4. JSON workload\ub85c \uc694\uccad \ubaa9\ub85d\uc744 \uc77d\uace0, `AsyncRequestQueue`\uc640 `RequestSubmitter`\uac00 arrival time\uc5d0 \ub9de\ucdb0 scheduler\uc5d0 request\ub97c \ub123\ub294\ub2e4.\\n\\nCLI\uc5d0\uc11c\ub294 JSON benchmark workload, max batch size, max tokens per batch, async \uc2e4\ud589, \uacb0\uacfc \uc800\uc7a5\uacfc \ube44\uad50 \ud750\ub984\uc744 \uc0ac\uc6a9\ud560 \uc218 \uc788\uac8c \ud588\ub2e4. \uc774\ub807\uac8c \ud574\uc57c scheduler \uad6c\ud604\uc774 \ub2e8\uc21c \uae30\ub2a5\uc774 \uc544\ub2c8\ub77c, \uc11c\ub85c \ub2e4\ub978 scheduling \uc124\uc815\uc744 \ube44\uad50\ud560 \uc218 \uc788\ub294 \uc2e4\ud5d8 \ub2e8\uc704\uac00 \ub41c\ub2e4.\\n\\n### GPU benchmark \ubb38\uc11c\ud654\\n\\nCPU\uc5d0\uc11c\ub294 continuous batching\uacfc chunked prefill\uc774 \ud56d\uc0c1 throughput\uc744 \uc62c\ub824\uc8fc\uc9c0\ub294 \uc54a\ub294\ub2e4. local CPU implementation\uc5d0\uc11c\ub294 batch\uac00 \uc2e4\uc81c GPU kernel\ucc98\ub7fc fused batched forward\ub85c \uc2e4\ud589\ub418\ub294 \uac83\uc774 \uc544\ub2c8\ub77c scheduler abstraction\uc5d0 \uac00\uae4c\uc6cc\uc11c, scheduler overhead\uac00 \uc131\ub2a5\uc5d0 \uadf8\ub300\ub85c \ubcf4\uc77c \uc218 \uc788\ub2e4.\\n\\n\uadf8\ub798\uc11c GPU benchmark \ubb38\uc11c\uc5d0\uc11c\ub294 vLLM\uc744 \uae30\uc900\uc73c\ub85c `max-num-seqs`, `max-num-batched-tokens`\ub97c \ubc14\uafb8\uba70 TTFT, TPOT, ITL, E2EL, throughput, peak VRAM\uc744 \ube44\uad50\ud588\ub2e4. \uc774\ud6c4 \ub9ac\ubdf0 \ud53c\ub4dc\ubc31\uc744 \ubc18\uc601\ud574 request-level static batching\uacfc continuous slot reuse\ub97c \uac19\uc740 \uc694\uccad \uc9d1\ud569\uc5d0\uc11c \ube44\uad50\ud558\ub294 Hugging Face control script\uc640 raw JSON \uacb0\uacfc\ub3c4 \ucd94\uac00\ud588\ub2e4.\\n\\n## \ud574\uacb0 \uacfc\uc815\uc5d0\uc11c \uc0dd\uae34 \ubb38\uc81c\uc640 \uacb0\uc815\\n\\n\uccab \ubc88\uc9f8 \ubb38\uc81c\ub294 continuous batching\uc744 CPU implementation\uc5d0\uc11c \uc5b4\ub5bb\uac8c \ubcf4\uc5ec\uc904\uc9c0\uc600\ub2e4. GPU serving engine\uc5d0\uc11c\ub294 \uc5ec\ub7ec sequence\ub97c \ud55c \ubc88\uc5d0 batched forward\ub85c \uc2e4\ud589\ud560 \uc218 \uc788\uc9c0\ub9cc, \uc774 educational C++ implementation\uc5d0\uc11c\ub294 scheduler\uac00 batch\ub97c \ub9cc\ub4e4\ub354\ub77c\ub3c4 \uc2e4\uc81c \uc5f0\uc0b0\uc774 production GPU engine\ucc98\ub7fc \uc644\uc804\ud788 fused \ub418\ub294 \uac83\uc740 \uc544\ub2c8\ub2e4. \uadf8\ub798\uc11c \uad6c\ud604 \ubaa9\ud45c\ub97c \\"CPU\uc5d0\uc11c \ubb34\uc870\uac74 \ube68\ub77c\uc9c4\ub2e4\\"\uac00 \uc544\ub2c8\ub77c, request lifecycle\uacfc slot reuse \uc815\ucc45\uc744 \ucf54\ub4dc\ub85c \uc124\uba85\ud560 \uc218 \uc788\uac8c \ud558\ub294 \uac83\uc73c\ub85c \uc7a1\uc558\ub2e4.\\n\\n\ub450 \ubc88\uc9f8 \ubb38\uc81c\ub294 benchmark \ud574\uc11d\uc774\uc5c8\ub2e4. CPU \uacb0\uacfc\ub9cc \ubcf4\uba74 continuous batching\uc774 baseline\ubcf4\ub2e4 \ub290\ub9ac\uac8c \ubcf4\uc77c \uc218 \uc788\ub2e4. \uc774\uac78 \uc2e4\ud328\ub85c \uc228\uae30\uc9c0 \uc54a\uace0, CPU\uc5d0\uc11c\ub294 scheduler overhead\uac00 \ub354 \ud06c\uac8c \ubcf4\uc774\uace0 GPU\uc5d0\uc11c\ub294 batch occupancy\uc640 kernel amortization \ub54c\ubb38\uc5d0 \ub2e4\ub978 \uacb0\uacfc\uac00 \ub098\uc628\ub2e4\ub294 \uc2dd\uc73c\ub85c \ubd84\ub9ac\ud588\ub2e4.\\n\\n\uc138 \ubc88\uc9f8 \ubb38\uc81c\ub294 \ub9ac\ubdf0\uc5d0\uc11c \ub098\uc628 request-level batching \ube44\uad50\uc600\ub2e4. `max-num-seqs` sweep\uc740 continuous batching \ub0b4\ubd80 capacity tuning\uc774\uc9c0, request-level static batching baseline \uc790\uccb4\ub294 \uc544\ub2c8\ub2e4. \uadf8\ub798\uc11c vanilla Hugging Face control experiment\ub97c \ub530\ub85c \ub9cc\ub4e4\uc5b4, \uac19\uc740 model\uacfc request set\uc5d0\uc11c `request_level_static`\uacfc `continuous_slot_reuse`\ub97c \ube44\uad50\ud588\ub2e4. \uc774 \uc2e4\ud5d8\uc5d0\uc11c\ub294 Qwen3-0.6B\uc5d0\uc11c continuous slot reuse\uac00 request throughput\uacfc output token throughput \ubaa8\ub450 4.70x \ub192\uc558\uace0, Qwen2.5-3B-Instruct\uc5d0\uc11c\ub3c4 2.73x \ub192\uac8c \ub098\uc654\ub2e4.\\n\\n## \uacb0\uacfc\\n\\n[PR #37](https://github.com/aerlabsAI/nano-vllm/pull/37)\uc740 merge\ub418\uc5b4 nano-vllm\uc5d0 continuous batching scheduler\uac00 \ub4e4\uc5b4\uac14\ub2e4. \uc774 \uc791\uc5c5\uc73c\ub85c request state, scheduler iteration, async arrival, JSON benchmark workload\uac00 \ud558\ub098\uc758 \uc2e4\ud589 \ud750\ub984\uc73c\ub85c \uc5f0\uacb0\ub410\ub2e4.\\n\\n[PR #50](https://github.com/aerlabsAI/nano-vllm/pull/50)\uc740 GPU benchmark\uc640 \ud6c4\uc18d control experiment\ub97c \ubb38\uc11c\ud654\ud558\ub294 \uc791\uc5c5\uc73c\ub85c merge\ub410\ub2e4. \uae30\ub2a5 \uad6c\ud604 PR\uacfc \ub2ec\ub9ac docs/benchmark \uc911\uc2ec\uc774\uc9c0\ub9cc, continuous batching\uc744 \\"\uc65c \ube60\ub978\uac00\\"\uac00 \uc544\ub2c8\ub77c \\"\uc5b4\ub5a4 \uc870\uac74\uc5d0\uc11c \ubb34\uc5c7\uacfc \ube44\uad50\ud574\uc57c \ud558\ub294\uac00\\"\uae4c\uc9c0 \uc124\uba85\ud558\ub294 \ucabd\uc73c\ub85c \ud655\uc7a5\ud588\ub2e4.\\n\\n\ud504\ub85c\uc81d\ud2b8 \uad6c\ud604\uacfc benchmark \uc815\ub9ac \uc774\ud6c4\uc5d0\ub294 AER Labs \ube14\ub85c\uadf8\uc5d0 2\ud3b8\uc758 \uae00\ub85c \uacf5\uac1c\ud588\ub2e4. Part 1\uc740 LLM inference engine\uc758 core architecture\uc640 PagedAttention\uc744 \uc124\uba85\ud558\uace0, Part 2\ub294 continuous batching\uacfc chunked prefill, \uadf8\ub9ac\uace0 GPU/CPU benchmark \uacb0\uacfc\ub97c \uc124\uba85\ud55c\ub2e4. \ub450 \uae00 \ubaa8\ub450 Hyogeun Oh, Wontak Ryu, Hyoseop Song, Chanho Lee 4\uba85\uc774 \ud568\uaed8 \uc791\uc131\ud55c AER Labs \uae30\uc220 \uae00\uc774\ub2e4.\\n\\n## References\\n\\n- [aerlabsAI/nano-vllm](https://github.com/aerlabsAI/nano-vllm)\\n- [PR #37: Implement continuous batching scheduler](https://github.com/aerlabsAI/nano-vllm/pull/37)\\n- [PR #50: Add section 9.6 GPU benchmark after CPU analysis](https://github.com/aerlabsAI/nano-vllm/pull/50)\\n- [Understanding LLM Inference Engines: Inside Nano-VLLM Part 1](https://aerlabs.tech/blogs/nano-vllm-part1)\\n- [Understanding LLM Inference Engines: Inside Nano-VLLM Part 2](https://aerlabs.tech/blogs/nano-vllm-part2)"},{"id":"/optiver-kaggle","metadata":{"permalink":"/projects/optiver-kaggle","source":"@site/projects/optiver-kaggle.md","title":"Optiver \\"Trading at the Close\\" \ub300\ud68c","description":"Kaggle Optiver - Trading at the Close \ub300\ud68c (Top 30%)","date":"2026-06-28T23:16:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"Optiver \\"Trading at the Close\\" \ub300\ud68c","description":"Kaggle Optiver - Trading at the Close \ub300\ud68c (Top 30%)","role":"Data Scientist","timeline":"Oct 2023 - Dec 2023","stack":["Python","LightGBM","Numba","Pandas"],"category":"Kaggle Competition","image":"/img/projects/optiver-kaggle/optiver-kaggle-header-aspect-v2.png","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"nano-vllm","permalink":"/projects/nano-vllm"},"nextItem":{"title":"Pyodide","permalink":"/projects/pyodide"}},"content":"{/* truncate */}\\n\\n\\n# Optiver \\"Trading at the Close\\" \ub300\ud68c\\n\\n## \uc2dc\uc791\ud558\uac8c \ub41c \uacc4\uae30\\n\\n2023\ub144, Google ML \ubd80\ud2b8\ucea0\ud504 4\uae30\uc5d0 \ucc38\uc5ec\ud558\uba74\uc11c \uc218\ub8cc \uc870\uac74 \uc911 \ud558\ub098\ub85c \uce90\uae00 \ub300\ud68c \ucc38\uac00\uac00 \uc788\uc5c8\ub2e4. \ub9c8\uce68 Optiver\uac00 \\"Trading at the Close\\"\ub77c\ub294 \ub300\ud68c\ub97c \uc5f4\uc5c8\uace0, \ub2f9\uc2dc \ub098\ub791\uc740 \uc804\ud600 \uad00\uacc4\uc5c6\uace0 \uc0dd\uc18c\ud55c \ub3c4\uba54\uc778\uc774\uc9c0\ub9cc \uc7ac\ubc0c\uc744 \uac83 \uac19\uc740 \ub3c4\uba54\uc778\uc774\ub77c \uc120\ud0dd\ud588\ub2e4. \ucd5c\uc885 \uc81c\ucd9c\ubb3c\uc740 LightGBM \uae30\ubc18 \ucf54\ub4dc\uc600\ub2e4.\\n\\n---\\n\\n## \ub300\ud68c \uac1c\uc694\\n\\n### Optiver\uc640 \uc885\uac00 \uacbd\ub9e4\\n\\nOptiver\ub294 \uae00\ub85c\ubc8c \uc804\uc790 \ub9c8\ucf13\uba54\uc774\ucee4\ub2e4. \ud30c\uc0dd\uc0c1\ud488, \uc8fc\uc2dd, ETF, \ucc44\uad8c, \uc678\ud658 \ub4f1\uc744 \uac70\ub798\ud558\uba74\uc11c \uc804 \uc138\uacc4 \uc8fc\uc694 \uac70\ub798\uc18c\uc5d0 \uc720\ub3d9\uc131\uc744 \uacf5\uae09\ud55c\ub2e4.\\n\\n**\ub098\uc2a4\ub2e5 \uc885\uac00 \uacbd\ub9e4(Nasdaq Closing Cross)**\ub294 \ub9e4\uc77c \uc7a5 \ub9c8\uac10 10\ubd84(3:50~4:00 PM ET) \ub3d9\uc548 \uc9c4\ud589\ub418\uba70, \uc774 \uc2dc\uac04\uc5d0 \uadf8 \ub0a0\uc758 \uacf5\uc2dd \uc885\uac00\uac00 \uacb0\uc815\ub41c\ub2e4. \ud22c\uc790\uc790\ub4e4\uc774 \ud3ec\uc9c0\uc158\uc744 \uc870\uc815\ud558\uba74\uc11c \ubcc0\ub3d9\uc131\uc774 \ud06c\uace0, \uc804\ud1b5\uc801\uc778 \ud638\uac00\ucc3d \ub370\uc774\ud130\uc640 \uacbd\ub9e4 \ub370\uc774\ud130\ub97c \ub3d9\uc2dc\uc5d0 \ucc98\ub9ac\ud574\uc57c \ud558\ub294 \ubcf5\uc7a1\ud55c \uad6c\uac04\uc774\ub2e4.\\n\\n### \ub300\ud68c \uc77c\uc815\\n\\n![\ub300\ud68c \uc77c\uc815](/img/projects/optiver-kaggle/optiver-timeline.png)\\n\\n\uc774 \ub300\ud68c\ub294 \ubaa8\ub378\uc744 \uba3c\uc800 \uc81c\ucd9c\ud558\uace0(Active Training Phase), \uc774\ud6c4 \uc2e4\uc81c \uc2dc\uc7a5 \ub370\uc774\ud130\ub85c \ud3c9\uac00\ubc1b\ub294(Forecasting Phase) \ubc29\uc2dd\uc73c\ub85c \uc9c4\ud589\ub418\uc5c8\ub2e4.\\n\\n**Training Timeline:**\\n\\n- **2023\ub144 9\uc6d4 20\uc77c** - \ub300\ud68c \uc2dc\uc791\\n- **2023\ub144 12\uc6d4 13\uc77c** - \ucc38\uac00 \ub9c8\uac10 (\uc774 \ub0a0\uc9dc \uc804\uae4c\uc9c0 \uaddc\uc815\uc5d0 \ub3d9\uc758\ud574\uc57c \ud568)\\n- **2023\ub144 12\uc6d4 13\uc77c** - \ud300 \ubcd1\ud569 \ub9c8\uac10\\n- **2023\ub144 12\uc6d4 20\uc77c** - \ucd5c\uc885 \uc81c\ucd9c \ub9c8\uac10\\n\\n\ubaa8\ub4e0 \ub9c8\uac10 \uc2dc\uac04\uc740 \ud574\ub2f9 \ub0a0\uc9dc\uc758 11:59 PM UTC\ub2e4.\\n\\n**Forecasting Timeline:**\\n\ucd5c\uc885 \uc81c\ucd9c \ub9c8\uac10 \ud6c4, \uc120\ud0dd\ub41c \ub178\ud2b8\ubd81\uc740 \uc2e4\uc81c \uc2dc\uc7a5 \ub370\uc774\ud130 \uc5c5\ub370\uc774\ud2b8\uc5d0 \ub9de\ucdb0 \uc8fc\uae30\uc801\uc73c\ub85c \uc2e4\ud589\ub418\uba70 \ub9ac\ub354\ubcf4\ub4dc\uac00 \uac31\uc2e0\ub41c\ub2e4. \uc5c5\ub370\uc774\ud2b8\ub294 \uc57d 2\uc8fc\ub9c8\ub2e4 \uc9c4\ud589\ub418\uc5c8\ub2e4.\\n\\n- **2024\ub144 3\uc6d4 20\uc77c** - \ub300\ud68c \uc885\ub8cc\\n\\n\uc774 \ub300\ud68c\ub294 \uc77c\ubc18\uc801\uc778 \uce90\uae00 \ub300\ud68c\uc640 \ub2ec\ub9ac, \uc81c\ucd9c \ud6c4 \uc57d 3\uac1c\uc6d4\uac04 \uc2e4\uc81c \uc2dc\uc7a5 \ub370\uc774\ud130\ub85c \ubaa8\ub378\uc774 \ud3c9\uac00\ub418\ub294 **forecasting \ub300\ud68c**\uc600\ub2e4. \ub9ac\ub354\ubcf4\ub4dc\uac00 2\uc8fc\ub9c8\ub2e4 \uac31\uc2e0\ub418\uc5c8\uace0, \ub9e4\uc77c `revealed_targets`\ub85c \uc804\ub0a0\uc758 \uc815\ub2f5\uc774 \uacf5\uac1c\ub410\ub2e4.\\n\\n### \ubb38\uc81c \uc815\uc758\\n\\n\uc885\uac00 \uacbd\ub9e4 \uad6c\uac04\uc5d0\uc11c 60\ucd08 \ub4a4\uc758 \uc8fc\uac00 \uc6c0\uc9c1\uc784\uc744 \uc608\uce21\ud558\ub294 \uac8c \uacfc\uc81c\ub2e4.\\n\\n### \ud0c0\uae43 \uc815\uc758\\n\\n\ud0c0\uae43\uc740 \uac1c\ubcc4 \uc885\ubaa9\uc758 WAP(\uac00\uc911\ud3c9\uade0\uac00\uaca9) \ubcc0\ud654\uc5d0\uc11c \uc9c0\uc218 WAP \ubcc0\ud654\ub97c \ube80 \uac12\uc73c\ub85c, basis points(bp, 0.01%) \ub2e8\uc704\ub85c \ud45c\ud604\ub41c\ub2e4:\\n\\n$$\\nTarget = \\\\left( \\\\frac{StockWAP_{t+60}}{StockWAP_t} - \\\\frac{IndexWAP_{t+60}}{IndexWAP_t} \\\\right) \\\\times 10000\\n$$\\n\\n\uc989, \uc2dc\uc7a5 \uc804\uccb4\uc758 \uc6c0\uc9c1\uc784\uc744 \uc81c\uac70\ud55c \uac1c\ubcc4 \uc885\ubaa9\uc758 \\"\uc0c1\ub300\uc801\\" \uac00\uaca9 \ubcc0\ud654\ub97c \ub9de\ucd94\ub294 \ubb38\uc81c\ub2e4.\\n\\n### \ud3c9\uac00 \uc9c0\ud45c\\n\\nMean Absolute Error (MAE)\\n\\n$$\\nMAE = \\\\frac{1}{n} \\\\sum_{i=1}^{n} |y_i - x_i|\\n$$\\n\\n\uc5ec\uae30\uc11c:\\n\\n- $n$ \uc740 \uc804\uccb4 \ub370\uc774\ud130 \ud3ec\uc778\ud2b8\uc758 \uc218\ub2e4.\\n- $y_i$ \ub294 \ub370\uc774\ud130 \ud3ec\uc778\ud2b8 $i$ \uc758 \uc608\uce21\uac12\uc774\ub2e4.\\n- $x_i$ \ub294 \ub370\uc774\ud130 \ud3ec\uc778\ud2b8 $i$ \uc758 \uad00\uce21\uac12\uc774\ub2e4.\\n\\n### \ub370\uc774\ud130 \uad6c\uc870\\n\\n\ud559\uc2b5 \ub370\uc774\ud130\ub294 481\uc77c\uac04 \uc57d 200\uac1c \uc885\ubaa9\uc758 \uc885\uac00 \uacbd\ub9e4 \uc2a4\ub0c5\uc0f7\uc73c\ub85c, \uc57d 500\ub9cc \ud589 \uaddc\ubaa8\ub2e4. \uc8fc\uc694 \uceec\ub7fc\uc740 \ub2e4\uc74c\uacfc \uac19\ub2e4:\\n\\n- `stock_id`: \uc885\ubaa9 \uace0\uc720 \uc2dd\ubcc4\uc790\\n- `date_id`: \ub0a0\uc9dc \uc2dd\ubcc4\uc790 (\uc21c\ucc28\uc801)\\n- `seconds_in_bucket`: \uacbd\ub9e4 \uc2dc\uc791 \ud6c4 \uacbd\uacfc \uc2dc\uac04 (\ucd08)\\n- `imbalance_size`: \ud604\uc7ac reference_price\uc5d0\uc11c \ub9e4\uce6d\ub418\uc9c0 \uc54a\uc740 \ubb3c\ub7c9 (USD)\\n- `imbalance_buy_sell_flag`: \ubd88\uade0\ud615 \ubc29\ud5a5: 1(\ub9e4\uc218 \ucd08\uacfc), -1(\ub9e4\ub3c4 \ucd08\uacfc), 0(\uc5c6\uc74c)\\n- `reference_price`: \ub9e4\uce6d \uc218\ub7c9\uc774 \ucd5c\ub300\uac00 \ub418\ub294 \uac00\uaca9\\n- `matched_size`: \ud604\uc7ac reference_price\uc5d0\uc11c \ub9e4\uce6d \uac00\ub2a5\ud55c \ubb3c\ub7c9 (USD)\\n- `far_price` / `near_price`: \uacbd\ub9e4 \uc8fc\ubb38\ub9cc/\uc5f0\uc18d \uc8fc\ubb38 \ud3ec\ud568 \uc2dc \ucd5c\uc801 \uccb4\uacb0\uac00\\n- `bid_price` / `ask_price`: \ube44\uacbd\ub9e4 \ud638\uac00\ucc3d\uc758 \ucd5c\uc6b0\uc120 \ub9e4\uc218/\ub9e4\ub3c4 \uac00\uaca9\\n- `bid_size` / `ask_size`: \ucd5c\uc6b0\uc120 \ud638\uac00\uc758 \ubb3c\ub7c9 (USD)\\n- `wap`: \ube44\uacbd\ub9e4 \ud638\uac00\ucc3d\uc758 \uac00\uc911\ud3c9\uade0\uac00\uaca9 ($BidP \\\\times AskS + AskP \\\\times BidS) / (BidS + AskS)$\\n\\n---\\n\\n## \ub0b4 \uc811\uadfc \ubc29\uc2dd\\n\\n### \ud53c\ucc98 \uc5d4\uc9c0\ub2c8\uc5b4\ub9c1\\n\\n`my-submission.ipynb`\uc5d0\uc11c \ucd1d 124\uac1c\uc758 \ud53c\ucc98\ub97c \uc0ac\uc6a9\ud588\ub2e4. \ud06c\uac8c \ub2e4\uc12f \uac00\uc9c0 \uce74\ud14c\uace0\ub9ac\ub85c \ub098\ub20c \uc218 \uc788\ub2e4\\n\\n**1. \uc720\ub3d9\uc131/\ubd88\uade0\ud615 \ud53c\ucc98**\\n\\n- `liquidity_imbalance`: \ud638\uac00 \ubb3c\ub7c9 \ubd88\uade0\ud615 \u2192 `(bid_size - ask_size) / (bid_size + ask_size)`\\n- `matched_imbalance`: \ub9e4\uce6d/\ubd88\uade0\ud615 \ubb3c\ub7c9 \ube44\uc728 \u2192 `(imbalance_size - matched_size) / (imbalance_size + matched_size)`\\n- `size_imbalance`: \ub2e8\uc21c \ube44\uc728 \u2192 `bid_size / ask_size`\\n- `imbalance_momentum`: \uc885\ubaa9\ubcc4 `imbalance_size`\uc758 \uc2dc\uac04 \ubcc0\ud654\ub97c `matched_size`\ub85c \ub098\ub208 \uac12\\n\\n**2. \uac00\uaca9 \uc2a4\ud504\ub808\ub4dc \ud53c\ucc98**\\n\\n- `price_spread`: `ask_price - bid_price`\\n- `spread_intensity`: \uc885\ubaa9\ubcc4 \uc2a4\ud504\ub808\ub4dc \ubcc0\ud654\ub7c9\\n- `price_pressure`: `imbalance_size * price_spread`\\n- `market_urgency`: `price_spread * liquidity_imbalance`\\n\\n**3. \uac00\uaca9 \uc30d/\uc0bc\uc911 \ube44\uc728 \ud53c\ucc98**\\n\\n- 6\uac1c \uac00\uaca9(`reference_price`, `far_price`, `near_price`, `ask_price`, `bid_price`, `wap`)\uc758 \ubaa8\ub4e0 \uc30d \uc870\ud569\uc73c\ub85c imbalance \ube44\uc728 \uacc4\uc0b0 \u2192 `(P1 - P2) / (P1 + P2)` \ud615\ud0dc\\n- Numba\ub85c \uac00\uc18d\ud55c triplet imbalance: \uc138 \uac00\uaca9\uc758 (max - mid) / (mid - min) \ube44\uc728\\n\\n**4. \uc2dc\uacc4\uc5f4 \ud53c\ucc98**\\n\\n- `matched_size`, `imbalance_size`, `reference_price`, `imbalance_buy_sell_flag`\uc758 1/2/3/10 \ub798\uadf8\uc640 pct_change\\n- `ask_price`, `bid_price`, `ask_size`, `bid_size`, `market_urgency`, `imbalance_momentum`, `size_imbalance`\uc758 1/2/3/10 diff\\n\\n**5. \uc804\uc5ed \ud1b5\uacc4 \ud53c\ucc98**\\n\\n- \uc885\ubaa9\ubcc4 `bid_size`, `ask_size`, `bid_price`, `ask_price`\uc758 median, std, ptp(peak-to-peak)\ub97c \uacc4\uc0b0\ud574 `global_*` \ud615\ud0dc\ub85c \ub9e4\ud551\\n- \uc2dc\uac04 \ud30c\uc0dd: `dow`(\uc694\uc77c), `seconds`, `minute`\\n\\n### \ubaa8\ub378\uacfc \ud559\uc2b5\\n\\n- **\ubaa8\ub378**: LightGBM (`objective=\'mae\'`, **Tesla P100 GPU**)\\n- **\ud558\uc774\ud37c\ud30c\ub77c\ubbf8\ud130**: n_estimators=6000, num_leaves=256, max_depth=11, learning_rate=0.00871, subsample=0.6, colsample_bytree=0.8\\n- **\uac80\uc99d**: \ub0a0\uc9dc \uae30\uc900 5-fold CV, \uac01 fold \uc0ac\uc774\uc5d0 5\uc77c purge gap \uc801\uc6a9 (\uc2dc\uac04 \ub204\uc218 \ubc29\uc9c0)\\n- **\ucd5c\uc885 \ud559\uc2b5**: 5\uac1c fold\uc758 \ud3c9\uade0 best_iteration(\uc57d 5103)\uc73c\ub85c \uc804\uccb4 \ub370\uc774\ud130 \uc7ac\ud559\uc2b5\\n\\n### \ucd94\ub860\\n\\n- \uc885\ubaa9\ubcc4 \ucd5c\uadfc 21\ud589\uc744 \ub864\ub9c1 \uce90\uc2dc\ub85c \uc720\uc9c0\ud558\uba74\uc11c \ud53c\ucc98 \uc0dd\uc131\\n- 5\uac1c fold \ubaa8\ub378\uc758 equal-weight \uc559\uc0c1\ube14\\n- `zero_sum` \ud6c4\ucc98\ub9ac: \uc608\uce21\uac12\uc5d0\uc11c **\uac70\ub798\ub7c9(bid+ask size)\uc758 \uc81c\uacf1\uadfc**\uc744 \uac00\uc911\uce58\ub85c \uc368\uc11c \uac00\uc911 \ud3c9\uade0\uc744 \ube80\ub2e4. \uc2dc\uc7a5 \uc804\uccb4\uc758 \ud569\uc774 0\uc774 \ub418\ub3c4\ub85d \ub9de\ucd94\ub294 \uacfc\uc815\uc774\ub2e4.\\n- \ud074\ub9ac\ud551: [-64, 64] \ubc94\uc704\ub85c \uc81c\ud55c\\n\\n---\\n\\n## \uacb0\uacfc\\n\\n| \ud56d\ubaa9              | \uac12                                          |\\n| ----------------- | ------------------------------------------- |\\n| 5-fold CV MAE     | 5.83 (fold\ubcc4: 6.75, 6.12, 5.97, 5.49, 4.80) |\\n| Public/Private LB | 5.4744                                      |\\n| \uc21c\uc704              | 981\uc704 / 3,225\ud300 (Top 30%)                   |\\n| \uc2e4\ud589 \uc2dc\uac04         | 2\uc2dc\uac04 35\ubd84 (P100 GPU)                       |\\n| \ucd94\ub860 \uc18d\ub3c4         | \ubc30\uce58\ub2f9 ~0.34\ucd08                              |\\n\\n---\\n\\n## \uc0c1\uc704 \uc194\ub8e8\uc158\uacfc \ube44\uad50\\n\\n\ub300\ud68c\uac00 \ub05d\ub098\uace0 \uc0c1\uc704\uad8c \uc194\ub8e8\uc158\ub4e4\uc744 \uc0b4\ud3b4\ubd24\ub2e4. \uc544\ub798\ub294 \ub0b4\uac00 \ub193\uce5c \ubd80\ubd84\uc774 \ubb34\uc5c7\uc778\uc9c0 \uc815\ub9ac\ud55c \uac83\uc774\ub2e4.\\n\\n### 1\uc704 \u2013 HYD (hydantess)\\n\\n- **\ubaa8\ub378**: CatBoost(50%) + GRU(30%) + Transformer(20%) \uc559\uc0c1\ube14\\n- **\ud2b9\uc9d5**: GRU\ub294 55\uac1c \ud0c0\uc784\uc2a4\ud15d\uc758 \uc2dc\uacc4\uc5f4 \ud328\ud134\uc744, Transformer\ub294 200\uac1c \uc885\ubaa9 \uac04 cross-sectional \uad00\uacc4\ub97c \ud3ec\ucc29\\n- **\uc628\ub77c\uc778 \ud559\uc2b5**: 12\uc77c\ub9c8\ub2e4 \uc7ac\ud559\uc2b5 (\ucd1d 4\ud68c)\\n- **\uac00\uc911 zero_sum**: `pred -= (pred * stock_weights).sum() / stock_weights.sum()`\\n- **\uc0d8\ud50c \uac00\uc911\uce58**: `1.0 / (stock_std + 1e-7)`\ub85c \uc885\ubaa9\ubcc4 \ubcc0\ub3d9\uc131 \uc815\uaddc\ud654\\n\\n### 9\uc704 \u2013 ADAM. (hookman)\\n\\n- **\ubaa8\ub378**: 3\xd7 XGBoost (\ub2e4\ub978 \uc2dc\ub4dc)\\n- **\ud53c\ucc98**: 157\uac1c, median-scaled \ubb3c\ub7c9, MACD, WAP \uae30\ubc18 \ud0c0\uae43 \ud504\ub85d\uc2dc\\n- **\ub370\uc774\ud130 \uac00\uc911\uce58**: \ucd5c\uadfc 45\uc77c\uc5d0 1.5\ubc30 \uac00\uc911\uce58\\n- **\uc628\ub77c\uc778 \ud559\uc2b5**: Day N, Day N+30\uc5d0 \uc7ac\ud559\uc2b5\\n\\n### 14\uc704 \u2013 Clash Royale (5\uc778 \ud300)\\n\\n- **\ubaa8\ub378**: LightGBM + CatBoost \ub2e8\uc21c \ud3c9\uade0\\n- **\ud53c\ucc98**: 193\uac1c, revealed target \ub798\uadf8, RSI/MACD/Bollinger Bands\\n- **\uc628\ub77c\uc778 \ud559\uc2b5**: 6~9\uc77c\ub9c8\ub2e4 LGB/CAT \uad50\ub300 \uc7ac\ud559\uc2b5\\n- **\ud575\uc2ec \uc218\uc815**: `mid_price_movement` \uacc4\uc0b0 \uc2dc `stock_id` \uadf8\ub8f9\ud654\ub85c \ub204\uc218 \uc218\uc815\\n\\n### 15\uc704 \u2013 O Yuksel (lognorm)\\n\\n- **\ubaa8\ub378**: 3\xd7 LGB(\uc624\ud504\ub77c\uc778) + 4\xd7 XGB + 1\xd7 LGB(\uc628\ub77c\uc778)\\n- **\ud53c\ucc98**: revealed target, \uc2dc\uc7a5/\uc139\ud130 \ub300\ube44 \uc0c1\ub300 \uc131\uacfc, stock_id \ub300\uc2e0 \ud589\ub3d9 \uae30\ubc18 \uc784\ubca0\ub529\\n- **\ud6c4\ucc98\ub9ac**: \ub2e8\uc21c zero-sum \ub300\uc2e0 index-weighted mean \ucc28\uac10\\n\\n### \uacf5\ud1b5\uc810\uacfc \ub0b4\uac00 \ub193\uce5c \uac83\ub4e4\\n\\n| \uc0c1\uc704\uad8c \ud2b9\uc9d5                                              | \ub0b4 \uc194\ub8e8\uc158                      |\\n| -------------------------------------------------------- | ------------------------------ |\\n| **\uc628\ub77c\uc778 \ud559\uc2b5** (6~30\uc77c\ub9c8\ub2e4 \uc7ac\ud559\uc2b5)                      | \ud55c \ubc88 \ud559\uc2b5 \ud6c4 \uace0\uc815             |\\n| **\ub2e4\uc911 \ubaa8\ub378 \uc559\uc0c1\ube14** (LGB+CAT+XGB \ub610\ub294 +GRU/Transformer) | LightGBM \ub2e8\uc77c                  |\\n| **\uc885\ubaa9\ubcc4 \uc2a4\ucf00\uc77c\ub9c1** (stock_std, median)                  | \uc804\uc5ed \ud1b5\uacc4\ub9cc \uc0ac\uc6a9               |\\n| **\uac00\uc911 zero_sum**                                        | \ub2e8\uc21c \uac70\ub798\ub7c9 \uc81c\uacf1\uadfc \uac00\uc911\uce58 \uc0ac\uc6a9 |\\n| **revealed target \ud53c\ucc98**                                 | \uc0ac\uc6a9 \uc548 \ud568                     |\\n| **\uc2dc\ub4dc \ub2e4\uc591\uc131** (\uac19\uc740 \ubaa8\ub378 3\uac1c \uc774\uc0c1)                     | 5-fold \uc559\uc0c1\ube14\ub9cc                |\\n\\n---\\n\\n## \ud68c\uace0\\n\\n### \uc798\ud55c \uc810\\n\\n- Numba\ub85c triplet imbalance\ub97c \uac00\uc18d\ud574\uc11c \ud53c\ucc98 \uc0dd\uc131 \uc2dc\uac04\uc744 \uc904\uc600\ub2e4\\n- \ub0a0\uc9dc \uae30\ubc18 purge gap\uc73c\ub85c \uc2dc\uac04 \ub204\uc218\ub97c \uc5b5\uc81c\ud588\ub2e4\\n- \uba54\ubaa8\ub9ac \ub2e4\uc6b4\uce90\uc2a4\ud305\uc73c\ub85c Kaggle \ud658\uacbd\uc5d0\uc11c\ub3c4 \uc548\uc815\uc801\uc73c\ub85c \ub3cc\uc558\ub2e4\\n\\n### \uc544\uc26c\uc6b4 \uc810\\n\\n- **\uc628\ub77c\uc778 \ud559\uc2b5\uc744 \uc548 \ud588\ub2e4.** \uc774 \ub300\ud68c\ub294 API\uac00 \ub9e4\uc77c \uc7a5 \uc2dc\uc791 \ub54c **\uc804\ub0a0\uc758 \uc815\ub2f5(`revealed_targets`)\uc744 \uc81c\uacf5**\ud574\uc900\ub2e4. \uc0c1\uc704\uad8c\ub4e4\uc740 \uc774 \ub370\uc774\ud130\ub97c \ubc84\ub9ac\uc9c0 \uc54a\uace0 \ubaa8\ub378\uc744 \uc8fc\uae30\uc801\uc73c\ub85c \uc7ac\ud559\uc2b5(retrain)\uc2dc\ucf1c\uc11c \uc2dc\uc7a5\uc758 \ucd5c\uc2e0 \ud2b8\ub80c\ub4dc\ub97c \ubc18\uc601\ud588\ub2e4. \ub098\ub294 \ubaa8\ub378\uc744 \ud55c \ubc88 \ud559\uc2b5\uc2dc\ud0a4\uace0 3\uac1c\uc6d4 \ub0b4\ub0b4 \uadf8\ub300\ub85c \ub46c\uc11c drift\uc5d0 \ub300\uc751\ud558\uc9c0 \ubabb\ud588\ub2e4.\\n- **\uc2dc\ud000\uc2a4 \ubaa8\ub378\uc744 \uc548 \ubd99\uc600\ub2e4.** 1\uc704 \uc194\ub8e8\uc158\uc740 GRU\ub85c \uc2dc\uac04 \uc21c\uc11c, Transformer\ub85c \uc885\ubaa9 \uac04 \uad00\uacc4\ub97c \ud3ec\ucc29\ud588\ub2e4. \ud2b8\ub9ac \ubaa8\ub378\ub9cc\uc73c\ub85c\ub294 \uc774\ub7f0 \uad6c\uc870\uc801 \ud328\ud134\uc744 \uc7a1\uae30 \uc5b4\ub824\uc6e0\uc744 \uac83\uc774\ub2e4.\\n- **\uc885\ubaa9\ubcc4 \uc815\uaddc\ud654\uac00 \uc5c6\uc5c8\ub2e4.** stock_std\ub098 median\uc73c\ub85c \uc2a4\ucf00\uc77c\ub9c1\ud588\uc73c\uba74 \uc885\ubaa9 \uac04 \ubcc0\ub3d9\uc131 \ucc28\uc774\ub97c \ubcf4\uc815\ud560 \uc218 \uc788\uc5c8\ub2e4.\\n- Google ML Bootcamp \uc218\ub8cc\ub97c \ubaa9\uc801\uc73c\ub85c \ud55c \ud504\ub85c\uc81d\ud2b8\uc774\uae30\uc5d0 \ub300\ud68c\uac00 \ub05d\ub0a0 \ub54c\uae4c\uc9c0 \ub04a\uae30\uc788\uac8c \ud558\uc9c0 \uc54a\uc558\ub2e4. \uc880 \ub354 \ub178\ub825\uc744 \ud588\uc73c\uba74 \ub354 \ub192\uc740 \uc810\uc218\ub3c4 \ubc1b\uc744 \uc218 \uc788\uc9c0 \uc54a\uc558\uc744\uae4c \uc2f6\ub2e4.\\n\\n---\\n\\n## \ucc38\uace0 \uc790\ub8cc\\n\\n- [1st place \u2013 HYD](https://www.kaggle.com/competitions/optiver-trading-at-the-close/writeups/hyd-1st-place-solution)\\n- [9th place \u2013 ADAM.](https://www.kaggle.com/competitions/optiver-trading-at-the-close/writeups/adam-9th-place-solution)\\n- [14th place \u2013 Clash Royale](https://www.kaggle.com/competitions/optiver-trading-at-the-close/writeups/clash-royale-14th-place-solution-for-the-optiver-t)\\n- [15th place \u2013 O Yuksel](https://www.kaggle.com/competitions/optiver-trading-at-the-close/writeups/o-yuksel-15th-place-solution)\\n- [Kaggle Data Page](https://www.kaggle.com/competitions/optiver-trading-at-the-close/data)"},{"id":"/pyodide","metadata":{"permalink":"/projects/pyodide","source":"@site/projects/pyodide.md","title":"Pyodide","description":"Pyodide \ube4c\ub4dc \uc2dc\uc2a4\ud15c \uac1c\uc120\uacfc WASM SIMD \ucd5c\uc801\ud654 \uae30\uc5ec","date":"2026-06-28T23:16:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"Pyodide","description":"Pyodide \ube4c\ub4dc \uc2dc\uc2a4\ud15c \uac1c\uc120\uacfc WASM SIMD \ucd5c\uc801\ud654 \uae30\uc5ec","role":"Contributor","timeline":"Ongoing","stack":["Python","WebAssembly","C++"],"category":"Open Source","image":"/img/projects/pyodide/logo-pyodide-repositioned.png","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"Optiver \\"Trading at the Close\\" \ub300\ud68c","permalink":"/projects/optiver-kaggle"},"nextItem":{"title":"RecSys \ud589\ub3d9 \uc774\ubca4\ud2b8 \ud50c\ub7ab\ud3fc","permalink":"/projects/recs-behavior-platform"}},"content":"{/* truncate */}\\n\\n# Pyodide\\n\\nPyodide\uc5d0 \uae30\uc5ec\ud558\uba74\uc11c \ud55c \uc791\uc5c5\uc740 \ud06c\uac8c \ub450 \uac08\ub798\uc600\ub2e4. \ud558\ub098\ub294 \ube4c\ub4dc \uc2dc\uc2a4\ud15c\uc744 \uc870\uae08 \ub35c \ubc88\uac70\ub86d\uac8c \ub9cc\ub4dc\ub294 \uc77c\uc774\uc5c8\uace0, \ub2e4\ub978 \ud558\ub098\ub294 WASM SIMD\ub97c \uc2e4\uc81c\ub85c \uc4f8 \uc218 \uc788\uac8c \ud655\uc778\ud558\uace0 OpenBLAS\uc5d0 \ubd99\uc774\ub294 \uc77c\uc774\uc5c8\ub2e4.\\n\\n## \uc65c \uc774 \uc791\uc5c5\uc744 \ud588\ub294\uac00\\n\\nPyodide\ub294 Python runtime\uacfc \uacfc\ud559 \uacc4\uc0b0 \ud328\ud0a4\uc9c0\ub97c WebAssembly \uc704\uc5d0\uc11c \uc2e4\ud589\ud558\uac8c \ud574\uc8fc\ub294 \ud504\ub85c\uc81d\ud2b8\ub2e4. \ube0c\ub77c\uc6b0\uc800 \uc548\uc5d0\uc11c NumPy, SciPy \uac19\uc740 \ud328\ud0a4\uc9c0\ub97c \ub3cc\ub9b4 \uc218 \uc788\ub2e4\ub294 \uc810\uc774 \ud765\ubbf8\ub85c\uc6e0\uace0, WebAssembly\ub97c \uacf5\ubd80\ud558\uba74\uc11c \uc2e4\uc81c \ud328\ud0a4\uc9c0 \ube4c\ub4dc\uc640 \uc131\ub2a5 \uac80\uc99d\uc774 \uc5b4\ub5bb\uac8c \uc774\uc5b4\uc9c0\ub294\uc9c0 \uc9c1\uc811 \ud655\uc778\ud574\ubcf4\uace0 \uc2f6\uc5c8\ub2e4.\\n\\n\ucc98\uc74c\uc5d0\ub294 \uc791\uc740 \ube4c\ub4dc \ub3c4\uad6c \uac1c\uc120\uc5d0\uc11c \uc2dc\uc791\ud588\ub2e4. \uc774\ud6c4 WebAssembly SIMD\uac00 Pyodide \ud658\uacbd\uc5d0\uc11c \uc2e4\uc81c\ub85c \ub3d9\uc791\ud558\ub294\uc9c0 \ud655\uc778\ud558\ub294 \uc774\uc288\ub97c \ubcf4\uba74\uc11c, \ub2e8\uc21c\ud788 flag\ub97c \ucf1c\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \ud14c\uc2a4\ud2b8 \ud328\ud0a4\uc9c0, OpenBLAS \ube4c\ub4dc, \ubca4\uce58\ub9c8\ud06c\uae4c\uc9c0 \uc774\uc5b4\uc9c0\ub294 \uac80\uc99d \ud750\ub984\uc744 \ub9cc\ub4e4\uc5b4\ubcf4\uace0 \uc2f6\uc5c8\ub2e4.\\n\\n## \ube4c\ub4dc \uc2dc\uc2a4\ud15c \uac1c\uc120\\n\\nPyodide \ube4c\ub4dc \uc2dc\uc2a4\ud15c\uc744 \uc4f0\ub2e4 \ubcf4\ub2c8 \uc18c\uc2a4 \ud30c\uc77c\uacfc \uc911\uac04 \ube4c\ub4dc \uacb0\uacfc\ubb3c\uc744 \ud55c \ubc88\uc5d0 \uc815\ub9ac\ud558\ub294 \uae30\ubcf8 \uba85\ub839\uc774 \uc5c6\ub2e4\ub294 \uc810\uc774 \ubd88\ud3b8\ud588\ub2e4. \uacb0\uad6d \ub514\ub809\ud1a0\ub9ac\ub97c \uc9c1\uc811 \uc9c0\uc6cc\uc57c \ud588\ub294\ub370, \uc790\uc8fc \uc4f0\ub294 \ud750\ub984\uce58\uace0\ub294 \uc190\uc774 \ub9ce\uc774 \uac14\ub2e4.\\n\\n[Issue #218](https://github.com/pyodide/pyodide-build/issues/218)\uc5d0\uc11c \uc2dc\uc791\ud55c \uc791\uc5c5\uc740 \ub450 \ubc88\uc5d0 \ub098\ub220 \uc9c4\ud589\ud588\ub2e4.\\n\\n1. **[PR #223](https://github.com/pyodide/pyodide-build/pull/223)**\uc5d0\uc11c \uc815\ub9ac \ub85c\uc9c1\uc744 \uba3c\uc800 \ub123\uc5c8\ub2e4. \uc18c\uc2a4 \ub808\uc774\uc544\uc6c3\uacfc \ube4c\ub4dc \ub514\ub809\ud1a0\ub9ac\ub97c \uc9c0\uc6b0\ub418, \uae30\ubcf8\uc801\uc73c\ub85c\ub294 \ube4c\ub4dc\ub41c \ud720\uc774 \ub4e4\uc5b4 \uc788\ub294 `dist` \ud3f4\ub354\ub294 \ub0a8\uae30\ub3c4\ub85d \ud588\ub2e4.\\n2. **[PR #254](https://github.com/pyodide/pyodide-build/pull/254)**\uc5d0\uc11c \uc774 \uae30\ub2a5\uc744 `pyodide clean recipes` \uba85\ub839\uc73c\ub85c \uaebc\ub0b4 \uc4f8 \uc218 \uc788\uac8c \ud588\ub2e4. \uadf8 \ub4a4\ub85c\ub294 \ud2b9\uc815 \ud328\ud0a4\uc9c0\ub9cc \uc9c0\uc6b0\uac70\ub098 \uc791\uc5c5 \uacf5\uac04 \uc804\uccb4\ub97c \uc815\ub9ac\ud558\ub294 \ud750\ub984\uc774 \ud6e8\uc52c \ub2e8\uc21c\ud574\uc84c\ub2e4.\\n\\n## WASM SIMD \ud65c\uc131\ud654\\n\\n\ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c Pyodide\ub97c \uc4f8 \ub54c \uc131\ub2a5\uc740 \uaf64 \uc911\uc694\ud55c \ubb38\uc81c\ub2e4. Emscripten\uc774 WebAssembly SIMD\ub97c \uc9c0\uc6d0\ud558\uae34 \ud588\uc9c0\ub9cc, Pyodide \ud658\uacbd\uc5d0\uc11c\ub3c4 \uc774 \uacbd\ub85c\uac00 \uc2e4\uc81c\ub85c \uc798 \uc791\ub3d9\ud558\ub294\uc9c0\ub294 \ub530\ub85c \ud655\uc778\uc774 \ud544\uc694\ud588\ub2e4. \uadf8\ub798\uc11c [Issue #5855](https://github.com/pyodide/pyodide/issues/5855)\ub97c \uae30\uc900\uc73c\ub85c SIMD\ub97c \uac80\uc99d\ud558\uace0 \uc2e4\uc81c \ud328\ud0a4\uc9c0\uc5d0 \uc801\uc6a9\ud558\ub294 \uc791\uc5c5\uc744 \uc9c4\ud589\ud588\ub2e4.\\n\\n### \uac80\uc99d \uc791\uc5c5\\n\\n\uba3c\uc800 [PR #5880](https://github.com/pyodide/pyodide/pull/5880)\uc5d0\uc11c `test-simd` \ud328\ud0a4\uc9c0\ub97c \ub9cc\ub4e4\uc5b4 \uae30\ubcf8 \uacbd\ub85c\ub97c \ud655\uc778\ud588\ub2e4. \uc5ec\uae30\uc11c\ub294 \ub450 \uac00\uc9c0\ub97c \ubd24\ub2e4.\\n\\n- `wasm_simd128.h` \ub0b4\uc7a5 \ud568\uc218\ub97c \uc9c1\uc811 \uc4f0\ub294 \ubc29\uc2dd\\n- Emscripten\uc774 SSE/AVX \ub0b4\uc7a5 \ud568\uc218\ub97c WASM SIMD\ub85c \ubc14\uafd4 \uc8fc\ub294 \ubc29\uc2dd\\n\\n### OpenBLAS \uc801\uc6a9\\n\\n\uac80\uc99d\uc774 \ub05d\ub09c \ub2e4\uc74c\uc5d0\ub294 NumPy\uc640 SciPy \ubc11\ub2e8\uc5d0 \uc788\ub294 **OpenBLAS**\ub85c \ub118\uc5b4\uac14\ub2e4. \ud655\uc778\ud574 \ubcf4\ub2c8 \uae30\uc874 OpenBLAS \ube4c\ub4dc\ub294 SIMD\ub97c \uac70\uc758 \ud65c\uc6a9\ud558\uc9c0 \ubabb\ud558\uace0 \uc788\uc5c8\uace0, \uc774 \ubd80\ubd84\uc740 [Issue #5948](https://github.com/pyodide/pyodide/issues/5948)\ub85c \uc815\ub9ac\ud588\ub2e4.\\n\\n[PR #5960](https://github.com/pyodide/pyodide/pull/5960)\uc5d0\uc11c\ub294 `-msimd128`\ub85c \ucef4\ud30c\uc77c\ud558\ub294 `libopenblas-simd` \ub808\uc2dc\ud53c\ub97c \ucd94\uac00\ud588\uace0, `test-openblas-simd`\ub85c `sdot`, `sgemm` \uac19\uc740 \uc5f0\uc0b0\uc758 \uc131\ub2a5 \ucc28\uc774\ub97c \ube44\uad50\ud560 \uc218 \uc788\uac8c \ud588\ub2e4. \uac80\uc99d\ub9cc \ud558\uace0 \ub05d\ub0b8 \uac8c \uc544\ub2c8\ub77c \uc2e4\uc81c \ud328\ud0a4\uc9c0\uc5d0 SIMD\ub97c \ubd99\uc774\uace0 \ubca4\uce58\ub9c8\ud06c\uae4c\uc9c0 \ub0a8\uae34 \uc791\uc5c5\uc774\uc5c8\ub2e4.\\n\\n## \ud574\uacb0 \uacfc\uc815\uc5d0\uc11c \uc0dd\uae34 \ubb38\uc81c\uc640 \uacb0\uc815\\n\\n\ube4c\ub4dc \uc2dc\uc2a4\ud15c \uac1c\uc120\uc5d0\uc11c \uba3c\uc800 \uc815\ub9ac\ud574\uc57c \ud588\ub358 \ubb38\uc81c\ub294 \\"\ubb34\uc5c7\uc744 \uc9c0\uc6b8 \uac83\uc778\uac00\\"\uc600\ub2e4. \uc18c\uc2a4\uc640 \uc911\uac04 \ube4c\ub4dc \uc0b0\ucd9c\ubb3c\uc740 \ub2e4\uc2dc \ub9cc\ub4e4 \uc218 \uc788\uc9c0\ub9cc, \uc774\ubbf8 \ub9cc\ub4e4\uc5b4 \ub454 wheel\uc774 \ub4e4\uc5b4 \uc788\ub294 `dist`\uae4c\uc9c0 \uc9c0\uc6b0\uba74 \uc0ac\uc6a9\uc790\uac00 \uc758\ub3c4\ud558\uc9c0 \uc54a\uc740 \uacb0\uacfc\ub97c \uc783\uc744 \uc218 \uc788\ub2e4. \uadf8\ub798\uc11c \uc815\ub9ac \ub85c\uc9c1\uc740 \ube4c\ub4dc \uc791\uc5c5 \uacf5\uac04\uc744 \ube44\uc6b0\ub418 `dist`\ub294 \uae30\ubcf8\uc801\uc73c\ub85c \ubcf4\uc874\ud558\ub294 \ubc29\ud5a5\uc73c\ub85c \uc7a1\uc558\uace0, \uc774\ud6c4 \ubcc4\ub3c4 CLI \uba85\ub839\uc73c\ub85c \uaebc\ub0b4 \uc4f8 \uc218 \uc788\uac8c \ub098\ub234\ub2e4.\\n\\nSIMD \ucabd\uc5d0\uc11c\ub294 compile flag\ub9cc \ubcf4\uace0 \uc131\uacf5\uc774\ub77c\uace0 \ub9d0\ud560 \uc218 \uc5c6\uc5c8\ub2e4. Emscripten\uc774 `wasm_simd128.h`\uc640 SSE/AVX intrinsic\uc744 WebAssembly SIMD\ub85c \uc5b4\ub5bb\uac8c \ubc14\uafb8\ub294\uc9c0 \uc2e4\uc81c wasm test\ub85c \ud655\uc778\ud574\uc57c \ud588\ub2e4. \uadf8\ub798\uc11c `test-simd` \ud328\ud0a4\uc9c0\ub97c \uba3c\uc800 \ub9cc\ub4e4\uace0, \uc9c1\uc811 SIMD intrinsic\uc744 \uc4f0\ub294 \uacbd\ub85c\uc640 x86 intrinsic\uc774 \ubcc0\ud658\ub418\ub294 \uacbd\ub85c\ub97c \ubd84\ub9ac\ud574 \uac80\uc99d\ud588\ub2e4.\\n\\nOpenBLAS \uc801\uc6a9\uc5d0\uc11c\ub294 \\"SIMD\ub97c \ucf30\ub2e4\\"\ubcf4\ub2e4 \\"NumPy/SciPy \ud558\uc704 BLAS \uc5f0\uc0b0\uc5d0\uc11c \ucc28\uc774\ub97c \ubcfc \uc218 \uc788\ub294\uac00\\"\uac00 \uc911\uc694\ud588\ub2e4. \uae30\uc874 \ube4c\ub4dc\uac00 SIMD\ub97c \ucda9\ubd84\ud788 \ud65c\uc6a9\ud558\uc9c0 \ubabb\ud55c\ub2e4\ub294 \uc810\uc744 \uc774\uc288\ub85c \uc815\ub9ac\ud558\uace0, `libopenblas-simd` \ub808\uc2dc\ud53c\uc640 `test-openblas-simd`\ub97c \ucd94\uac00\ud588\ub2e4. `sdot`, `sgemm` \uac19\uc740 \uc5f0\uc0b0\uc744 \uae30\uc900\uc73c\ub85c \ube44\uad50\ud560 \uc218 \uc788\uac8c \ub9cc\ub4e4\uc5b4\uc11c, \uae30\ub2a5 \ucd94\uac00\uc640 \uc131\ub2a5 \ud655\uc778\uc744 \uac19\uc740 PR \uc548\uc5d0\uc11c \uc124\uba85\ud560 \uc218 \uc788\uc5c8\ub2e4.\\n\\n## \uacb0\uacfc\\n\\n### Pyodide\\n\\n#### Release 0.29\\n\\nSIMD \uad00\ub828 \uc791\uc5c5\uc740 `pyodide` \uba54\uc778 \uc800\uc7a5\uc18c\uc5d0 \ub4e4\uc5b4\uac14\uace0 0.29 \ub9b4\ub9ac\uc2a4\uc5d0\ub3c4 \ud3ec\ud568\ub410\ub2e4. \uc790\uc138\ud55c \ub0b4\uc6a9\uc740 [Pyodide 0.29 Release Blog](https://blog.pyodide.org/posts/0.29-release/)\uc5d0\uc11c \ud655\uc778\ud560 \uc218 \uc788\ub2e4.\\n\\n![SIMD Support Exploration](/img/projects/pyodide/simd-exploration.png)\\n\\n### Pyodide-build\\n\\n`pyodide-build` \ucabd \uc791\uc5c5\uc740 0.30.8, 0.30.9, 0.31.0\uc5d0 \uac78\uccd0 \ub9b4\ub9ac\uc2a4\ub410\ub2e4.\\n\\n#### Release 0.30.8\\n\\n\ud504\ub85c\uc81d\ud2b8\uc5d0 \ucc98\uc74c\uc73c\ub85c \ub4e4\uc5b4\uac04 \uae30\uc5ec\uc600\ub2e4.\\n\\n![0.30.8 \ub9b4\ub9ac\uc2a4](/img/projects/pyodide/release-0.30.8.png)\\n\\n#### Release 0.30.9\\n\\n`pyodide clean recipes` \uba85\ub839\uc774 \ub9b4\ub9ac\uc2a4\uc5d0 \ud3ec\ud568\ub410\ub2e4.\\n\\n![0.30.9 \ub9b4\ub9ac\uc2a4](/img/projects/pyodide/release-0.30.9.png)\\n\\n#### Release 0.31.0\\n\\n\ucd94\uac00 \ub9ac\ud329\ud1a0\ub9c1\uacfc \uc815\ub9ac\uac00 \ubc18\uc601\ub410\ub2e4.\\n\\n![0.31.0 \ub9b4\ub9ac\uc2a4](/img/projects/pyodide/release-0.31.0.png)\\n\\n## \uae30\uc5ec \uc694\uc57d\\n\\n| \ud504\ub85c\uc81d\ud2b8 | PR | \uc124\uba85 | \uc0c1\ud0dc |\\n| :--- | :--- | :--- | :--- |\\n| [pyodide-build](https://github.com/pyodide/pyodide-build) | [PR #223](https://github.com/pyodide/pyodide-build/pull/223) | \ub808\uc2dc\ud53c \uc815\ub9ac \ub85c\uc9c1 \uad6c\ud604 | Merged |\\n| [pyodide-build](https://github.com/pyodide/pyodide-build) | [PR #254](https://github.com/pyodide/pyodide-build/pull/254) | `pyodide clean recipes` CLI \uba85\ub839 \ucd94\uac00 | Merged |\\n| [pyodide](https://github.com/pyodide/pyodide) | [PR #5880](https://github.com/pyodide/pyodide/pull/5880) | WASM/SSE/AVX \ub0b4\uc7a5 \ud568\uc218 \uac80\uc99d\uc744 \uc704\ud55c `test-simd` \ud328\ud0a4\uc9c0 \ucd94\uac00 | Merged |\\n| [pyodide](https://github.com/pyodide/pyodide) | [PR #5960](https://github.com/pyodide/pyodide/pull/5960) | OpenBLAS (WASM)\uc5d0 \ub300\ud55c SIMD \ud65c\uc131\ud654 | Merged |"},{"id":"/recs-behavior-platform","metadata":{"permalink":"/projects/recs-behavior-platform","source":"@site/projects/recs-behavior-platform.md","title":"RecSys \ud589\ub3d9 \uc774\ubca4\ud2b8 \ud50c\ub7ab\ud3fc","description":"Synerise RecSys 2025 \ud589\ub3d9 \ub85c\uadf8\ub97c Java, Kafka, Flink, Elasticsearch \uae30\ubc18 event-to-feature pipeline\uc73c\ub85c \uc7ac\ud574\uc11d\ud55c \ubc31\uc5d4\ub4dc \ud504\ub85c\uc81d\ud2b8","date":"2026-06-28T23:16:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"RecSys \ud589\ub3d9 \uc774\ubca4\ud2b8 \ud50c\ub7ab\ud3fc","description":"Synerise RecSys 2025 \ud589\ub3d9 \ub85c\uadf8\ub97c Java, Kafka, Flink, Elasticsearch \uae30\ubc18 event-to-feature pipeline\uc73c\ub85c \uc7ac\ud574\uc11d\ud55c \ubc31\uc5d4\ub4dc \ud504\ub85c\uc81d\ud2b8","role":"Backend Engineer","timeline":"May 2026 - Jun 2026","stack":["Java","Python","Kafka","Flink","Elasticsearch","Docker","Kubernetes"],"category":"Personal Project","image":"/img/projects/recs-behavior-platform/architecture.png","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"Pyodide","permalink":"/projects/pyodide"},"nextItem":{"title":"LLM PR Reviewer","permalink":"/projects/serverless-code-review"}},"content":"{/* truncate */}\\n\\n# RecSys \ud589\ub3d9 \uc774\ubca4\ud2b8 \ud50c\ub7ab\ud3fc\\n\\n## \uc65c \uc774 \ud504\ub85c\uc81d\ud2b8\ub97c \ub9cc\ub4e4\uc5c8\ub294\uac00\\n\\n\ucd94\ucc9c \uc2dc\uc2a4\ud15c\uc744 \uacf5\ubd80\ud558\ub2e4 \ubcf4\ub2c8 \ubaa8\ub378 \uc790\uccb4\ubcf4\ub2e4 \uadf8 \uc55e\ub4a4\uc758 \uc2dc\uc2a4\ud15c\uc774 \uad81\uae08\ud574\uc84c\ub2e4. \uc0ac\uc6a9\uc790\uc758 \ud589\ub3d9 \ub85c\uadf8\uac00 \uc5b4\ub5a4 \ud615\ud0dc\ub85c \ub4e4\uc5b4\uc624\uace0, \uadf8 \ub85c\uadf8\ub97c \uc5b4\ub5bb\uac8c profile\ub85c \uc9d1\uacc4\ud558\uace0, serving API\uc5d0\uc11c\ub294 \uadf8 profile\uc744 \uc5b4\ub5bb\uac8c \uc77d\uc5b4 \ud6c4\ubcf4\ub97c \ub9cc\ub4dc\ub294\uc9c0 \uc9c1\uc811 \uc124\uacc4\ud574\ubcf4\uace0 \uc2f6\uc5c8\ub2e4.\\n\\n\ub370\uc774\ud130\ub294 Synerise RecSys Challenge 2025\uc5d0\uc11c \uacf5\uac1c\ub41c \ud589\ub3d9 \ub85c\uadf8\ub97c \uc0ac\uc6a9\ud588\ub2e4. \uc6d0\ub798\ub294 Universal Behavioral Profiles\ub97c \ub9cc\ub4dc\ub294 \ub300\ud68c \ub370\uc774\ud130\uc9c0\ub9cc, \ub098\ub294 \uc774 \ub85c\uadf8\ub97c \ucd94\ucc9c \ubaa8\ub378 \ud559\uc2b5 \ubb38\uc81c\uac00 \uc544\ub2c8\ub77c event pipeline \uc785\ub825\uc73c\ub85c \ub2e4\uc2dc \ud574\uc11d\ud588\ub2e4. Python\uc73c\ub85c \uc6d0\ubcf8 row\ub97c normalized event\ub85c \ubc14\uafb8\uace0, Java, Kafka, Flink, Elasticsearch\ub97c \uac70\uccd0 \uc0ac\uc6a9\uc790 behavior profile\uacfc \ud6c4\ubcf4 \uc0c1\ud488 feature\ub97c \uc870\ud68c\ud558\ub294 \uc791\uc740 event-to-feature pipeline\uc744 \ub9cc\ub4e4\uc5b4\ubd24\ub2e4.\\n\\n## \ub370\uc774\ud130\uc640 \uc804\ucc98\ub9ac\\n\\n\uc0ac\uc6a9\ud55c \ub370\uc774\ud130\ub294 Synerise\uac00 \uacf5\uac1c\ud55c [RecSys Challenge 2025 Universal Behavioral Modeling Dataset](https://www.recsyschallenge.com/2025/)\uc774\ub2e4. \uc774 \ub370\uc774\ud130\uc14b\uc740 \uc775\uba85\ud654\ub41c \uc2e4\uc81c \uc0ac\uc6a9\uc790 interaction log\ub85c \uad6c\uc131\ub418\uc5b4 \uc788\uace0, \ub300\ud68c \ubaa9\ud45c\ub294 \uc5ec\ub7ec downstream task\uc5d0 \uc7ac\uc0ac\uc6a9\ud560 \uc218 \uc788\ub294 Universal Behavioral Profiles\ub97c \ub9cc\ub4dc\ub294 \uac83\uc774\ub2e4. \uacf5\uc2dd \uc124\uba85 \uae30\uc900 \ub370\uc774\ud130\uc5d0\ub294 product buy, add to cart, remove from cart, page visit, search query event\uc640 product attributes\uac00 \ud3ec\ud568\ub41c\ub2e4.\\n\\n\ub370\uc774\ud130\uc14b \uc804\uccb4 \uaddc\ubaa8\ub294 \uaf64 \ud06c\ub2e4. \uacf5\uc2dd \ud398\uc774\uc9c0 \uae30\uc900\uc73c\ub85c product buy\ub294 \uc57d 170\ub9cc \uac74, add to cart\ub294 \uc57d 520\ub9cc \uac74, remove from cart\ub294 \uc57d 170\ub9cc \uac74, page visit\uc740 \uc57d 1\uc5b5 5\ucc9c\ub9cc \uac74, search query\ub294 \uc57d 960\ub9cc \uac74\uc774\uace0, unique user\ub294 \uc57d 1,900\ub9cc \uba85\uc774\ub2e4. \ub77c\uc774\uc120\uc2a4\ub294 CC BY-NC 4.0\uc774\ub2e4.\\n\\n\uc774 \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c\ub294 \uc804\uccb4 \ub370\uc774\ud130\ub97c \uadf8\ub300\ub85c \ud559\uc2b5\uc5d0 \uc4f0\ub294 \ub300\uc2e0, replay\uc640 smoke \uac80\uc99d\uc774 \uac00\ub2a5\ud55c slice\ub85c \uc798\ub77c event pipeline \uc785\ub825\uc73c\ub85c \ubc14\uafe8\ub2e4. \ud575\uc2ec \ubcc0\ud658\uc740 \uc544\ub798\uc640 \uac19\ub2e4.\\n\\n| \uc6d0\ubcf8 | \uc6d0\ubcf8 \ud544\ub4dc | \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c \ub9cc\ub4e0 \ud615\ud0dc |\\n|---|---|---|\\n| `product_buy` | `client_id`, `timestamp`, `sku` | `event_type=product_buy`\uc778 normalized behavior event |\\n| `add_to_cart` | `client_id`, `timestamp`, `sku` | `event_type=add_to_cart`\uc778 normalized behavior event |\\n| `remove_from_cart` | `client_id`, `timestamp`, `sku` | `event_type=remove_from_cart`\uc778 normalized behavior event |\\n| `product_properties` | `sku`, `category`, `price`, `embedding` | product feature document |\\n\\nPython normalizer\ub294 \uc6d0\ubcf8 row\ub97c `event_id`, `event_type`, `client_id`, `event_time`, `sku`, `source`, `schema_version`\uc744 \uac00\uc9c4 NDJSON event\ub85c \ubc14\uafbc\ub2e4. `event_id`\ub294 source, event type, client id, event time, sku\ub97c \uc870\ud569\ud574 deterministic\ud558\uac8c \ub9cc\ub4e4\uc5c8\ub2e4. \uc774 \ub355\ubd84\uc5d0 \uac19\uc740 \uc6d0\ubcf8 row\ub97c \ub2e4\uc2dc replay\ud574\ub3c4 \uac19\uc740 idempotency key\uac00 \ub9cc\ub4e4\uc5b4\uc9c4\ub2e4.\\n\\n`product_properties`\ub294 \ubcc4\ub3c4\uc758 product feature document\ub85c \ubcc0\ud658\ud588\ub2e4. \uc774 \ubb38\uc11c\ub294 Elasticsearch\uc5d0 \uc800\uc7a5\ub418\uace0, candidate API\uac00 behavior profile\uc758 top sku\ub97c \uc77d\uc744 \ub54c category, price bucket, freshness \uac19\uc740 \ud6c4\ubcf4 \uc0c1\ud488 metadata\ub97c \ud568\uaed8 \uc870\ud68c\ud558\ub294 \ub370 \uc4f4\ub2e4.\\n\\n## \ubb38\uc81c \uc815\uc758\\n\\n\ucd94\ucc9c \uc2dc\uc2a4\ud15c \uc8fc\ubcc0 \uc778\ud504\ub77c\uc5d0\uc11c \ud575\uc2ec\uc774 \ub418\ub294 \ubb38\uc81c\ub294 \uc544\ub798\uc600\ub2e4.\\n\\n- \uac19\uc740 \uc6d0\ubcf8 row\ub97c \ub2e4\uc2dc replay\ud574\ub3c4 \uac19\uc740 event id\uac00 \ub9cc\ub4e4\uc5b4\uc838\uc57c \ud55c\ub2e4.\\n- \uac19\uc740 event\uac00 \uc911\ubcf5 \uc18c\ube44\ub418\uc5b4\ub3c4 profile count\uac00 \ubd80\ud480\uba74 \uc548 \ub41c\ub2e4.\\n- \ub108\ubb34 \ub2a6\uac8c \ub3c4\ucc29\ud55c event\ub294 \ucd5c\uc2e0 profile\uc744 \ub418\ub3cc\ub9ac\uc9c0 \uc54a\uc544\uc57c \ud55c\ub2e4.\\n- profile\uacfc product feature\ub97c Elasticsearch\uc5d0 \uc800\uc7a5\ud574 API\uac00 \uc870\ud68c\ud560 \uc218 \uc788\uc5b4\uc57c \ud55c\ub2e4.\\n- \uc7a5\uc560\ub098 \uc7ac\uc2dc\uc791 \ub4a4\uc5d0\ub3c4 replay, checkpoint, dead-letter \uae30\uc900\uc744 \uc124\uba85\ud560 \uc218 \uc788\uc5b4\uc57c \ud55c\ub2e4.\\n\\n\uc774 \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c\ub294 \uc644\uc804\ud55c \ucd94\ucc9c \ubaa8\ub378\uc774\ub098 production cluster\ub97c \ub9cc\ub4e4\uc5c8\ub2e4\uace0 \uc8fc\uc7a5\ud558\uc9c0 \uc54a\ub294\ub2e4. \ub300\uc2e0 \ucd94\ucc9c serving path \uc55e\ub2e8\uc758 event normalization, profile aggregation, feature lookup, failure accounting\uc744 \uad6c\ud604\ud558\uace0 smoke\ub85c \uac80\uc99d\ud588\ub2e4.\\n\\n## \uc804\uccb4 \ud750\ub984\\n\\n<div className=\\"project-architecture-frame\\">\\n  <img\\n    className=\\"project-architecture-image\\"\\n    src=\\"/img/projects/recs-behavior-platform/architecture.png\\"\\n    alt=\\"RecSys event-to-feature pipeline architecture\\"\\n  />\\n</div>\\n\\n```text\\nSynerise-style rows\\n  -> Python normalizer\\n  -> normalized behavior events\\n  -> Kafka topic\\n  -> Flink keyed aggregation\\n  -> Elasticsearch behavior profile store\\n  -> Java profile and candidate API\\n```\\n\\n\ub370\uc774\ud130\uc14b\uc758 \uc6d0\ub798 \ubaa9\uc801\uc740 Universal Behavioral Profiles \ubaa8\ub378\ub9c1\uc774\ub2e4. \uc774 \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c\ub294 \uadf8 \ub85c\uadf8\ub97c \ucd94\ucc9c \uc778\ud504\ub77c \uad00\uc810\uc73c\ub85c \ubc14\uafd4 \ubd24\ub2e4. Python normalizer\uac00 product event\ub97c \uc548\uc815\uc801\uc778 event contract\ub85c \ub9cc\ub4e4\uace0, Java API\uc640 Flink job\uc740 client id \uae30\uc900 profile state\ub97c materialize\ud55c\ub2e4.\\n\\n## \uad6c\ud604\ud55c \ubc94\uc704\\n\\n### Event contract\uc640 replay\\n\\nPython normalizer\ub294 Synerise-style product row\ub97c normalized event JSON\uc73c\ub85c \ubc14\uafbc\ub2e4. event id\ub294 source, event type, client id, event time, sku\ub97c \uc0ac\uc6a9\ud574 deterministic\ud558\uac8c \ub9cc\ub4e4\uc5c8\ub2e4. \uc774 \uae30\uc900 \ub355\ubd84\uc5d0 \uac19\uc740 row replay\uac00 \uac19\uc740 idempotency key\ub97c \uac16\ub294\ub2e4. page visit\uacfc search query\ub294 \ub370\uc774\ud130\uc14b \ub9e5\ub77d\uc5d0\ub294 \ud3ec\ud568\ub418\uc9c0\ub9cc, \ud604\uc7ac public project \ubb38\uc11c\uc5d0\uc11c \uc124\uba85\ud558\ub294 \uc2e4\ud589 \uacbd\ub85c\ub294 product event\uc640 product feature\ub97c \uc911\uc2ec\uc73c\ub85c \ub2eb\uc558\ub2e4.\\n\\nJava \ucabd\uc5d0\uc11c\ub294 `BehaviorEvent` record\uc640 loader\ub97c \ub9cc\ub4e4\uc5b4 \uac19\uc740 contract\ub97c \uc77d\ub3c4\ub85d \ud588\ub2e4. `client_id`\ub294 Kafka key\uc774\uba74\uc11c Flink keyed state boundary\ub2e4.\\n\\n### Profile aggregation\\n\\n\ucd08\uae30\uc5d0\ub294 in-memory projector\ub85c event count, event type count, distinct sku count, last event time, top sku\ub97c \uacc4\uc0b0\ud588\ub2e4. \uc774 path\uac00 baseline\uc774 \ub418\uc5c8\uace0, \uc774\ud6c4 Kafka input, Flink aggregation, Elasticsearch profile store\ub85c \ud55c \ub2e8\uacc4\uc529 \uad50\uccb4\ud588\ub2e4.\\n\\nFlink aggregation\uc5d0\uc11c\ub294 duplicate event id\ub97c suppress\ud558\uace0, keyed max event time\ubcf4\ub2e4 10\ubd84 \ucd08\uacfc\ub85c \ub2a6\uc740 event\ub294 profile snapshot\uc5d0 \ubc18\uc601\ud558\uc9c0 \uc54a\uac8c \ud588\ub2e4. \ub108\ubb34 \ub2a6\uc740 event\ub294 configured dead-letter path\uac00 \uc788\uc73c\uba74 Kafka dead-letter topic\uc73c\ub85c \ubcf4\ub0b8\ub2e4.\\n\\n### API\uc640 feature serving\\n\\nJava HTTP API\ub294 `GET /users/{client_id}/behavior-profile`\ub85c profile\uc744 \ubc18\ud658\ud55c\ub2e4. \uc774\ud6c4 product feature path\ub97c \ucd94\uac00\ud574 `GET /features/products/{sku}`\uc640 `GET /users/{client_id}/candidates`\ub3c4 \ub9cc\ub4e4\uc5c8\ub2e4.\\n\\nCandidate API\ub294 \uc544\uc9c1 ranking model\uc774 \uc544\ub2c8\ub2e4. behavior profile\uc758 top sku \uc21c\uc11c\ub97c \uc720\uc9c0\ud558\uba74\uc11c product feature freshness\uc640 category affinity\ub97c deterministic score\uc5d0 \ubc18\uc601\ud558\ub294 prototype\uc774\ub2e4. \uadf8\ub798\uc11c \uae00\uc5d0\uc11c\ub3c4 \\"full recommendation serving\\"\uc774 \uc544\ub2c8\ub77c \\"feature-backed deterministic candidate scoring prototype\\"\uc73c\ub85c \uad6c\ubd84\ud55c\ub2e4.\\n\\n### \uc6b4\uc601\uc131\\n\\n\uc774 \ud504\ub85c\uc81d\ud2b8\uc758 \uc911\uc694\ud55c \ubd80\ubd84\uc740 \uc2e4\ud328 \uacbd\ub85c\ub97c \uc791\uac8c\ub77c\ub3c4 \ub0a8\uae34 \uac83\uc774\ub2e4.\\n\\n- Java file ingestion\uc5d0\uc11c invalid event\ub97c dead-letter\ub85c capture\\n- Kafka dead-letter sink\uc640 publisher boundary \uad6c\ud604\\n- Flink late-event exclusion\uacfc Kafka dead-letter output smoke\\n- `GET /metrics/pipeline`\uc73c\ub85c dead-letter count\uc640 late-event count \ub178\ucd9c\\n- Elasticsearch-backed latest pipeline metrics snapshot \uc800\uc7a5\\n- kind \uae30\ubc18 API, Kafka, Elasticsearch, replay worker, standalone Flink runtime \uac80\uc99d\\n- local PVC-backed Flink recovery variant\uc640 TaskManager, JobManager restart proof\\n\\n## \ud574\uacb0 \uacfc\uc815\uc5d0\uc11c \uc0dd\uae34 \ubb38\uc81c\uc640 \uacb0\uc815\\n\\n\uccab \ubc88\uc9f8 \ubb38\uc81c\ub294 \ub300\ud68c \ub370\uc774\ud130\ub97c \uc11c\ube44\uc2a4 event\ucc98\ub7fc \ub2e4\uc2dc \ud574\uc11d\ud558\ub294 \uc77c\uc774\uc5c8\ub2e4. \uc6d0\ubcf8 row\ub294 \ubaa8\ub378 \ud559\uc2b5\uc6a9 \ud589\ub3d9 \ub85c\uadf8\uc5d0 \uac00\uae5d\uae30 \ub54c\ubb38\uc5d0, \uadf8\ub300\ub85c Kafka\uc5d0 \ub123\uc73c\uba74 event contract\uac00 \uc560\ub9e4\ud574\uc9c4\ub2e4. \uadf8\ub798\uc11c Python normalizer\ub97c \uba3c\uc800 \ub9cc\ub4e4\uace0, source, event type, client id, event time, sku\ub85c deterministic event id\ub97c \ub9cc\ub4e4\uc5c8\ub2e4. \uac19\uc740 row\ub97c replay\ud574\ub3c4 \uac19\uc740 id\uac00 \ub098\uc624\uac8c \ud55c \uac83\uc774 \uc774\ud6c4 idempotency \uae30\uc900\uc774 \ub410\ub2e4.\\n\\n\ub450 \ubc88\uc9f8 \ubb38\uc81c\ub294 aggregation\uc758 \uc911\ubcf5\uacfc late event\uc600\ub2e4. \uac19\uc740 event\ub97c \ub450 \ubc88 \uc18c\ube44\ud558\uba74 event count\uc640 top sku\uac00 \ud2c0\uc5b4\uc9c0\uace0, \ub108\ubb34 \ub2a6\uac8c \uc628 event\ub97c \ubc18\uc601\ud558\uba74 \ucd5c\uc2e0 profile\uc774 \uacfc\uac70 \uc0c1\ud0dc\ub85c \ub418\ub3cc\uc544\uac08 \uc218 \uc788\ub2e4. Flink keyed aggregation\uc5d0\uc11c\ub294 seen event id\ub97c \uae30\uc900\uc73c\ub85c duplicate\ub97c suppress\ud558\uace0, keyed max event time\ubcf4\ub2e4 10\ubd84 \ub118\uac8c \ub2a6\uc740 event\ub294 profile\uc5d0\ub294 \ubc18\uc601\ud558\uc9c0 \uc54a\uace0 dead-letter\ub85c \ubd84\ub9ac\ud588\ub2e4.\\n\\n\uc138 \ubc88\uc9f8 \ubb38\uc81c\ub294 local \uac80\uc99d \ubc94\uc704\uc600\ub2e4. \ub2e8\uc21c unit test\ub9cc\uc73c\ub85c\ub294 Kafka, Flink, Elasticsearch, API \uc0ac\uc774\uc758 contract\uac00 \ub9de\ub294\uc9c0 \uc54c\uae30 \uc5b4\ub835\ub2e4. \uadf8\ub798\uc11c \ucc98\uc74c\uc5d0\ub294 in-memory projector\ub85c \uae30\uc900 \ub3d9\uc791\uc744 \ub9cc\ub4e4\uace0, \uc774\ud6c4 Kafka vertical slice, Flink to Elasticsearch smoke, candidate API smoke, kind \uae30\ubc18 recovery smoke\ub97c \uc21c\uc11c\ub300\ub85c \ubd99\uc600\ub2e4. \uac01 \ub2e8\uacc4\ub294 \ud558\ub098\uc758 \uc2e4\ud328 \uc6d0\uc778\ub9cc \ub4dc\ub7ec\ub098\ub3c4\ub85d \uc881\uac8c \ub098\ub234\ub2e4.\\n\\n## \uac80\uc99d\\n\\n\ub300\ud45c \uac80\uc99d\uc740 \uc544\ub798\uc640 \uac19\ub2e4.\\n\\n| \uac80\uc99d | \ub0b4\uc6a9 |\\n|---|---|\\n| `bash scripts/test.sh` | Python test, Compose helper test, Kubernetes manifest validator, image packaging validator, Flink recovery policy validator, Java test 92\uac1c \ud1b5\uacfc |\\n| `bash scripts/smoke-local-vertical-slice.sh` | NDJSON\uc5d0\uc11c Java API profile \uc870\ud68c\uae4c\uc9c0 local path \uac80\uc99d |\\n| `bash scripts/smoke-kafka-vertical-slice.sh` | Kafka publish/consume \uc774\ud6c4 Java API profile \uc870\ud68c \uac80\uc99d |\\n| `bash scripts/smoke-flink-kafka-elasticsearch-vertical-slice.sh` | Flink output\uc744 Elasticsearch\uc5d0 \uc800\uc7a5\ud558\uace0 API\uac00 profile\uc744 \uc77d\ub294 path \uac80\uc99d |\\n| `bash scripts/smoke-candidate-vertical-slice.sh` | behavior profile\uacfc product feature\ub97c \uacb0\ud569\ud55c candidate API \uac80\uc99d |\\n| `bash scripts/smoke-kind-flink-job-profile.sh` | standalone Flink job\uc774 Elasticsearch profile\uc744 \uc4f0\uace0 reader-only API\uac00 \uc870\ud68c\ud558\ub294 path \uac80\uc99d |\\n| `bash scripts/smoke-kind-flink-jobmanager-recovery.sh` | JobManager restart \uc774\ud6c4 job running \uc0c1\ud0dc\uc640 API profile \uc720\uc9c0 \ud655\uc778 |\\n\\nkind replay worker smoke\uc5d0\uc11c\ub294 fixture event\ub97c Kafka\ub85c publish\ud55c \ub4a4 API\uac00 `client_id=123`, `event_count=2`, `distinct_sku_count=2`, `top_skus=[456,789]`\ub97c \ubc18\ud658\ud558\ub294 \uac83\uc744 \ud655\uc778\ud588\ub2e4.\\n\\n## References\\n\\n- [RecSys Challenge 2025](https://www.recsyschallenge.com/2025/)\\n- [RecSys Challenge 2025 by Synerise summary](https://recsys.synerise.com/summary)\\n- [Synerise/recsys2025 repository](https://github.com/Synerise/recsys2025)"},{"id":"/serverless-code-review","metadata":{"permalink":"/projects/serverless-code-review","source":"@site/projects/serverless-code-review.md","title":"LLM PR Reviewer","description":"GitHub PR diff\ub97c \uc218\uc9d1\ud558\uace0 Amazon Bedrock\uc73c\ub85c \ub9ac\ubdf0 \ucf54\uba58\ud2b8\ub97c \uc0dd\uc131\ud558\ub294 \uc11c\ubc84\ub9ac\uc2a4 PR \ub9ac\ubdf0 \uc6cc\ud06c\ud50c\ub85c","date":"2026-06-28T23:16:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"LLM PR Reviewer","description":"GitHub PR diff\ub97c \uc218\uc9d1\ud558\uace0 Amazon Bedrock\uc73c\ub85c \ub9ac\ubdf0 \ucf54\uba58\ud2b8\ub97c \uc0dd\uc131\ud558\ub294 \uc11c\ubc84\ub9ac\uc2a4 PR \ub9ac\ubdf0 \uc6cc\ud06c\ud50c\ub85c","role":"Cloud Engineer","timeline":"Jan 2025 - Feb 2025","stack":["AWS Lambda","API Gateway","DynamoDB","DynamoDB Streams","EventBridge","SNS","Amazon S3","Amazon Bedrock Knowledge Bases","Amazon OpenSearch Serverless","Amazon Bedrock","Anthropic Claude 3.5 Sonnet v2","GitHub API"],"category":"Work Project","image":"/img/projects/serverless-code-review/architecture.png","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"RecSys \ud589\ub3d9 \uc774\ubca4\ud2b8 \ud50c\ub7ab\ud3fc","permalink":"/projects/recs-behavior-platform"},"nextItem":{"title":"wasm-bindgen Float16Array \uae30\uc5ec","permalink":"/projects/wasm-bindgen-float16array"}},"content":"{/* truncate */}\\n\\n# LLM PR Reviewer\\n\\n## \uc65c \uc774 \ud504\ub85c\uc81d\ud2b8\ub97c \ub9cc\ub4e4\uc5c8\ub294\uac00\\n\\nAWS \uc778\ud134\uc2ed\uc5d0\uc11c ACC Korea \uc18c\uc18d \ub300\ud559\uc0dd\uc744 \ub300\uc0c1\uc73c\ub85c \uc0dd\uc131\ud615 AI\uc640 \uc11c\ubc84\ub9ac\uc2a4 \uc544\ud0a4\ud14d\ucc98\ub97c \ud568\uaed8 \ub2e4\ub8e8\ub294 [\ud578\uc988\uc628 \uc6cc\ud06c\uc20d](https://www.meetup.com/aws-sbg-at-sookmyung-women-university/events/306005836/)\uc744 \uc900\ube44\ud588\ub2e4. \ub2e8\uc21c\ud788 \ubaa8\ub378\uc744 \ud638\ucd9c\ud574\ubcf4\ub294 \ub370\ubaa8\ubcf4\ub2e4, \uac1c\ubc1c\uc790\uc5d0\uac8c \uc775\uc219\ud55c \ud750\ub984\uc774 \ud544\uc694\ud588\ub2e4. \uadf8\ub798\uc11c GitHub Pull Request\ub97c \ub9cc\ub4e4\uba74 \ubcc0\uacbd \ub0b4\uc6a9\uc744 \uc77d\uace0 1\ucc28 \ub9ac\ubdf0 \ucf54\uba58\ud2b8\ub97c \ub0a8\uae30\ub294 \uc6cc\ud06c\ud50c\ub85c\ub97c \uc8fc\uc81c\ub85c \uc7a1\uc558\ub2e4.\\n\\n\uc774 \ud504\ub85c\uc81d\ud2b8\uc758 \ubaa9\ud45c\ub294 \\"AI\uac00 \ucf54\ub4dc \ub9ac\ubdf0\ub97c \ub300\uc2e0\ud55c\ub2e4\\"\uac00 \uc544\ub2c8\uc5c8\ub2e4. PR \uc774\ubca4\ud2b8\ub97c \ubc1b\uace0, \ubcc0\uacbd \ud30c\uc77c\uacfc diff\ub97c \uc815\ub9ac\ud558\uace0, \ub9ac\ubdf0 \uae30\uc900\uc744 \ud568\uaed8 \ub123\uc5b4 Bedrock\uc73c\ub85c \ub9ac\ubdf0 \ucd08\uc548\uc744 \ub9cc\ub4e0 \ub4a4, GitHub\uc5d0 \ub2e4\uc2dc \ucf54\uba58\ud2b8\ub97c \ub0a8\uae30\ub294 \uc804\uccb4 \ud750\ub984\uc744 \ud559\uc0dd\ub4e4\uc774 \uc9c1\uc811 \ub530\ub77c\uac08 \uc218 \uc788\uac8c \ub9cc\ub4dc\ub294 \uac83\uc774\uc5c8\ub2e4. \uc6cc\ud06c\uc20d\uc5d0\uc11c \uc4f0\uc774\ub294 \uc2dc\uc2a4\ud15c\uc774\uc5c8\uae30 \ub54c\ubb38\uc5d0 \uae30\ub2a5 \uad6c\ud604\ubfd0 \uc544\ub2c8\ub77c \uc2e4\ud328 \uc9c0\uc810, \uc7ac\ucc98\ub9ac \uac00\ub2a5\uc131, [\ubb38\uc11c\ud654](https://acc.awskorea.kr/)\uae4c\uc9c0 \uac19\uc774 \ubd10\uc57c \ud588\ub2e4.\\n\\n## \ud504\ub85c\uc81d\ud2b8 \uac1c\uc694\\n\\nLLM PR Reviewer \ud504\ub85c\uc81d\ud2b8\ub294 GitHub Webhook\uc5d0\uc11c \uc2dc\uc791\ub418\ub294 \uc11c\ubc84\ub9ac\uc2a4 \ucf54\ub4dc \ub9ac\ubdf0 \uc6cc\ud06c\ud50c\ub85c\ub2e4. GitHub \uc774\ubca4\ud2b8\uac00 \ub4e4\uc5b4\uc624\uba74 API Gateway\uc640 Lambda\uac00 \uc774\ubca4\ud2b8\ub97c \ubc1b\uace0, Issue \uc774\ubca4\ud2b8\uc640 Pull Request \uc774\ubca4\ud2b8\ub97c \ub098\ub220 \ucc98\ub9ac\ud55c\ub2e4. Issue\uac00 \uc0dd\uc131\ub41c \uacbd\uc6b0\uc5d0\ub294 \ubcc4\ub3c4 Lambda\uac00 SNS \uc54c\ub9bc\uc744 \ubcf4\ub0b4\uace0, PR\uc774 \uc0dd\uc131\ub41c \uacbd\uc6b0\uc5d0\ub294 diff \uc6d0\ubb38\uc774 \uc544\ub2c8\ub77c PR\uc744 \ub2e4\uc2dc \uc870\ud68c\ud560 \uc218 \uc788\ub294 \uc815\ubcf4\ub97c DynamoDB\uc5d0 \uc800\uc7a5\ud55c\ub2e4. DynamoDB\uc5d0\ub294 PR \ubc88\ud638, \uc800\uc7a5\uc18c \uc774\ub984, PR URL, PR \uc791\uc131\uc790, \uc774\ubca4\ud2b8 \uc885\ub958, \uc561\uc158, \uc0dd\uc131 \uc2dc\uac01, \ub9c8\uc9c0\ub9c9 \uac31\uc2e0 \uc2dc\uac01, diff URL\uc744 \ub0a8\uacbc\ub2e4. \uc774\ud6c4 DynamoDB Streams\uc5d0 \uc5f0\uacb0\ub41c Lambda\uac00 PR \uc54c\ub9bc\uacfc \ub9ac\ubdf0 \uc0dd\uc131\uc744 \ub2f4\ub2f9\ud55c\ub2e4. \uc774 Lambda\ub294 DynamoDB\uc5d0 \uc800\uc7a5\ub41c PR \uc815\ubcf4\ub97c \ubc14\ud0d5\uc73c\ub85c GitHub API\uc5d0\uc11c \ubcc0\uacbd \ud30c\uc77c\uacfc patch\ub97c \uc870\ud68c\ud574 \ub9ac\ubdf0 \uc785\ub825\uc744 \ub9cc\ub4e4\uace0, Bedrock Knowledge Bases\uc5d0\uc11c \uac80\uc0c9\ud55c \ub9ac\ubdf0 \uae30\uc900 \ucee8\ud14d\uc2a4\ud2b8\ub97c \ud568\uaed8 \ubd99\uc5ec Bedrock \ud504\ub86c\ud504\ud2b8\ub97c \uad6c\uc131\ud55c\ub2e4. \uc0dd\uc131\ub41c \ucf54\uba58\ud2b8\ub294 \ub2e4\uc2dc GitHub API\ub85c PR\uc5d0 \ubc18\uc601\ud55c\ub2e4.\\n\\n\uc804\uccb4 \uad6c\uc870\ub294 \uc544\ub798\uc640 \uac19\ub2e4.\\n\\n<div className=\\"project-architecture-frame\\">\\n  <img\\n    className=\\"project-architecture-image\\"\\n    src=\\"/img/projects/serverless-code-review/architecture.png\\"\\n    alt=\\"LLM PR Reviewer architecture\\"\\n  />\\n</div>\\n\\n\ub9ac\ubdf0 \uc0dd\uc131\uc5d0\ub294 Amazon Bedrock\uc758 Anthropic Claude 3.5 Sonnet v2\ub97c \uc0ac\uc6a9\ud588\ub2e4. \uc6cc\ud06c\uc20d \ud658\uacbd\uc5d0\uc11c\ub294 \ucc38\uac00\uc790\ub4e4\uc774 \uac01\uc790 AWS \uacc4\uc815\uc5d0\uc11c \ubaa8\ub378 \uc811\uadfc \uad8c\ud55c\uc744 \uc694\uccad\ud574\uc57c \ud588\uae30 \ub54c\ubb38\uc5d0, \ubaa8\ub378 \uc131\ub2a5\ubfd0 \uc544\ub2c8\ub77c \ubaa8\ub378 \uc0ac\uc6a9 \uac00\ub2a5 \uc5ec\ubd80\uc640 API \ud560\ub2f9\ub7c9\ub3c4 \ud568\uaed8 \uace0\ub824\ud574\uc57c \ud588\ub2e4.\\n\\n\ub0b4\uac00 \ub2f4\ub2f9\ud55c \ubd80\ubd84\uc740 Bedrock\uacfc \uc5f0\uacb0\ub418\ub294 \ub9ac\ubdf0 \uc0dd\uc131 \ud750\ub984, GitHub API\ub97c \ud1b5\ud55c diff \uc218\uc9d1, \ud504\ub86c\ud504\ud2b8 \uac1c\uc120, SNS \uae30\ubc18 \uc54c\ub9bc, \uadf8\ub9ac\uace0 \uc6cc\ud06c\uc20d \uc804 \uc804\uccb4 \ud750\ub984 \ud14c\uc2a4\ud2b8\uc600\ub2e4. \ucd08\uae30\uc5d0\ub294 \ucf54\ub4dc\uac00 \uc2e4\ud589\ub418\ub294\uc9c0\ub9cc \ud655\uc778\ud558\uba74 \ub41c\ub2e4\uace0 \uc0dd\uac01\ud558\uae30 \uc26c\uc6e0\uc9c0\ub9cc, \uc2e4\uc81c\ub85c\ub294 \\"\ubaa8\ub378\uc774 \uc5b4\ub5a4 \uc785\ub825\uc744 \ubcf4\uace0 \uc65c \uadf8\ub7f0 \ub9ac\ubdf0\ub97c \ub0a8\uacbc\ub294\uac00\\"\ub97c \uc124\uba85\ud560 \uc218 \uc788\uc5b4\uc57c \ud588\ub2e4.\\n\\n## \ubb38\uc81c \uc815\uc758\\n\\n\uac00\uc7a5 \ud070 \ubb38\uc81c\ub294 PR diff\ub97c \uadf8\ub300\ub85c \ubaa8\ub378\uc5d0 \ub123\uc73c\uba74 \ub9ac\ubdf0 \ud488\uc9c8\uc774 \ud754\ub4e4\ub9b0\ub2e4\ub294 \uc810\uc774\uc5c8\ub2e4. PR\uc740 \ud30c\uc77c \ud558\ub098\ub9cc \ubc14\ub00c\ub294 \uacbd\uc6b0\ub3c4 \uc788\uc9c0\ub9cc, \uc5ec\ub7ec \ud30c\uc77c\uc774 \ub3d9\uc2dc\uc5d0 \ubc14\ub00c\uac70\ub098 \ubcc0\uacbd \uaddc\ubaa8\uac00 \ud070 \uacbd\uc6b0\ub3c4 \ub9ce\ub2e4. \uc774\ub54c diff\ub97c \ub2e8\uc21c\ud788 \uc774\uc5b4 \ubd99\uc774\uba74 \ubaa8\ub378\uc774 \uc911\uc694\ud55c \ubcc0\uacbd\uc744 \ub193\uce58\uac70\ub098, \ud30c\uc77c \uac04 \uad00\uacc4\ub97c \ubcf4\uc9c0 \ubabb\ud55c \ucc44 \uc77c\ubc18\uc801\uc778 \uc870\uc5b8\ub9cc \ubc18\ubcf5\ud560 \uc218 \uc788\ub2e4.\\n\\n\ub450 \ubc88\uc9f8 \ubb38\uc81c\ub294 \uc6cc\ud06c\uc20d \uc2e4\uc2b5 \ud658\uacbd\uc774\uc5c8\ub2e4. \ud558\ub098\uc758 \uacf5\uc720 \uc11c\ube44\uc2a4\uc5d0 \ucc38\uac00\uc790\ub4e4\uc774 \uc811\uc18d\ud558\ub294 \ubc29\uc2dd\uc774 \uc544\ub2c8\ub77c, \ucc38\uac00\uc790 \uac01\uc790\uac00 \uc790\uc2e0\uc758 AWS \uacc4\uc815\uc5d0\uc11c \uac19\uc740 \uc544\ud0a4\ud14d\ucc98\ub97c \uad6c\uc131\ud558\ub294 \ubc29\uc2dd\uc774\uc5c8\ub2e4. \ub530\ub77c\uc11c \ud558\ub098\uc758 \uc11c\ube44\uc2a4\ub97c \ud06c\uac8c \ud655\uc7a5\ud558\ub294 \uac83\ubcf4\ub2e4, \ucc38\uac00\uc790\uac00 \uc790\uae30 \uacc4\uc815\uc5d0\uc11c \uc5b4\ub290 \ub2e8\uacc4\uae4c\uc9c0 \uc131\uacf5\ud588\uace0 \uc5b4\ub514\uc11c \ub9c9\ud614\ub294\uc9c0 \ud655\uc778\ud560 \uc218 \uc788\uac8c \ub9cc\ub4dc\ub294 \uac83\uc774 \uc911\uc694\ud588\ub2e4.\\n\\n\uc138 \ubc88\uc9f8 \ubb38\uc81c\ub294 \uc0dd\uc131\ud615 AI \uae30\ub2a5\uc758 \ud488\uc9c8\uc744 \uc5b4\ub5bb\uac8c \ud655\uc778\ud560\uc9c0\uc600\ub2e4. \uc77c\ubc18 API\ucc98\ub7fc status code\ub9cc \ubcf4\uba74 \ucda9\ubd84\ud558\uc9c0 \uc54a\uc558\ub2e4. \ub9ac\ubdf0\uac00 \uc2e4\uc81c \ubcc0\uacbd \ub0b4\uc6a9\uacfc \uad00\ub828 \uc788\ub294\uc9c0, \ud55c\uae00 \uc124\uba85\uc774 \uc790\uc5f0\uc2a4\ub7ec\uc6b4\uc9c0, \ubd88\ud544\uc694\ud558\uac8c \uac19\uc740 \ub9d0\uc744 \ubc18\ubcf5\ud558\uc9c0 \uc54a\ub294\uc9c0, \ud070 PR\uc5d0\uc11c\ub3c4 \ud575\uc2ec \ubcc0\uacbd\uc744 \ub193\uce58\uc9c0 \uc54a\ub294\uc9c0\ub97c \ub530\ub85c \ud655\uc778\ud574\uc57c \ud588\ub2e4.\\n\\n## \uad6c\ud604 \uacfc\uc815\\n\\n### PR \uc774\ubca4\ud2b8\uc640 \uc0c1\ud0dc\ub97c \uba3c\uc800 \ubd84\ub9ac\ud588\ub2e4\\n\\nGitHub Webhook\uc5d0\uc11c \ubc1b\uc740 \uc774\ubca4\ud2b8\ub97c \ubc14\ub85c \ubaa8\ub378 \ud638\ucd9c\uae4c\uc9c0 \uc774\uc5b4 \ubd99\uc774\uba74 \uad6c\ud604\uc740 \ub2e8\uc21c\ud558\uc9c0\ub9cc, PR \uc774\ubca4\ud2b8 \uc218\uc2e0, diff \uc870\ud68c, Bedrock \ud638\ucd9c, GitHub \ucf54\uba58\ud2b8 \ubc18\uc601\uc774 \ud55c \ud568\uc218 \uc548\uc5d0 \uc11e\uc778\ub2e4. \uc6cc\ud06c\uc20d \uc2e4\uc2b5\uc5d0\uc11c\ub294 \uac01 \ucc38\uac00\uc790\uac00 \uc790\uae30 AWS \uacc4\uc815\uc5d0\uc11c \uac19\uc740 \ud750\ub984\uc744 \ub9cc\ub4e4\uae30 \ub54c\ubb38\uc5d0, \uba3c\uc800 \\"GitHub \uc774\ubca4\ud2b8\uac00 \uc81c\ub300\ub85c \ub4e4\uc5b4\uc654\ub294\uac00\\"\ub97c \ub208\uc73c\ub85c \ud655\uc778\ud560 \uc218 \uc788\ub294 \uc911\uac04 \uc0c1\ud0dc\uac00 \ud544\uc694\ud588\ub2e4. \uadf8\ub798\uc11c API Gateway\uc640 Lambda\ub294 PR \uc774\ubca4\ud2b8\ub97c \ubc1b\uc544 DynamoDB\uc5d0 \uc800\uc7a5\ud558\uace0, \ud6c4\uc18d \ucc98\ub9ac\ub294 DynamoDB Streams\uc5d0 \uc5f0\uacb0\ub41c Lambda\uac00 \uc774\uc5b4\ubc1b\ub3c4\ub85d \uad6c\uc131\ud588\ub2e4.\\n\\n\uc774 \uad6c\uc870 \ub355\ubd84\uc5d0 Webhook \uc218\uc2e0, diff \uc870\ud68c, Bedrock \ud638\ucd9c, GitHub \ucf54\uba58\ud2b8 \ubc18\uc601\uc744 \ub2e8\uacc4\ubcc4\ub85c \ubcfc \uc218 \uc788\uc5c8\ub2e4. \uc6cc\ud06c\uc20d \uc6b4\uc601 \uad00\uc810\uc5d0\uc11c\ub3c4 \\"GitHub \uc774\ubca4\ud2b8\uac00 \ub4e4\uc5b4\uc624\uc9c0 \uc54a\uc740 \ubb38\uc81c\\"\uc640 \\"\ubaa8\ub378 \ud638\ucd9c \uc774\ud6c4 \ucf54\uba58\ud2b8 \uc791\uc131\uc774 \uc2e4\ud328\ud55c \ubb38\uc81c\\"\ub97c \uad6c\ubd84\ud560 \uc218 \uc788\uc5c8\ub2e4.\\n\\nDynamoDB\uc5d0 \uc774\ubca4\ud2b8\ub97c \uc800\uc7a5\ud55c \uc774\uc720\ub294 \ub2e8\uc21c \ub85c\uadf8 \uc800\uc7a5\uc774 \uc544\ub2c8\uc5c8\ub2e4. Webhook payload\ub294 \ud55c \ubc88 \ub4e4\uc5b4\uc624\uba74 \ub2e4\uc2dc \ubc1b\uae30 \uc5b4\ub835\uace0, \ub4a4\ucabd Lambda\uac00 GitHub API\ub85c diff\ub97c \uc870\ud68c\ud558\uac70\ub098 \ub9ac\ubdf0 \uc785\ub825\uc744 \ub9cc\ub4e4\ub824\uba74 \uc800\uc7a5\uc18c \uc774\ub984, PR \ubc88\ud638, diff URL \uac19\uc740 \uae30\uc900 \uc815\ubcf4\uac00 \ud544\uc694\ud558\ub2e4. \uadf8\ub798\uc11c diff \uc6d0\ubb38\uc744 DynamoDB\uc5d0 \ub123\uc740 \uac83\uc774 \uc544\ub2c8\ub77c, PR\uc744 \ub2e4\uc2dc \ud655\uc778\ud560 \uc218 \uc788\ub294 \ucd5c\uc18c \uae30\uc900 \uc815\ubcf4\uc640 \uc774\ubca4\ud2b8 \uc218\uc2e0 \uc2dc\uac01\uc744 \uba3c\uc800 \ub0a8\uacbc\ub2e4. \uc774 \uc815\ubcf4\ub97c DynamoDB\uc5d0 \ub0a8\uaca8\ub450\uba74 Bedrock \ud638\ucd9c\uc774\ub098 GitHub \ucf54\uba58\ud2b8 \uc791\uc131\uc774 \uc2e4\ud328\ud588\uc744 \ub54c\ub3c4 \uc6d0\ub798 \uc5b4\ub5a4 PR\uc744 \ucc98\ub9ac\ud558\ub358 \uc911\uc774\uc5c8\ub294\uc9c0 \ub2e4\uc2dc \ud655\uc778\ud560 \uc218 \uc788\ub2e4.\\n\\nDynamoDB\uc5d0\ub294 \uc774\ubca4\ud2b8 ID, \uc774\ubca4\ud2b8 \uc885\ub958, \uc561\uc158, \uc800\uc7a5\uc18c \uc774\ub984, \uc774\ubca4\ud2b8 \ubc1c\uc2e0\uc790, \uc0dd\uc131 \uc2dc\uac01\uacfc \ub9c8\uc9c0\ub9c9 \uac31\uc2e0 \uc2dc\uac01\ucc98\ub7fc \uacf5\ud1b5\uc73c\ub85c \ud544\uc694\ud55c \uac12\uc744 \uba3c\uc800 \uc800\uc7a5\ud588\ub2e4. PR \uc774\ubca4\ud2b8\uc5d0\uc11c\ub294 \uc5ec\uae30\uc5d0 PR \ubc88\ud638, \uc81c\ubaa9, URL, PR \uc791\uc131\uc790, GitHub organization \uc774\ub984, diff URL\uc744, Issue \uc774\ubca4\ud2b8\uc5d0\uc11c\ub294 \uc774\uc288 \ubc88\ud638, \uc81c\ubaa9, URL, \uc774\uc288 \uc791\uc131\uc790\ub97c \uc800\uc7a5\ud588\ub2e4. \ub2e4\uc2dc \ub9d0\ud574 DynamoDB\ub294 diff \ubcf8\ubb38 \uc800\uc7a5\uc18c\uac00 \uc544\ub2c8\ub77c, \ud6c4\uc18d Lambda\uac00 \uc5b4\ub5a4 GitHub \uc774\ubca4\ud2b8\ub97c \ub2e4\uc2dc \uc870\ud68c\ud558\uace0 \ucc98\ub9ac\ud574\uc57c \ud558\ub294\uc9c0 \uc54c\ub824\uc8fc\ub294 \uc911\uac04 \uc0c1\ud0dc \uc800\uc7a5\uc18c\uc5d0 \uac00\uae4c\uc6e0\ub2e4.\\n\\n\ucd08\uae30 \uc124\uacc4\uc5d0\uc11c\ub294 GitHub Issue\ub098 PR \uc774\ubca4\ud2b8\uac00 \ubc1c\uc0dd\ud560 \ub54c\ub9c8\ub2e4 \ubc14\ub85c SNS SMS \uc54c\ub9bc\uc744 \ubcf4\ub0b4\ub294 \ud750\ub984\ub3c4 \uace0\ub824\ud588\ub2e4. \ud558\uc9c0\ub9cc \uc2e4\uc81c \ud14c\uc2a4\ud2b8 \uacfc\uc815\uc5d0\uc11c SNS SMS \ud560\ub2f9\ub7c9\uacfc \uacc4\uc815 \uc124\uc815 \ubb38\uc81c\uac00 \uc0dd\uae38 \uc218 \uc788\ub2e4\ub294 \uc810\uc744 \ud655\uc778\ud588\uace0, \uc54c\ub9bc, \uc774\ubca4\ud2b8 \uc800\uc7a5, \ub9ac\ubdf0 \uc0dd\uc131\uc744 \ud55c \ub369\uc5b4\ub9ac\ub85c \ubcf4\uc9c0 \uc54a\uace0 \ub2e8\uacc4\ubcc4\ub85c \ub098\ub220 \ud655\uc778\ud558\ub294 \ucabd\uc73c\ub85c \uc815\ub9ac\ud588\ub2e4. \ud2b9\ud788 \uc544\ud0a4\ud14d\ucc98\uc5d0\uc11c \uc67c\ucabd Lambda\ub294 Issue \uc0dd\uc131 \uc54c\ub9bc, DynamoDB Streams\uc5d0 \uc5f0\uacb0\ub41c Lambda\ub294 Pull Request \uc54c\ub9bc\uacfc \ub9ac\ubdf0 \uc791\uc131\uc744 \ub2f4\ub2f9\ud558\ub3c4\ub85d \uc5ed\ud560\uc744 \ub098\ub204\uc5c8\ub2e4. \uc774\ub807\uac8c \ub098\ub204\uba74 \uc2e4\uc2b5 \ucc38\uac00\uc790\ub3c4 DynamoDB \ud14c\uc774\ube14\uc744 \ubcf4\uba74\uc11c \\"\uc774\ubca4\ud2b8 \uc218\uc2e0\uc740 \ub410\uace0, \uadf8\ub2e4\uc74c \ucc98\ub9ac \ub2e8\uacc4\uc5d0\uc11c \ubb38\uc81c\uac00 \uc0dd\uacbc\ub2e4\\"\ucc98\ub7fc \uc7a5\uc560 \uc704\uce58\ub97c \ub098\ub220 \ubcfc \uc218 \uc788\uc5c8\ub2e4.\\n\\n### diff\ub97c \ub9ac\ubdf0 \uac00\ub2a5\ud55c \uc785\ub825\uc73c\ub85c \ubc14\uafe8\ub2e4\\n\\nBedrock\uc774 \ubcc0\uacbd \ub0b4\uc6a9\uc744 \uc81c\ub300\ub85c \ubcf4\uac8c \ud558\ub824\uba74 \uba3c\uc800 GitHub API\ub85c \ubcc0\uacbd \ud30c\uc77c \ubaa9\ub85d\uacfc patch\ub97c \uac00\uc838\uc640\uc57c \ud588\ub2e4. \uc5ec\ub7ec \ud30c\uc77c\uc774 \ubc14\ub010 PR\uc5d0\uc11c\ub294 \ud30c\uc77c \uacbd\ub85c, \ubcc0\uacbd\ub41c \ucf54\ub4dc, \uc8fc\ubcc0 \ucf54\ub4dc \ucee8\ud14d\uc2a4\ud2b8\ub97c \ud568\uaed8 \uc815\ub9ac\ud558\uace0, \ubaa8\ub378\uc5d0 \uc804\ub2ec\ud558\uae30 \uc804\uc5d0 \ub9ac\ubdf0 \ub2e8\uc704\ub85c \ubb36\uc5c8\ub2e4.\\n\\n\ud070 diff\ub294 \uadf8\ub300\ub85c \ub123\uae30\ubcf4\ub2e4 \ud575\uc2ec \ubcc0\uacbd, \ud30c\uc77c \uacbd\ub85c, \ud655\uc778\ud574\uc57c \ud560 \uc870\uac74\uc744 \uc911\uc2ec\uc73c\ub85c \uc904\uc600\ub2e4. \uc774\ub54c \ud504\ub86c\ud504\ud2b8\uc5d0\ub294 \\"\ubb34\uc5c7\uc744 \ub9ac\ubdf0\ud574\uc57c \ud558\ub294\uc9c0\\", \\"\uadfc\uac70 \uc5c6\ub294 \uc9c0\uc801\uc744 \ud53c\ud574\uc57c \ud55c\ub2e4\\", \\"\ubb38\uc81c\uac00 \uba85\ud655\ud558\uc9c0 \uc54a\uc73c\uba74 \uc5b5\uc9c0\ub85c \ucf54\uba58\ud2b8\ub97c \ub9cc\ub4e4\uc9c0 \uc54a\ub294\ub2e4\\" \uac19\uc740 \uae30\uc900\uc744 \ub123\uc5c8\ub2e4. \ub2e8\uc21c\ud788 \ub9ac\ubdf0 \ubb38\uc7a5\uc744 \uc0dd\uc131\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, \ubaa8\ub378\uc774 \ub9ac\ubdf0\ud560 \ucc45\uc784 \ubc94\uc704\ub97c \uc81c\ud55c\ud558\ub294 \uc791\uc5c5\uc774\uc5c8\ub2e4.\\n\\n### S3\uc640 Knowledge Bases\ub85c \ub9ac\ubdf0 \uae30\uc900\uc744 \uac80\uc0c9\ud588\ub2e4\\n\\n\ucc98\uc74c\uc5d0\ub294 PR diff\ub97c \uac70\uc758 \uadf8\ub300\ub85c Claude 3.5 Sonnet v2 \ud504\ub86c\ud504\ud2b8\uc5d0 \ub123\uace0 \ub9ac\ubdf0\ub97c \uc0dd\uc131\ud588\ub2e4. \ube60\ub974\uac8c \ub3d9\uc791\uc744 \ud655\uc778\ud558\uae30\uc5d0\ub294 \ucda9\ubd84\ud588\uc9c0\ub9cc, MLE \uad00\uc810\uc5d0\uc11c \ubcf4\uba74 \uc785\ub825 \uc124\uacc4\uac00 \ub108\ubb34 \uc57d\ud588\ub2e4. \ubaa8\ub378\uc774 \uc5b4\ub5a4 \uae30\uc900\uc73c\ub85c \ub9ac\ubdf0\ud574\uc57c \ud558\ub294\uc9c0 \uba85\ud655\ud558\uc9c0 \uc54a\uc73c\uba74, \uac19\uc740 diff\ub97c \ubcf4\uace0\ub3c4 \ub9e4\ubc88 \ub2e4\ub978 \uc218\uc900\uc758 \uc77c\ubc18\uc801\uc778 \uc870\uc5b8\uc744 \ub9cc\ub4e4 \uc218 \uc788\ub2e4.\\n\\n\uadf8\ub798\uc11c \ucf54\ub4dc \ub9ac\ubdf0 \uae30\uc900, \uc2e4\uc2b5 \uac00\uc774\ub4dc, \ucd9c\ub825 \ud615\uc2dd \uaddc\uce59, \uc608\uc2dc \ucf54\uba58\ud2b8\ucc98\ub7fc \ubaa8\ub378\uc774 \ucc38\uace0\ud574\uc57c \ud560 \uae30\uc900\uc744 S3\uc5d0 \uc815\ub9ac\ud558\uace0, Amazon Bedrock Knowledge Bases\uc758 \ub370\uc774\ud130 \uc18c\uc2a4\ub85c \uc5f0\uacb0\ud588\ub2e4. Knowledge Bases\ub294 \uc774 \ub370\uc774\ud130\ub97c \uc784\ubca0\ub529\ud574 Amazon OpenSearch Serverless vector store\uc5d0 \uc800\uc7a5\ud558\uace0, \ub9ac\ubdf0 Lambda\ub294 PR diff\ub97c \ub9cc\ub4e0 \ub4a4 \ud604\uc7ac \ubcc0\uacbd\uacfc \uad00\ub828 \uc788\ub294 \ub9ac\ubdf0 \uae30\uc900\uc744 \uac80\uc0c9\ud588\ub2e4.\\n\\n\uc774 \uad6c\uc870\uc5d0\uc11c S3\ub294 \ub9ac\ubdf0 \uae30\uc900\uc758 \uc6d0\ubcf8 \uc800\uc7a5\uc18c, Bedrock Knowledge Bases\ub294 \ub370\uc774\ud130 \ub3d9\uae30\ud654\uc640 \uac80\uc0c9 API, OpenSearch Serverless\ub294 vector index \uc5ed\ud560\uc744 \ub9e1\uc558\ub2e4. OpenSearch\ub97c \uc9c1\uc811 \\"\uc815\ub2f5 \uac80\uc0c9 \uc5d4\uc9c4\\"\ucc98\ub7fc \uc4f4 \uac83\uc774 \uc544\ub2c8\ub77c, Knowledge Bases \ub4a4\uc5d0\uc11c \uac80\uc0c9 \uac00\ub2a5\ud55c \ucee8\ud14d\uc2a4\ud2b8 \uc800\uc7a5\uc18c\ub85c \ub454 \uac83\uc774\ub2e4. PR diff\ub9cc \ub123\uc73c\uba74 \ubaa8\ub378\uc774 \uc77c\ubc18\uc801\uc778 \ucf54\ub4dc \ub9ac\ubdf0 \ubb38\uc7a5\uc744 \ub9cc\ub4e4\uae30 \uc27d\uc9c0\ub9cc, \uac80\uc0c9\ub41c \ub9ac\ubdf0 \uae30\uc900 \ucee8\ud14d\uc2a4\ud2b8\ub97c \ud568\uaed8 \ub123\uc73c\uba74 \ubaa8\ub378\uc774 \uac19\uc740 \ubcc0\uacbd\uc744 \ub354 \uc77c\uad00\ub41c \uae30\uc900\uc73c\ub85c \ubcf4\uac8c \ub41c\ub2e4.\\n\\n\uac80\uc0c9 \ub2e8\uc704\ub294 \uae34 \ubb38\uc11c \uc804\uccb4\uac00 \uc544\ub2c8\ub77c \ub9ac\ubdf0 \uae30\uc900\uc73c\ub85c \uc4f8 \uc218 \uc788\ub294 \uc791\uc740 \ucee8\ud14d\uc2a4\ud2b8 \uc870\uac01\uc73c\ub85c \ub450\ub294 \uac83\uc774 \uc801\ud569\ud588\ub2e4. \uc608\ub97c \ub4e4\uc5b4 \\"\ubcf4\uc548\uc0c1 \uc704\ud5d8\ud55c \ud558\ub4dc\ucf54\ub529\\", \\"\uc608\uc678 \ucc98\ub9ac \ub204\ub77d\\", \\"\ubd88\ud544\uc694\ud558\uac8c \ub113\uc740 \ucc45\uc784 \ubc94\uc704\\", \\"\uc6cc\ud06c\uc20d\uc5d0\uc11c \uc124\uba85\ud574\uc57c \ud558\ub294 \ucd9c\ub825 \ud615\uc2dd\\"\ucc98\ub7fc \ub9ac\ubdf0 \ud310\ub2e8\uc5d0 \uc9c1\uc811 \uc601\ud5a5\uc744 \uc8fc\ub294 \uae30\uc900\uc744 \ucc3e\uc544 Bedrock \ud504\ub86c\ud504\ud2b8\uc5d0 \ub123\uc5c8\ub2e4. \uc774\ub807\uac8c \ud558\uba74 \ubaa8\ub378\uc774 diff\ub97c \uc77d\uace0\ub3c4 \uadfc\uac70 \uc5c6\ub294 \uc77c\ubc18\ub860\uc744 \uc4f0\ub294 \ubb38\uc81c\ub97c \uc904\uc774\uace0, \ub9ac\ubdf0 \ucf54\uba58\ud2b8\uac00 \uc5b4\ub5a4 \uae30\uc900\uc5d0\uc11c \ub098\uc628 \uac83\uc778\uc9c0 \uc124\uba85\ud558\uae30 \uc26c\uc6cc\uc9c4\ub2e4.\\n\\nMLE \uad00\uc810\uc5d0\uc11c \ubcf4\uba74 \uc774 \uc791\uc5c5\uc740 \ubaa8\ub378 \ud559\uc2b5\ubcf4\ub2e4 \uac80\uc0c9\uacfc \ud504\ub86c\ud504\ud2b8 \uc785\ub825 \uc124\uacc4\uc5d0 \uac00\uae4c\uc6e0\ub2e4. \ubaa8\ub378 \uc790\uccb4\ub97c fine-tuning\ud558\uc9c0 \uc54a\uc558\uae30 \ub54c\ubb38\uc5d0, \ud488\uc9c8\uc744 \uc88c\uc6b0\ud558\ub294 \ud575\uc2ec\uc740 \\"\uc5b4\ub5a4 diff\ub97c \uc5b4\ub5a4 \ud615\ud0dc\ub85c \uc904 \uac83\uc778\uac00\\"\uc640 \\"\uc5b4\ub5a4 \ub9ac\ubdf0 \uae30\uc900\uc744 \ud568\uaed8 \uc904 \uac83\uc778\uac00\\"\uc600\ub2e4. \uadf8\ub798\uc11c Knowledge Bases\ub97c \uc5f0\uacb0\ud55c \ub4a4\uc5d0\ub294 \uc0dd\uc131 \uacb0\uacfc\ub9cc \ubcf4\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, \uac80\uc0c9\ub41c \ucee8\ud14d\uc2a4\ud2b8\uac00 \uc2e4\uc81c PR \ubcc0\uacbd\uacfc \uad00\ub828 \uc788\ub294\uc9c0\ub3c4 \uac19\uc774 \ud655\uc778\ud588\ub2e4.\\n\\n### \uc2e4\ud328 \uc54c\ub9bc\uacfc \uc7ac\ucc98\ub9ac \ud750\ub984\uc744 \uace0\ub824\ud588\ub2e4\\n\\n\uc6cc\ud06c\uc20d\uc5d0\uc11c\ub294 \ucc38\uac00\uc790\uac00 \uc2e4\uc2b5 \uc911 \ub9c9\ud788\uba74 \ubc14\ub85c \ub300\uc751\ud574\uc57c \ud55c\ub2e4. \uadf8\ub798\uc11c Lambda \ub85c\uadf8\ub9cc \ubcf4\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, \uc2e4\ud328 \uc9c0\uc810\uc744 \uc6b4\uc601\uc790\uac00 \ud655\uc778\ud560 \uc218 \uc788\ub3c4\ub85d SNS \uc54c\ub9bc\uacfc \uc0c1\ud0dc \uc800\uc7a5\uc744 \ud568\uaed8 \uace0\ub824\ud588\ub2e4. \uc608\ub97c \ub4e4\uc5b4 Issue \uc0dd\uc131 \uc54c\ub9bc, GitHub API \ud638\ucd9c \uc2e4\ud328, Bedrock \ud638\ucd9c \uc2e4\ud328, \ucf54\uba58\ud2b8 \ubc18\uc601 \uc2e4\ud328\ucc98\ub7fc \ub2e8\uacc4\ubcc4\ub85c \uc2e4\ud328 \uac00\ub2a5\uc131\uc774 \ub2e4\ub978 \uc9c0\uc810\uc744 \ub098\ub220 \ubd24\ub2e4.\\n\\n\uc7ac\ucc98\ub9ac\ub294 \uac19\uc740 PR\uc744 \ub2e4\uc2dc \uc870\ud68c\ud574 \uc774\uc5b4 \ucc98\ub9ac\ud560 \uc218 \uc788\uc5b4\uc57c \ud55c\ub2e4\ub294 \uae30\uc900\uc73c\ub85c \uc124\uacc4\ud588\ub2e4. PR \ubc88\ud638, \uc800\uc7a5\uc18c \uc774\ub984, diff URL\uc744 \ub0a8\uaca8\ub450\uba74 \ud6c4\uc18d \ub2e8\uacc4\uc5d0\uc11c \uac19\uc740 PR\uc744 \ub2e4\uc2dc \uc870\ud68c\ud560 \uc218 \uc788\ub2e4. \uc2e4\uc81c \uc6b4\uc601 \uc218\uc900\uc758 \uc7ac\uc2dc\ub3c4 \uad6c\uc870\uae4c\uc9c0 \uc644\uc131\ud55c \uac83\uc740 \uc544\ub2c8\uc9c0\ub9cc, \uc6cc\ud06c\uc20d \ud658\uacbd\uc5d0\uc11c \uc2e4\ud328\ub97c \ud655\uc778\ud558\uace0 \ub2e4\uc2dc \uc2e4\ud589\ud560 \uc218 \uc788\ub294 \uad6c\uc870\ub97c \uac16\ucd94\ub294 \uac83\uc774 \uc911\uc694\ud588\ub2e4. \uc774 \ud750\ub984\uc744 \ub354 \uc548\uc815\uc801\uc73c\ub85c \ub9cc\ub4e4\ub824\uba74 \uc774\ubca4\ud2b8 ID, commit SHA, \ucc98\ub9ac \ub2e8\uacc4, \uc2e4\ud328 \uc6d0\uc778\uae4c\uc9c0 \ud568\uaed8 \ub0a8\uaca8 \uc5b4\ub290 \ub2e8\uacc4\ubd80\ud130 \ub2e4\uc2dc \uc2e4\ud589\ud574\uc57c \ud558\ub294\uc9c0 \ud310\ub2e8\ud560 \uc218 \uc788\uc5b4\uc57c \ud55c\ub2e4.\\n\\n## \uac80\uc99d\\n\\n\uc774 \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c \uac00\uc7a5 \ub9ce\uc774 \ud55c \uc77c\uc740 \ud14c\uc2a4\ud2b8 PR\uc744 \ub9cc\ub4dc\ub294 \uc77c\uc774\uc5c8\ub2e4. \ub2e8\uc77c \ud30c\uc77c \ubcc0\uacbd, \uc5ec\ub7ec \ud30c\uc77c \ubcc0\uacbd, \ud070 diff, \ub9ac\ubdf0\ud560 \ub0b4\uc6a9\uc774 \uac70\uc758 \uc5c6\ub294 \ubcc0\uacbd, \uba85\ud655\ud55c \ubc84\uadf8\uac00 \uc788\ub294 \ubcc0\uacbd\ucc98\ub7fc \ub2e4\uc591\ud55c \uc0c1\ud669\uc744 \ub9cc\ub4e4\uace0 Bedrock\uc758 \uc751\ub2f5\uc744 \ud655\uc778\ud588\ub2e4. \ud14c\uc2a4\ud2b8 PR\uc740 100\uac1c \uc774\uc0c1 \ub9cc\ub4e4\uc5c8\uace0, \uadf8 \uacfc\uc815\uc5d0\uc11c \ucf54\uba58\ud2b8 \ud488\uc9c8\uacfc \ud504\ub86c\ud504\ud2b8 \uc870\uac74\uc744 \ubc18\ubcf5\ud574\uc11c \uc870\uc815\ud588\ub2e4.\\n\\n\uac80\uc99d\uc740 \uc815\ub2f5 \ub77c\ubca8\uc774 \uc788\ub294 ML \ubca4\uce58\ub9c8\ud06c\ucc98\ub7fc \uc9c4\ud589\ud558\uae30 \uc5b4\ub835\ub2e4. PR \ub9ac\ubdf0\ub294 \\"\uc815\ub2f5 \ubb38\uc7a5 \ud558\ub098\\"\uac00 \uc788\ub294 \ubb38\uc81c\uac00 \uc544\ub2c8\uae30 \ub54c\ubb38\uc774\ub2e4. \uadf8\ub798\uc11c \uc791\uc740 \ud3c9\uac00 \uc138\ud2b8\ub97c \uc9c1\uc811 \ub9cc\ub4e4\uace0, \uac01 PR\uc5d0 \ub300\ud574 \uac80\uc0c9 \ub2e8\uacc4\uc640 \uc0dd\uc131 \ub2e8\uacc4\ub97c \ub098\ub220 \ud655\uc778\ud588\ub2e4.\\n\\n| \uad00\uc810 | \ud655\uc778\ud55c \ub0b4\uc6a9 |\\n|---|---|\\n| \uac80\uc0c9 \uad00\ub828\uc131 | Knowledge Bases\uac00 PR \ubcc0\uacbd\uacfc \uad00\ub828 \uc788\ub294 \ub9ac\ubdf0 \uae30\uc900\uc744 \uac00\uc838\uc624\ub294\uc9c0 \ud655\uc778\ud588\ub2e4. |\\n| Diff \ucee4\ubc84\ub9ac\uc9c0 | \uc5ec\ub7ec \ud30c\uc77c \ubcc0\uacbd\uc5d0\uc11c \ud2b9\uc815 \ud30c\uc77c\ub9cc \ubcf4\uace0 \ub05d\ub098\uc9c0 \uc54a\ub294\uc9c0 \ud655\uc778\ud588\ub2e4. |\\n| \uadfc\uac70\uc131 | \uac80\uc0c9 \ucee8\ud14d\uc2a4\ud2b8\ub098 diff\uc5d0 \uc5c6\ub294 \ub0b4\uc6a9\uc744 \uadfc\uac70\ucc98\ub7fc \ub9d0\ud558\uc9c0 \uc54a\ub294\uc9c0 \ud655\uc778\ud588\ub2e4. |\\n| \uc2e4\ud589 \uac00\ub2a5\uc131 | \\"\uac1c\uc120\uc774 \ud544\uc694\ud569\ub2c8\ub2e4\\"\uac00 \uc544\ub2c8\ub77c \uc5b4\ub5a4 \ud30c\uc77c\uacfc \ubcc0\uacbd\uc5d0\uc11c \ubb34\uc5c7\uc744 \uace0\uccd0\uc57c \ud558\ub294\uc9c0 \ub4dc\ub7ec\ub098\ub294\uc9c0 \ud655\uc778\ud588\ub2e4. |\\n| \uc624\ud0d0 | \ub9ac\ubdf0\ud560 \ub0b4\uc6a9\uc774 \uac70\uc758 \uc5c6\ub294 PR\uc5d0\uc11c \uc5b5\uc9c0 \ucf54\uba58\ud2b8\ub97c \ub9cc\ub4e4\uc9c0 \uc54a\ub294\uc9c0 \ud655\uc778\ud588\ub2e4. |\\n| \ud55c\uad6d\uc5b4 \uac00\ub3c5\uc131 | \uc6cc\ud06c\uc20d \ucc38\uac00\uc790\uac00 \uc774\ud574\ud560 \uc218 \uc788\ub294 \uc790\uc5f0\uc2a4\ub7ec\uc6b4 \ud55c\uae00 \ub9ac\ubdf0\uc778\uc9c0 \ud655\uc778\ud588\ub2e4. |\\n| \uc804\uccb4 \ud750\ub984 | GitHub \uc774\ubca4\ud2b8 \uc218\uc2e0\ubd80\ud130 PR \ucf54\uba58\ud2b8 \ubc18\uc601\uae4c\uc9c0 \ud750\ub984\uc774 \ub04a\uae30\uc9c0 \uc54a\ub294\uc9c0 \ud655\uc778\ud588\ub2e4. |\\n| \uc2e4\ud328 \uc9c4\ub2e8 | \uc2e4\ud328\ud588\uc744 \ub54c DynamoDB \uc0c1\ud0dc, Lambda \ub85c\uadf8, SNS \uc54c\ub9bc\uc73c\ub85c \uc6d0\uc778\uc744 \uc881\ud790 \uc218 \uc788\ub294\uc9c0 \ud655\uc778\ud588\ub2e4. |\\n\\n\uc774 \uae30\uc900\uc73c\ub85c \ud504\ub86c\ud504\ud2b8\ub97c \uc5ec\ub7ec \ubc88 \ubc14\uafe8\ub2e4. \ud2b9\ud788 \uc5ec\ub7ec \ud30c\uc77c\uc774 \ubc14\ub010 PR\uc5d0\uc11c\ub294 \ubaa8\ub378\uc774 \uccab \ubc88\uc9f8 \ud30c\uc77c\ub9cc \ubcf4\uace0 \ub9ac\ubdf0\ub97c \ub05d\ub0b4\ub294 \uacbd\uc6b0\uac00 \uc788\uc5c8\uae30 \ub54c\ubb38\uc5d0, \ubcc0\uacbd \ud30c\uc77c \ubaa9\ub85d\uacfc \uac01 patch\ub97c \ubd84\ub9ac\ud574\uc11c \ubcf4\uc5ec\uc8fc\uace0 \\"\ud30c\uc77c\ubcc4\ub85c \ud655\uc778\ud558\ub418 \uc911\ubcf5 \ucf54\uba58\ud2b8\ub294 \uc904\uc774\ub77c\\"\ub294 \uc2dd\uc73c\ub85c \uc870\uac74\uc744 \uc870\uc815\ud588\ub2e4. \ub610\ud55c \ub9ac\ubdf0\uac00 \ub108\ubb34 \uc77c\ubc18\uc801\uc774\uba74 \uac80\uc0c9 \ucee8\ud14d\uc2a4\ud2b8\ub97c \ub298\ub9ac\uace0, \ubc18\ub300\ub85c \ub9ac\ubdf0\uac00 \uc7a5\ud669\ud574\uc9c0\uba74 \ucd9c\ub825 \ud615\uc2dd\uacfc \ucf54\uba58\ud2b8 \uac1c\uc218\ub97c \uc81c\ud55c\ud588\ub2e4.\\n\\nKnowledge Bases\ub97c \uc5f0\uacb0\ud55c \ub4a4\uc5d0\ub294 \uac80\uc0c9 \uacb0\uacfc \uc790\uccb4\ub3c4 \ud655\uc778\ud588\ub2e4. \uad00\ub828 \uc5c6\ub294 \uae30\uc900 \ubb38\uc11c\uac00 \ud504\ub86c\ud504\ud2b8\uc5d0 \ub4e4\uc5b4\uac00\uba74 \ubaa8\ub378 \ucd9c\ub825\uc774 \uc624\ud788\ub824 \ud754\ub4e4\ub9b4 \uc218 \uc788\uae30 \ub54c\ubb38\uc774\ub2e4. \uadf8\ub798\uc11c \ud14c\uc2a4\ud2b8 PR\ubcc4\ub85c \\"\uc774 \ubcc0\uacbd\uc5d0 \ud544\uc694\ud55c \uae30\uc900\uc774 \uac80\uc0c9\ub410\ub294\uac00\\", \\"\uac80\uc0c9 \ucee8\ud14d\uc2a4\ud2b8\uac00 \uc5c6\uc5b4\ub3c4 \uae30\ubcf8 \ub9ac\ubdf0 \uae30\uc900\uc740 \uc720\uc9c0\ub418\ub294\uac00\\", \\"\uac80\uc0c9 \ucee8\ud14d\uc2a4\ud2b8 \ub54c\ubb38\uc5d0 \uc5c9\ub6b1\ud55c \ucf54\uba58\ud2b8\uac00 \ub298\uc9c0 \uc54a\ub294\uac00\\"\ub97c \uac19\uc774 \ubd24\ub2e4. \uc774 \uacfc\uc815\uc740 \ubaa8\ub378 \uc131\ub2a5 \uac1c\uc120\uc774\ub77c\uae30\ubcf4\ub2e4, LLM \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc5d0\uc11c \uac80\uc0c9 \ud488\uc9c8\uacfc \uc0dd\uc131 \ud488\uc9c8\uc744 \ub530\ub85c \uc810\uac80\ud55c \uc791\uc5c5\uc5d0 \uac00\uae4c\uc6e0\ub2e4.\\n\\n\uc6cc\ud06c\uc20d \uc804\uc5d0\ub294 \uc2e4\uc2b5 \ubb38\uc11c\ub3c4 \ud568\uaed8 \uc815\ub9ac\ud588\ub2e4. \uae30\uc874 \uc790\ub8cc\ub294 \uc774\ubbf8\uc9c0 \uc911\uc2ec\uc774\ub77c AWS \ucf58\uc194\uc5d0 \uc775\uc219\ud558\uc9c0 \uc54a\uc740 \ucc38\uac00\uc790\uac00 \uc911\uac04\uc5d0 \uae38\uc744 \uc783\uae30 \uc26c\uc6e0\ub2e4. \uadf8\ub798\uc11c \uc6f9 \ubb38\uc11c \ud615\ud0dc\ub85c \uc808\ucc28\ub97c \uc62e\uae30\uace0, \uc0dd\ub7b5\ub41c \uc124\uc815\uacfc \ud655\uc778 \uc9c0\uc810\uc744 \ub2e8\uacc4\ubcc4\ub85c \ubcf4\uc644\ud588\ub2e4. \uc774 \ubb38\uc11c\ub294 \uc2e4\uc2b5 \uc911 \ucc38\uac00\uc790\uac00 \ub193\uce5c \ubd80\ubd84\uc744 \ub2e4\uc2dc \ub530\ub77c\uac00\ub294 \uae30\uc900\uc774 \ub410\ub2e4.\\n\\n## \uc6b4\uc601 \uc911 \ubb38\uc81c \ud574\uacb0\\n\\n\uc2e4\uc81c \uc6cc\ud06c\uc20d \uc911\uc5d0\ub294 SNS SMS \uc804\uc1a1\uc774 \ub418\uc9c0 \uc54a\ub294 \ubb38\uc81c\uac00 \ubc1c\uc0dd\ud588\ub2e4. \ud300\uc6d0\ubcc4 \uc5ed\ud560 \ubd84\ub2f4\uc5d0 \ub530\ub77c \ub9e1\uc740 \uc11c\ube44\uc2a4\uc640 \ud655\uc778 \ubc94\uc704\ub97c \ub098\ub204\uc5b4 \ub450\uc5c8\uae30 \ub54c\ubb38\uc5d0, \ubb38\uc81c\ub97c \ud55c \ubc88\uc5d0 \ucd94\uce21\ud558\uc9c0 \uc54a\uace0 \ub2e8\uacc4\ubcc4\ub85c \uc881\ud600 \uac14\ub2e4. \ucc98\uc74c\uc5d0\ub294 Lambda \ucf54\ub4dc\ub098 \uc804\ud654\ubc88\ud638 \ud615\uc2dd \ubb38\uc81c\ub77c\uace0 \ubcfc \uc218\ub3c4 \uc788\uc5c8\uc9c0\ub9cc, CloudWatch \ub85c\uadf8\uc5d0\uc11c Lambda \uc790\uccb4 \uc5d0\ub7ec\uac00 \ubcf4\uc774\uc9c0 \uc54a\uc558\uace0, \uc11c\ube44\uc2a4 \ub9ac\uc804\ub3c4 \ubaa9\ud45c \ub9ac\uc804\uc778 us-west-2\ub85c \ub9de\ucdb0\uc838 \uc788\uc5c8\ub2e4. \uadf8\ub798\uc11c \ubb38\uc81c\ub97c SNS \ucabd\uc73c\ub85c \uc881\ud600 \ud655\uc778\ud588\ub2e4.\\n\\n\uc6d0\uc778\uc740 \uc6cc\ud06c\uc20d \uacc4\uc815\uc758 SNS Text Messaging \uc124\uc815\uc774\uc5c8\ub2e4. SMS Account spend limit\uc774 0\uc73c\ub85c \uc124\uc815\ub418\uc5b4 \uc788\uc5b4 \ucf54\ub4dc\uac00 \uc815\uc0c1\uc774\uc5b4\ub3c4 \ubb38\uc790 \uc804\uc1a1\uc774 \ub9c9\ud788\ub294 \uc0c1\ud0dc\uc600\ub2e4. \uc774 \uac12\uc744 \uc870\uc815\ud55c \ub4a4 SMS \uc804\uc1a1\uc774 \uc815\uc0c1 \ub3d9\uc791\ud588\uace0, \uac19\uc740 \ubb38\uc81c\uac00 \ub2e4\ub978 \ucc38\uac00\uc790\uc5d0\uac8c\ub3c4 \ubc18\ubcf5\ub420 \uc218 \uc788\ub2e4\uace0 \ud310\ub2e8\ud574 \ubc1c\ud45c\uc790\uc640 \uc2e4\uc2b5 \uc9c0\uc6d0\uc790\uc5d0\uac8c \uc989\uc2dc \uacf5\uc720\ud588\ub2e4.\\n\\n\uc774 \uacbd\ud5d8\uc740 \uc6cc\ud06c\uc20d \uc6b4\uc601\uc5d0\uc11c \uc911\uc694\ud55c \uc9c0\uc810\uc744 \ubcf4\uc5ec\uc92c\ub2e4. \uc11c\ubc84\ub9ac\uc2a4 \uc2dc\uc2a4\ud15c\uc5d0\uc11c\ub294 \ucf54\ub4dc\uac00 \ub9de\uc544\ub3c4 \uacc4\uc815 \uc124\uc815, \ub9ac\uc804, \uc11c\ube44\uc2a4 \ud560\ub2f9\ub7c9, \uc9c0\ucd9c \ud55c\ub3c4 \uac19\uc740 \uc6b4\uc601 \uc870\uac74 \ub54c\ubb38\uc5d0 \uc2e4\ud328\ud560 \uc218 \uc788\ub2e4. \uadf8\ub798\uc11c \ub2e8\uc21c\ud788 Lambda \ucf54\ub4dc\ub9cc \uac80\uc99d\ud558\ub294 \uac83\uc774 \uc544\ub2c8\ub77c, GitHub \uc774\ubca4\ud2b8, Lambda, DynamoDB, SNS\ucc98\ub7fc \ud300\uc6d0\ubcc4 \uc5ed\ud560\uc5d0 \ub9de\ucdb0 \ud655\uc778 \uc9c0\uc810\uc744 \ub098\ub204\uace0, \uc2e4\uc81c \ucc38\uac00\uc790 \uacc4\uc815\uacfc \uac19\uc740 \uc870\uac74\uc5d0\uc11c \uc804\uccb4 \ud750\ub984\uc744 \uc2e4\ud589\ud574\ubd10\uc57c \ud588\ub2e4.\\n\\n## \uc774 \ud504\ub85c\uc81d\ud2b8\ub97c \uc5b4\ub5bb\uac8c \uac1c\uc120\ud560 \uc218 \uc788\uc744\uae4c\\n\\n\uc774 \ud504\ub85c\uc81d\ud2b8\ub294 \uc6cc\ud06c\uc20d \uc2e4\uc2b5\uc744 \ubaa9\ud45c\ub85c \ud588\uae30 \ub54c\ubb38\uc5d0, \ucc38\uac00\uc790\uac00 \uc790\uae30 AWS \uacc4\uc815\uc5d0\uc11c GitHub \uc774\ubca4\ud2b8 \uc218\uc2e0 \uc5ec\ubd80\uc640 \ud6c4\uc18d \ucc98\ub9ac \ub2e8\uacc4\ub97c \ub208\uc73c\ub85c \ud655\uc778\ud560 \uc218 \uc788\ub294 \uad6c\uc870\ub97c \uc6b0\uc120\ud588\ub2e4. \uadf8\ub798\uc11c DynamoDB\ub97c \uc911\uac04 \uc0c1\ud0dc \ud655\uc778 \uc9c0\uc810\uc73c\ub85c \ub450\uace0, DynamoDB Streams\ub85c \ub2e4\uc74c Lambda\ub97c \uc5f0\uacb0\ud558\ub294 \ubc29\uc2dd\uc774 \uc2e4\uc2b5 \ubaa9\uc801\uc5d0 \uc798 \ub9de\uc558\ub2e4.\\n\\n\uac1c\uc120 \ubc29\ud5a5\uc740 DynamoDB\uc758 \ucc45\uc784\uc744 \ub354 \ubd84\uba85\ud558\uac8c \ub098\ub204\ub294 \uac83\uc774\ub2e4. DynamoDB\ub294 PR \ub9ac\ubdf0 \uc791\uc5c5\uc758 \uc0c1\ud0dc \uc800\uc7a5\uc18c\ub85c \ub450\uace0, \ube44\ub3d9\uae30 \ucc98\ub9ac\uc640 \uc7ac\uc2dc\ub3c4\ub294 SQS, EventBridge, Step Functions \uac19\uc740 \uc11c\ube44\uc2a4\ub85c \ubd84\ub9ac\ud558\ub294 \ud3b8\uc774 \ub354 \uc6b4\uc601\ud558\uae30 \uc27d\ub2e4. Webhook \uc218\uc2e0 Lambda\ub294 GitHub \uc11c\uba85\uc744 \uac80\uc99d\ud558\uace0, \uc800\uc7a5\uc18c \uc774\ub984, PR \ubc88\ud638, commit SHA, \uc774\ubca4\ud2b8 ID, diff URL \uac19\uc740 \uae30\uc900 \uc815\ubcf4\ub97c \uc800\uc7a5\ud55c \ub4a4 SQS\ub098 EventBridge\ub85c \ud6c4\uc18d \uc791\uc5c5\uc744 \ub118\uae34\ub2e4. \uc774\ud6c4 \uc791\uc5c5 Lambda\ub098 Step Functions\uac00 GitHub API\ub85c \ubcc0\uacbd \ud30c\uc77c \ubaa9\ub85d\uacfc patch\ub97c \uc870\ud68c\ud558\uace0, Knowledge Bases \ucee8\ud14d\uc2a4\ud2b8 \uac80\uc0c9, Bedrock \ud638\ucd9c, GitHub \ucf54\uba58\ud2b8 \uc791\uc131 \ub2e8\uacc4\ub97c \uc21c\uc11c\ub300\ub85c \ucc98\ub9ac\ud55c\ub2e4.\\n\\n\ub610\ud55c diff URL\uc740 GitHub\uc5d0\uc11c \ud604\uc7ac PR diff\ub97c \ub2e4\uc2dc \uac00\uc838\uc624\uae30 \uc704\ud55c \ucc38\uc870 \uc815\ubcf4\uc77c \ubfd0, \ub9ac\ubdf0 \ub2f9\uc2dc \uc785\ub825\uc744 \uadf8\ub300\ub85c \ubcf4\uc874\ud558\uc9c0\ub294 \uc54a\ub294\ub2e4. PR\uc5d0 \ucd94\uac00 \ucee4\ubc0b\uc774 \ub4e4\uc5b4\uc624\uac70\ub098 force push\uac00 \ubc1c\uc0dd\ud558\uba74 \ub098\uc911\uc5d0 \uac19\uc740 URL\uc744 \uc870\ud68c\ud588\uc744 \ub54c \ub9ac\ubdf0 \ub2f9\uc2dc\uc640 \ub2e4\ub978 diff\ub97c \ubc1b\uc744 \uc218 \uc788\ub2e4. \uadf8\ub798\uc11c \ub9ac\ubdf0\uc5d0 \uc2e4\uc81c \uc0ac\uc6a9\ud55c diff \uc2a4\ub0c5\uc0f7, \uc815\ub9ac\ub41c \ud504\ub86c\ud504\ud2b8 \uc785\ub825, Knowledge Bases \uac80\uc0c9 \uacb0\uacfc, \uc0dd\uc131\ub41c \ub9ac\ubdf0 \ucd08\uc548 \uac19\uc740 \uc911\uac04 \uc0b0\ucd9c\ubb3c\uc740 S3\uc5d0 \uc800\uc7a5\ud558\uace0, DynamoDB\uc5d0\ub294 S3 key, \ucc98\ub9ac \ub2e8\uacc4, \uc7ac\uc2dc\ub3c4 \ud69f\uc218, \uc2e4\ud328 \uc6d0\uc778, \ucd5c\uc885 \ucf54\uba58\ud2b8 ID \uac19\uc740 \uba54\ud0c0\ub370\uc774\ud130\ub9cc \ub0a8\uae30\ub294 \ud3b8\uc774 \ub354 \uc801\ud569\ud558\ub2e4. \uc774\ub807\uac8c \ud558\uba74 DynamoDB \uc544\uc774\ud15c \ud06c\uae30 \uc81c\ud55c\uc744 \ud53c\ud558\uba74\uc11c\ub3c4, \uc2e4\ud328\ud55c \uc791\uc5c5\uc744 \ub2e4\uc2dc \uc2e4\ud589\ud560 \ub54c \uc5b4\ub5a4 \uc785\ub825\uc73c\ub85c \uc5b4\ub290 \ub2e8\uacc4\uc5d0\uc11c \uc2e4\ud328\ud588\ub294\uc9c0 \ucd94\uc801\ud558\uae30 \uc27d\ub2e4.\\n\\n\ub610 \ud558\ub098 \ud544\uc694\ud55c \uac1c\uc120\uc740 \uba71\ub4f1\uc131\uacfc \uad00\uce21\uc131\uc774\ub2e4. GitHub Webhook\uc740 \uac19\uc740 \uc774\ubca4\ud2b8\uac00 \ub2e4\uc2dc \ub4e4\uc5b4\uc62c \uc218 \uc788\uc73c\ubbc0\ub85c \uc774\ubca4\ud2b8 ID, \uc800\uc7a5\uc18c \uc774\ub984, PR \ubc88\ud638, commit SHA\ub97c \uae30\uc900\uc73c\ub85c \uc911\ubcf5 \ucc98\ub9ac\ub97c \ub9c9\uc544\uc57c \ud55c\ub2e4. \uc2e4\ud328\ud55c \uc791\uc5c5\uc740 Dead Letter Queue\ub85c \ubcf4\ub0b4\uace0, CloudWatch dashboard\ub098 OpenTelemetry trace\ub85c Webhook \uc218\uc2e0, diff \uc870\ud68c, \uac80\uc0c9, Bedrock \ud638\ucd9c, GitHub \ucf54\uba58\ud2b8 \uc791\uc131 \uc2dc\uac04\uc744 \ub098\ub220 \ubcfc \uc218 \uc788\uc5b4\uc57c \ud55c\ub2e4.\\n\\n\ub9c8\uc9c0\ub9c9\uc73c\ub85c \ub9ac\ubdf0 \ud488\uc9c8 \uac80\uc99d\ub3c4 \ub354 \uccb4\uacc4\ud654\ud560 \uc218 \uc788\ub2e4. \uc6cc\ud06c\uc20d\uc5d0\uc11c\ub294 100\uac1c \uc774\uc0c1\uc758 \ud14c\uc2a4\ud2b8 PR\ub85c \ud504\ub86c\ud504\ud2b8\uc640 \ucd9c\ub825 \ud488\uc9c8\uc744 \uc9c1\uc811 \ud655\uc778\ud588\uc9c0\ub9cc, \uc774\ud6c4\uc5d0\ub294 \uc7ac\uc2e4\ud589 \uac00\ub2a5\ud55c \ud3c9\uac00 \uc138\ud2b8\ub97c \ub9cc\ub4e4\uace0 \uac80\uc0c9 \uad00\ub828\uc131, \uadfc\uac70\uc131, \uc624\ud0d0, \uc2e4\ud589 \uac00\ub2a5\uc131 \uac19\uc740 \uae30\uc900\uc744 \uc8fc\uae30\uc801\uc73c\ub85c \uce21\uc815\ud558\ub294 \ud3b8\uc774 \uc88b\ub2e4. \uc5ec\uae30\uc5d0 LLM-as-judge\ub97c \ubcf4\uc870 \ud3c9\uac00\uc790\ub85c \ubd99\uc774\uba74 \ub9ac\ubdf0\uac00 \uc2e4\uc81c diff\uc5d0 \uadfc\uac70\ud558\ub294\uc9c0, \uac80\uc0c9\ub41c \ub9ac\ubdf0 \uae30\uc900\uc744 \ubc18\uc601\ud588\ub294\uc9c0, \ubb38\uc81c \uc9c0\uc801\uc774 \uc2e4\ud589 \uac00\ub2a5\ud55c\uc9c0, \ubd88\ud544\uc694\ud55c \uc624\ud0d0\uc774 \uc5c6\ub294\uc9c0\ub97c \ud56d\ubaa9\ubcc4\ub85c \uc810\uac80\ud560 \uc218 \uc788\ub2e4. \ub2e4\ub9cc \ud3c9\uac00\uc790 \ubaa8\ub378\uc758 \uacb0\uacfc\ub9cc \uc2e0\ub8b0\ud558\uc9c0 \uc54a\uace0, \uc77c\ubd80 \uc0d8\ud50c\uc740 \uc0ac\ub78c\uc774 \ub2e4\uc2dc \ud655\uc778\ud574 \ud3c9\uac00 \ud504\ub86c\ud504\ud2b8\uc640 \uc810\uc218 \uae30\uc900\uc744 \ubcf4\uc815\ud574\uc57c \ud55c\ub2e4. \uc774\ub807\uac8c \ud558\uba74 \ubaa8\ub378\uc774\ub098 \ud504\ub86c\ud504\ud2b8\ub97c \ubc14\uafe8\uc744 \ub54c \ub9ac\ubdf0 \ud488\uc9c8\uc774 \uc88b\uc544\uc84c\ub294\uc9c0, \ub2e8\uc21c\ud788 \ubb38\uc7a5\uc774 \uc790\uc5f0\uc2a4\ub7ec\uc6cc\uc9c4 \uac83\uc778\uc9c0 \uad6c\ubd84\ud558\uae30 \uc26c\uc6cc\uc9c4\ub2e4.\\n\\n## \uacb0\uacfc\\n\\n\ucd5c\uc885\uc801\uc73c\ub85c GitHub PR \uc0dd\uc131\ubd80\ud130 diff \uc218\uc9d1, Bedrock \ub9ac\ubdf0 \uc0dd\uc131, GitHub \ucf54\uba58\ud2b8 \ubc18\uc601\uae4c\uc9c0 \uc774\uc5b4\uc9c0\ub294 \uc804\uccb4 \ud750\ub984\uc744 \uad6c\uc131\ud588\ub2e4. 100\uac1c \uc774\uc0c1\uc758 \ud14c\uc2a4\ud2b8 PR\ub85c \ub9ac\ubdf0 \ud488\uc9c8\uc744 \uc810\uac80\ud588\uace0, 2025\ub144 2\uc6d4 19\uc77c ACC Korea \uc18c\uc18d \ub300\ud559\uc0dd 45\uba85\uc774 \uac01\uc790 AWS \uacc4\uc815\uc5d0\uc11c \uc774 \ud750\ub984\uc744 \ub530\ub77c \uad6c\uc131\ud558\ub294 \uc6cc\ud06c\uc20d\uc744 \uc9c4\ud589\ud588\ub2e4.\\n\\n\uc6cc\ud06c\uc20d\uc5d0\uc11c\ub294 \ucc38\uac00\uc790\ub4e4\uc774 \uc11c\ubc84\ub9ac\uc2a4 \uc11c\ube44\uc2a4\uc640 \uc0dd\uc131\ud615 AI \ud638\ucd9c \ud750\ub984\uc744 \uc9c1\uc811 \uc5f0\uacb0\ud574\ubcfc \uc218 \uc788\uc5c8\ub2e4. \uacb0\uacfc\uc801\uc73c\ub85c \ubaa8\ub4e0 \ucc38\uac00\uc790\uac00 \uc2e4\uc2b5\uc744 \ub9c8\ucce4\uace0, \uc0ac\ud6c4 \uc124\ubb38\uc5d0\uc11c \uace0\uac1d\ub9cc\uc871\ub3c4 4.92/5\ub97c \uae30\ub85d\ud588\ub2e4.\\n\\n\uc774 \ud504\ub85c\uc81d\ud2b8\ub97c \ud1b5\ud574 \ubaa8\ub378\uc744 \uc5f0\uacb0\ud558\ub294 \uac83\ub9cc\uc73c\ub85c\ub294 \uc0dd\uc131\ud615 AI \uae30\ub2a5\uc774 \uc644\uc131\ub418\uc9c0 \uc54a\ub294\ub2e4\ub294 \uc810\uc744 \ubc30\uc6e0\ub2e4. \uc2e4\uc81c\ub85c \uc4f8 \uc218 \uc788\ub294 \uc790\ub3d9\ud654\uac00 \ub418\ub824\uba74 \uc785\ub825 \ub370\uc774\ud130\ub97c \uc5b4\ub5bb\uac8c \uad6c\uc870\ud654\ud560\uc9c0, \uc2e4\ud328\ub97c \uc5b4\ub5bb\uac8c \ud655\uc778\ud560\uc9c0, \uc0ac\uc6a9\uc790\uac00 \uc5b4\ub290 \uc9c0\uc810\uc5d0\uc11c \ub9c9\ud788\ub294\uc9c0\uae4c\uc9c0 \ud568\uaed8 \uc124\uacc4\ud574\uc57c \ud55c\ub2e4. LLM PR Reviewer\ub294 \uadf8 \uc810\uc744 \uac00\uc7a5 \uc9c1\uc811\uc801\uc73c\ub85c \uacbd\ud5d8\ud55c \ud504\ub85c\uc81d\ud2b8\uc600\ub2e4."},{"id":"/wasm-bindgen-float16array","metadata":{"permalink":"/projects/wasm-bindgen-float16array","source":"@site/projects/wasm-bindgen-float16array.md","title":"wasm-bindgen Float16Array \uae30\uc5ec","description":"js-sys\uc5d0 Float16Array\uc640 DataView float16 \uc9c0\uc6d0\uc744 \ucd94\uac00\ud558\uba70 Rust stable \uc81c\uc57d \uc544\ub798 public API \uacbd\uacc4\ub97c \uc815\ub9ac\ud55c \uc624\ud508\uc18c\uc2a4 \uae30\uc5ec","date":"2026-06-28T23:16:00.000Z","tags":[],"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"wasm-bindgen Float16Array \uae30\uc5ec","description":"js-sys\uc5d0 Float16Array\uc640 DataView float16 \uc9c0\uc6d0\uc744 \ucd94\uac00\ud558\uba70 Rust stable \uc81c\uc57d \uc544\ub798 public API \uacbd\uacc4\ub97c \uc815\ub9ac\ud55c \uc624\ud508\uc18c\uc2a4 \uae30\uc5ec","role":"Open Source Contributor","timeline":"Mar 2026","stack":["Rust","WebAssembly","JavaScript","js-sys"],"category":"Open Source","image":"/img/projects/wasm-bindgen-float16array/wasm-bindgen-github-card.png","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"LLM PR Reviewer","permalink":"/projects/serverless-code-review"}},"content":"{/* truncate */}\\n\\n# wasm-bindgen Float16Array \uae30\uc5ec\\n\\n## wasm-bindgen\uc740 \uc5b4\ub5a4 \ud504\ub85c\uc81d\ud2b8\uc778\uac00\\n\\n[wasm-bindgen](https://github.com/wasm-bindgen/wasm-bindgen)\uc740 Rust\ub85c \ub9cc\ub4e0 WebAssembly module\uacfc JavaScript \uc0ac\uc774\uc758 binding\uc744 \ub9cc\ub4e4\uc5b4\uc8fc\ub294 \ud504\ub85c\uc81d\ud2b8\ub2e4. Rust\uc5d0\uc11c JavaScript API\ub97c import\ud558\uac70\ub098, Rust \ud568\uc218\ub97c JavaScript\uc5d0\uc11c \ud638\ucd9c\ud560 \uc218 \uc788\uac8c glue code\uc640 type binding\uc744 \uc0dd\uc131\ud55c\ub2e4.\\n\\n\uc774 \ud504\ub85c\uc81d\ud2b8 \uc548\uc5d0\uc11c `js-sys`\ub294 JavaScript \ud45c\uc900 built-in object\ub97c Rust\uc5d0\uc11c \ub2e4\ub8f0 \uc218 \uc788\uac8c \ub178\ucd9c\ud558\ub294 crate\ub2e4. \uc608\ub97c \ub4e4\uc5b4 `Array`, `Promise`, `DataView`, \uc5ec\ub7ec typed array \uac19\uc740 JS API\uac00 `js_sys::*` \ud0c0\uc785\uacfc \uba54\uc11c\ub4dc\ub85c \uc5f0\uacb0\ub41c\ub2e4. \uc774\ubc88 \uc791\uc5c5\uc740 \uadf8\uc911 `js-sys`\uc5d0 \ube60\uc838 \uc788\ub358 `Float16Array`\uc640 `DataView` float16 \uba54\uc11c\ub4dc\ub97c \ucd94\uac00\ud55c \uae30\uc5ec\uc600\ub2e4.\\n\\n## \uc65c \uc774 \uc791\uc5c5\uc744 \ud588\ub294\uac00\\n\\n\ub9c8\uce68 Rust\ub97c \uacf5\ubd80\ud558\uace0 \uc788\uc5c8\uace0, Rust\uc640 WebAssembly\uac00 JavaScript\uc640 \ub9cc\ub098\ub294 \uc9c0\uc810\uc744 \uc9c1\uc811 \ub9cc\uc838\ubcf4\uace0 \uc2f6\uc5c8\ub2e4. \uadf8\ub7ec\ub358 \uc911 wasm-bindgen \uc800\uc7a5\uc18c\uc5d0\uc11c [Issue #4984](https://github.com/wasm-bindgen/wasm-bindgen/issues/4984)\ub97c \ubc1c\uacac\ud588\ub2e4. \ub77c\ubca8\ub3c4 `good first issue`, `js-sys`, `enhancement`\uc600\uace0, \uc124\uba85\ub9cc \ubcf4\uba74 \uae30\uc874 typed array binding\uc744 \ub530\ub77c \ucd94\uac00\ud558\uba74 \ub418\ub294 \uc791\uc5c5\ucc98\ub7fc \ubcf4\uc600\ub2e4.\\n\\n\uc774\uc288\ub294 \uac04\ub2e8\ud588\ub2e4. `Float16Array`\ub294 \uc8fc\uc694 \ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c \uc774\ubbf8 \uc9c0\uc6d0\ub418\uace0 \uc788\uc5c8\uc9c0\ub9cc `js-sys`\uc5d0\ub294 binding\uc774 \uc5c6\uc5c8\uace0, \uae30\uc874 typed array \uc608\uc2dc\ub97c \ub530\ub77c `Float16Array`\ub97c \ucd94\uac00\ud558\uba74\uc11c `DataView`\uc758 \uc0c8 float16 \uba54\uc11c\ub4dc\ub3c4 \ucd94\uac00\ud558\uba74 \ub41c\ub2e4\ub294 \ub0b4\uc6a9\uc774\uc5c8\ub2e4.\\n\\n\ubb38\uc81c\ub294 Rust stable\uc5d0 \uc544\uc9c1 builtin `f16` \ud0c0\uc785\uc774 \uc5c6\ub2e4\ub294 \uc810\uc774\uc5c8\ub2e4. JavaScript\uc758 float16 \uac12\uc740 JS `Number`\ub85c \uc77d\uace0 \uc4f8 \uc218 \uc788\uc9c0\ub9cc, Rust \ucabd public API\uc5d0 \uc5b4\ub5a4 \ud0c0\uc785\uc744 \ub178\ucd9c\ud560\uc9c0\ub294 \ubcc4\uac1c\uc758 \ubb38\uc81c\uc600\ub2e4. `js-sys`\ub294 raw JS binding\uc5d0 \uac00\uae4c\uc6b4 crate\uc774\uae30 \ub54c\ubb38\uc5d0, \ub2e8\uc21c\ud788 \uc678\ubd80 crate\uc758 `half::f16`\uc744 public API\ub85c \ub04c\uc5b4\uc624\uac70\ub098, \ub098\uc911\uc5d0 native `f16`\uc774 \uc0dd\uacbc\uc744 \ub54c \uc368\uc57c \ud560 \uc774\ub984\uc744 \uc9c0\uae08 \ub2e4\ub978 \ud0c0\uc785\uc5d0 \uc368\ubc84\ub9ac\uba74 API\uac00 \uc624\ub798 \ub0a8\ub294 \ubb38\uc81c\uac00 \uc0dd\uae38 \uc218 \uc788\ub2e4.\\n\\n\uadf8\ub798\uc11c \uc774 \uc791\uc5c5\uc758 \ud575\uc2ec\uc740 \\"Float16Array\ub97c \ucd94\uac00\ud55c\ub2e4\\"\uac00 \uc544\ub2c8\ub77c, Rust stable\uc5d0 `f16`\uc774 \uc5c6\ub294 \uc0c1\ud0dc\uc5d0\uc11c \uc9c0\uae08 \uc5f4\uc5b4\ub3c4 \ub418\ub294 public API \uacbd\uacc4\ub97c \uc815\ud558\ub294 \uac83\uc774\uc5c8\ub2e4.\\n\\n## \uc774\uc288\uc640 PR\\n\\n- Issue: [Issue #4984](https://github.com/wasm-bindgen/wasm-bindgen/issues/4984)\\n- PR: [PR #5033](https://github.com/wasm-bindgen/wasm-bindgen/pull/5033)\\n- \ud6c4\uc18d PR: [PR #5067](https://github.com/wasm-bindgen/wasm-bindgen/pull/5067)\\n- \uc0c1\ud0dc: 2026\ub144 3\uc6d4 29\uc77c merge\\n- merge commit: `2c8fe69db`\\n- \ubc94\uc704: `js-sys` public API \ucd94\uac00, wasm test \ucd94\uac00, `CHANGELOG.md` \ubc18\uc601\\n\\n\ucd5c\uc885 merge\ub294 5\uac1c \ud30c\uc77c, 374 lines \ucd94\uac00\uc600\ub2e4.\\n\\n- `CHANGELOG.md`\\n- `crates/js-sys/Cargo.toml`\\n- `crates/js-sys/src/lib.rs`\\n- `crates/js-sys/tests/wasm/DataView.rs`\\n- `crates/js-sys/tests/wasm/TypedArray.rs`\\n\\n\ucd08\uae30\uc5d0\ub294 `half` \uae30\ubc18 \ubcc0\ud658\uacfc `f64` accessor\uae4c\uc9c0 \uac80\ud1a0\ud588\uc9c0\ub9cc, \ucd5c\uc885 \ubc29\ud5a5\uc740 \ub354 \uba85\uc2dc\uc801\uc778 `f32` accessor\uc640 raw `[u16]` helper\uc600\ub2e4.\\n\\n\ucc98\uc74c [Issue #4984](https://github.com/wasm-bindgen/wasm-bindgen/issues/4984)\uc5d0\uc11c \ud655\uc778\ud55c \ubc29\ud5a5\uc740 raw binding\uc744 \uae30\ubcf8\uc73c\ub85c \ub9cc\ub4e4\uace0, `half` crate \ubcc0\ud658\uc744 feature flag \ub4a4\uc5d0 \ub458 \uc218 \uc788\ub294\uc9c0\uc600\ub2e4. \uba54\uc778\ud14c\uc774\ub108\ub294 \ub2f9\uc7a5\uc740 `half`\ub97c \uc9c1\uc811 \uc758\uc874\ud558\uc9c0 \ub9d0\uace0, `half`\uac00 \uc81c\uacf5\ud558\ub294 `u16` bit conversion\uacfc \uc798 \ub9de\ub3c4\ub85d `new_from_u16_slice` \uac19\uc740 helper\ub97c \ub450\ub294 \ud3b8\uc774 \ub0ab\ub2e4\uace0 \uc815\ub9ac\ud588\ub2e4. \uc774\ub54c\ubd80\ud130 raw binding, explicit helper, future `f16` \uc774\ub984 \ubcf4\uc874\uc774\ub77c\ub294 \ubc29\ud5a5\uc774 \uc7a1\ud614\ub2e4.\\n\\n[PR #5033](https://github.com/wasm-bindgen/wasm-bindgen/pull/5033)\uc5d0\uc11c\ub294 \uc774 \ubc29\ud5a5\uc774 \ub9ac\ubdf0\ub97c \uac70\uce58\uba70 \ub354 \ub2e4\ub4ec\uc5b4\uc84c\ub2e4. `TypedArray`\uac00 Atomics generic bound\uc5d0\ub3c4 \uc4f0\uc778\ub2e4\ub294 \uc9c0\uc801\uc774 \uc788\uc5c8\uc9c0\ub9cc, \uae30\uc874 float typed array\uc640\uc758 \uc77c\uad00\uc131\uc744 \uc704\ud574 \uc774 \ubb38\uc81c\ub294 PR \ubc94\uc704 \ubc16\uc73c\ub85c \ube90\ub2e4. \uc774\ud6c4 float16 \uac12\uc740 `f32`\ub85c \uc190\uc2e4 \uc5c6\uc774 \ud45c\ud604\ud560 \uc218 \uc788\uc73c\ub2c8 `*_as_f32`, `*_from_f32` suffix\ub97c \uc4f0\uc790\ub294 \ub9ac\ubdf0\ub97c \ubc18\uc601\ud588\ub2e4. \ub9c8\uc9c0\ub9c9\uc5d0\ub294 `half` \uc0ac\uc6a9 \uc608\ub97c docs/tests\uc5d0 \ucd94\uac00\ud558\uace0 `CHANGELOG.md` entry\ub97c \ub123\uc740 \ub4a4 merge\ub410\ub2e4.\\n\\n## \uad6c\ud604\ud55c \ubc94\uc704\\n\\n### Float16Array raw binding\\n\\n`js_sys::Float16Array` \ud0c0\uc785\uacfc \uae30\ubcf8 JS typed array \uba54\uc11c\ub4dc\ub97c \ucd94\uac00\ud588\ub2e4. \uc0dd\uc131\uc790, buffer, subarray, slice, copyWithin, set, length, byte length, byte offset \uac19\uc740 API\ub97c \uae30\uc874 typed array \ud328\ud134\uc5d0 \ub9de\ucdb0 \uc815\ub9ac\ud588\ub2e4.\\n\\n\uc22b\uc790 \uac12\uc744 \uc9c1\uc811 \ubc1b\uac70\ub098 \ubc18\ud658\ud558\ub294 \uba54\uc11c\ub4dc\ub294 \ubaa8\ub450 \ud0c0\uc785 \uc758\ubbf8\uac00 \ub4dc\ub7ec\ub098\ub3c4\ub85d \uc774\ub984\uc744 \ubd99\uc600\ub2e4.\\n\\n- `fill_with_f32`\\n- `for_each_as_f32`\\n- `try_for_each_as_f32`\\n- `at_as_f32`\\n- `get_index_as_f32`\\n- `set_index_from_f32`\\n\\nunsuffixed \uc774\ub984\uc744 \uc4f0\uc9c0 \uc54a\uc740 \uc774\uc720\ub294 \uc758\ub3c4\uc801\uc774\ub2e4. \uc608\ub97c \ub4e4\uc5b4 `get_index`\ub97c \uc9c0\uae08 `f32` \ubc18\ud658 API\ub85c \uc5f4\uc5b4\ubc84\ub9ac\uba74, \ub098\uc911\uc5d0 Rust native `f16`\uc774 \uc548\uc815\ud654\ub410\uc744 \ub54c \ub354 \uc790\uc5f0\uc2a4\ub7ec\uc6b4 `f16` API \uc774\ub984\uc744 \uc4f0\uae30 \uc5b4\ub835\ub2e4.\\n\\n### DataView float16 accessors\\n\\n\ucc98\uc74c\uc5d0\ub294 numeric helper\ub97c \uc5b4\ub5a4 \ud0c0\uc785\uc73c\ub85c \ub458\uc9c0 \uc5ec\ub7ec \ubc29\ud5a5\uc744 \uac80\ud1a0\ud588\ub2e4. \ub9ac\ubdf0\ub97c \uac70\uce58\uba70 \ucd5c\uc885 \ubc29\ud5a5\uc740 `f32` \uae30\ubc18\uc758 \uba85\uc2dc\uc801 \uc774\ub984\uc73c\ub85c \uc815\ub9ac\ub410\ub2e4.\\n\\n- `get_float16_as_f32`\\n- `get_float16_endian_as_f32`\\n- `set_float16_from_f32`\\n- `set_float16_endian_from_f32`\\n\\n`f32`\ub294 float16 \uac12\uc744 \uc190\uc2e4 \uc5c6\uc774 \ud45c\ud604\ud560 \uc218 \uc788\uace0, WebAssembly\uc5d0\uc11c\ub3c4 native numeric type\uc774\ub2e4. \uc774 \uacb0\uc815\uc740 \ub9ac\ubdf0\uc5d0\uc11c \ub098\uc628 \uc758\uacac\uc744 \ubc18\uc601\ud55c \uac83\uc774\ub2e4. \ucc98\uc74c \ucd08\uc548\uc740 `f64` \ucabd\uc744 \ubcf4\uace0 \uc788\uc5c8\uc9c0\ub9cc, `f32`\ub85c \ucda9\ubd84\ud558\ub2e4\uba74 \ub354 \uc791\uc740 \ud0c0\uc785\uc744 \uba85\uc2dc\ud558\ub294 \ud3b8\uc774 \ub0ab\uace0, \uc774\ub984\uc5d0\ub3c4 `as_f32`, `from_f32`\ub97c \ubd99\uc5ec future native `f16` API\uc640 \ucda9\ub3cc\ud558\uc9c0 \uc54a\uac8c \ub9cc\ub4e4 \uc218 \uc788\uc5c8\ub2e4.\\n\\n### Raw u16 helper API\\n\\nfloat16\uc758 binary16 bit pattern\uc744 \uc9c1\uc811 \ub2e4\ub8f0 \uc218 \uc788\ub3c4\ub85d `[u16]` helper\ub3c4 \ucd94\uac00\ud588\ub2e4.\\n\\n- `new_from_u16_slice`\\n- `copy_to_u16_slice`\\n- `copy_from_u16_slice`\\n- `to_u16_vec`\\n\\n\uc774 helper\ub4e4\uc740 `Float16Array`\uac00 \ubc14\ub77c\ubcf4\ub294 `ArrayBuffer`, `byte_offset`, `length`\ub97c \uadf8\ub300\ub85c \uc0ac\uc6a9\ud574 \ub0b4\ubd80\uc801\uc73c\ub85c `Uint16Array` view\ub97c \ub9cc\ub4e0\ub2e4. \uadf8 \ub2e4\uc74c \uae30\uc874 `Uint16Array`\uc758 `copy_to`, `copy_from`, `to_vec` \uad6c\ud604\uc744 \uc7ac\uc0ac\uc6a9\ud55c\ub2e4.\\n\\n\uc774 \ubc29\uc2dd\uc740 float16 \uac12\uc744 \\"\uc22b\uc790 \ud0c0\uc785\\"\uc73c\ub85c \uac00\uc7a5\ud558\uc9c0 \uc54a\uace0, \uc2e4\uc81c \uc800\uc7a5 \ub2e8\uc704\uc778 IEEE 754 binary16 bit pattern\uc744 \uadf8\ub300\ub85c \ub2e4\ub8ec\ub2e4. `half` crate\ub294 public API dependency\ub85c \uac15\uc81c\ud558\uc9c0 \uc54a\uc558\ub2e4. \ub300\uc2e0 doc comment\uc640 wasm test\uc5d0\uc11c `half::f16::to_bits`, `half::f16::from_bits` \uc608\uc2dc\ub97c \ubcf4\uc5ec \uc8fc\ub294 \ubc29\uc2dd\uc73c\ub85c \uc2e4\uc81c \uc0ac\uc6a9 \ud750\ub984\uc744 \uc124\uba85\ud588\ub2e4.\\n\\n## \ud574\uacb0\ud574\uc57c \ud588\ub358 \ubb38\uc81c\ub4e4\\n\\n### Rust stable\uc5d0 f16\uc774 \uc5c6\uc5c8\ub2e4\\n\\n\ucc98\uc74c\ubd80\ud130 \uac00\uc7a5 \ud070 \uc81c\uc57d\uc740 Rust stable\uc5d0 builtin `f16`\uc774 \uc5c6\ub2e4\ub294 \uc810\uc774\uc5c8\ub2e4. \uadf8\ub798\uc11c `Float16Array`\ub97c `Float32Array`\ub098 `Float64Array`\ucc98\ub7fc \uc790\uc5f0\uc2a4\ub7fd\uac8c Rust primitive type\uacfc \uc5f0\uacb0\ud560 \uc218 \uc5c6\uc5c8\ub2e4.\\n\\n\ud574\uacb0 \ubc29\ud5a5\uc740 \uc138 \uce35\uc73c\ub85c \ub098\ub234\ub2e4.\\n\\n- JS API \uc790\uccb4\ub294 raw binding\uc73c\ub85c \ucd94\uac00\ud55c\ub2e4.\\n- \uc22b\uc790\ub85c \uc77d\uace0 \uc4f0\ub294 API\ub294 `f32`\uc784\uc744 \uc774\ub984\uc5d0 \ub4dc\ub7ec\ub0b8\ub2e4.\\n- raw binary16 bit pattern\uc740 `[u16]` helper\ub85c \ub2e4\ub8ec\ub2e4.\\n\\n\uc774\ub807\uac8c \ud558\uba74 \uc9c0\uae08\uc740 \uc548\uc815\uc801\uc778 Rust \ud0c0\uc785\ub9cc \uc0ac\uc6a9\ud558\uba74\uc11c, \ub098\uc911\uc5d0 native `f16`\uc774 \uc548\uc815\ud654\ub410\uc744 \ub54c unsuffixed \uc774\ub984\uc744 \uc0c8 API\uc5d0 \ub0a8\uaca8\ub458 \uc218 \uc788\ub2e4.\\n\\n### f64 \ucd08\uc548\uc5d0\uc11c f32 API\ub85c \ubc14\ub00c\uc5c8\ub2e4\\n\\n\ucd08\uae30 PR \uc124\uba85\uacfc \uc77c\ubd80 \uc911\uac04 \uae30\ub85d\uc5d0\ub294 `f64` accessor\uac00 \ub0a8\uc544 \uc788\ub2e4. \ub2f9\uc2dc\uc5d0\ub294 JS `Number` \ubaa8\ub378\uacfc \uae30\uc874 `DataView` float API\ub97c \uc758\uc2dd\ud574 `f64`\ub97c \uac80\ud1a0\ud588\ub2e4. \ud558\uc9c0\ub9cc \ub9ac\ubdf0\uc5d0\uc11c `f32`\ub3c4 native Wasm type\uc774\uace0 float16\uc744 \uc190\uc2e4 \uc5c6\uc774 \ud45c\ud604\ud558\uae30\uc5d0 \ucda9\ubd84\ud558\ub2e4\ub294 \ud53c\ub4dc\ubc31\uc774 \ub098\uc654\ub2e4.\\n\\n\uadf8 \uacb0\uacfc `DataView`\uc640 `Float16Array`\uc758 \uc9c1\uc811 numeric API\ub97c \uc804\ubd80 `f32` \uae30\ubc18\uc73c\ub85c \ubc14\uafe8\ub2e4. \ub3d9\uc2dc\uc5d0 \uc774\ub984\ub3c4 `get_float16_as_f32`, `set_float16_from_f32`, `fill_with_f32`\ucc98\ub7fc \ubc14\uafe8\ub2e4. \ud0c0\uc785\uc744 \ubc14\uafb8\ub294 \uac83\ub9cc\uc73c\ub85c\ub294 \ubd80\uc871\ud588\uace0, API \uc774\ub984\uc5d0\ub3c4 \\"\uc774\uac74 native `f16`\uc774 \uc544\ub2c8\ub77c `f32` \uacbd\uc720 API\\"\ub77c\ub294 \uc758\ubbf8\uac00 \ub0a8\uc544\uc57c \ud588\ub2e4.\\n\\n### half\ub97c \uc4f0\uc9c0 \uc54a\ub294\ub2e4\ub294 \ub9d0\uc758 \uc758\ubbf8\uac00 \uc815\ub9ac\ub410\ub2e4\\n\\n\ucc98\uc74c \ubc29\ud5a5\uc740 \\"`half`\ub97c hard dependency\ub85c \ub9cc\ub4e4\uc9c0 \uc54a\ub294\ub2e4\\"\uc600\ub2e4. \uc5ec\uae30\uc11c \ud5f7\uac08\ub9b4 \uc218 \uc788\ub294 \ubd80\ubd84\uc740 \\"\uc544\uc608 `half`\ub97c \uc5b8\uae09\ud558\uc9c0 \uc54a\ub294\ub2e4\\"\uac00 \uc544\ub2c8\ub77c\ub294 \uc810\uc774\ub2e4.\\n\\n\ucd5c\uc885\uc801\uc73c\ub85c `half`\ub294 normal dependency\ub098 public API type\uc73c\ub85c \ub4e4\uc5b4\uac00\uc9c0 \uc54a\uc558\ub2e4. \ub300\uc2e0 `[u16]` helper\uc758 \ub300\ud45c \uc0ac\uc6a9 \ubc29\uc2dd\uc774 `half::f16::to_bits`\uc640 `half::f16::from_bits`\uac00 \ub420 \uac00\ub2a5\uc131\uc774 \ub192\uae30 \ub54c\ubb38\uc5d0, doc comment\uc640 test\uc5d0\uc11c\ub294 \uadf8 \ud750\ub984\uc744 \ubcf4\uc5ec\uc92c\ub2e4. \uc989 \uc0ac\uc6a9\uc790\ub294 \uc6d0\ud558\uba74 `half`\ub97c \uc790\uae30 \ucf54\ub4dc\uc5d0\uc11c \uc4f8 \uc218 \uc788\uc9c0\ub9cc, `js-sys` API \uc790\uccb4\uac00 `half`\uc5d0 \ubb36\uc774\uc9c0\ub294 \uc54a\ub294\ub2e4.\\n\\n### TypedArray\uc640 Atomics trait \uc758\ubbf8\uac00 \uac78\ub838\ub2e4\\n\\n\ub9ac\ubdf0 \uc911 `impl TypedArray for Float16Array {}`\uc5d0 \ub300\ud55c \uc9c0\uc801\uc774 \uc788\uc5c8\ub2e4. \uc774 repo\uc5d0\uc11c `TypedArray`\ub294 \ub2e8\uc21c marker\ucc98\ub7fc \ubcf4\uc774\uc9c0\ub9cc, \uc2e4\uc81c\ub85c\ub294 `Atomics::*` generic bound\uc5d0\ub3c4 \uc4f0\uc778\ub2e4. `Float16Array`\uc5d0 `TypedArray`\ub97c \uad6c\ud604\ud558\uba74, \uc6d0\ub798 float16\uc5d0\ub294 \ub9de\uc9c0 \uc54a\ub294 atomic API surface\uac00 \uac19\uc774 \uc5f4\ub9b4 \uc218 \uc788\ub2e4\ub294 \ubb38\uc81c\uc600\ub2e4.\\n\\n\uc774 \ubd80\ubd84\uc740 \ub0b4\uac00 \ucc98\uc74c \uad6c\ud604\ud560 \ub54c \ub193\uce5c \uc9c0\uc810\uc774\uc5c8\ub2e4. \uae30\uc874 `Float32Array`, `Float64Array`\ub3c4 \uac19\uc740 \ubc29\uc2dd\uc73c\ub85c \ub4e4\uc5b4\uac00 \uc788\uc5c8\uae30 \ub54c\ubb38\uc5d0 \ud328\ud134\uc744 \ub530\ub77c\uac14\uc9c0\ub9cc, \uadf8 \ud328\ud134 \uc790\uccb4\uac00 \uc644\uc804\ud788 \uae68\ub057\ud55c \uc124\uacc4\ub294 \uc544\ub2c8\uc5c8\ub2e4.\\n\\n\ucd5c\uc885 \uacb0\uc815\uc740 \uc774\ubc88 PR\uc5d0\uc11c `Float16Array`\ub9cc \ub2e4\ub974\uac8c \uace0\uce58\uc9c0 \uc54a\ub294 \ucabd\uc774\uc5c8\ub2e4. RReverser\ub294 \uae30\uc874 float typed array\uc640 \uc77c\uad00\uc131\uc744 \uc720\uc9c0\ud558\uace0, atomic bound \ubb38\uc81c\ub294 \ub098\uc911\uc5d0 \uc804\uccb4\uc801\uc73c\ub85c \uace0\uce58\ub294 \ud3b8\uc774 \ub0ab\ub2e4\uace0 \uc815\ub9ac\ud588\ub2e4. \uadf8\ub798\uc11c \uc774 \uc774\uc288\ub294 [PR #5033](https://github.com/wasm-bindgen/wasm-bindgen/pull/5033) \ubc94\uc704 \ubc16\uc73c\ub85c \ube7c\uace0, `Float16Array`\ub294 \uae30\uc874 float typed array\ub4e4\uacfc \uac19\uc740 \ubc29\ud5a5\uc73c\ub85c merge\ub410\ub2e4.\\n\\n### runtime feature detection\uc774 \ud544\uc694\ud588\ub2e4\\n\\n`Float16Array`\uc640 `DataView.getFloat16`\uc740 \ubaa8\ub4e0 JS runtime\uc5d0\uc11c \ud56d\uc0c1 \uc788\ub294 API\uac00 \uc544\ub2c8\ub2e4. \uadf8\ub798\uc11c \ud14c\uc2a4\ud2b8\ub97c \uadf8\ub0e5 \ucd94\uac00\ud558\uba74, API\ub97c \uc544\uc9c1 \uc9c0\uc6d0\ud558\uc9c0 \uc54a\ub294 \ud658\uacbd\uc5d0\uc11c \uc804\uccb4 `js-sys` \ud14c\uc2a4\ud2b8\uac00 \uae68\uc9c8 \uc218 \uc788\ub2e4.\\n\\n\uc774 \ubb38\uc81c\ub294 \ud14c\uc2a4\ud2b8\uc5d0 runtime guard\ub97c \ub123\uc5b4\uc11c \ud574\uacb0\ud588\ub2e4.\\n\\n- `TypedArray.rs`\uc5d0\ub294 `has_float16_array`\ub97c \ub450\uace0 `globalThis.Float16Array` \uc874\uc7ac \uc5ec\ubd80\ub97c \ud655\uc778\ud588\ub2e4.\\n- `DataView.rs`\uc5d0\ub294 `has_float16_methods`\ub97c \ub450\uace0 `DataView.prototype.getFloat16`, `setFloat16` \uc874\uc7ac \uc5ec\ubd80\ub97c \ud655\uc778\ud588\ub2e4.\\n\\n\uc774\ub807\uac8c \ud574\uc11c API\uac00 \uc788\ub294 \ud658\uacbd\uc5d0\uc11c\ub294 \uc2e4\uc81c \ub3d9\uc791\uc744 \uac80\uc99d\ud558\uace0, \uc544\uc9c1 \uc9c0\uc6d0\ud558\uc9c0 \uc54a\ub294 \ud658\uacbd\uc5d0\uc11c\ub294 \uad00\ub828 \ud14c\uc2a4\ud2b8\ub9cc \uac74\ub108\ub6f0\uac8c \ud588\ub2e4.\\n\\n## \uac80\uc99d\\n\\n\ucc98\uc74c WSL\uc5d0\uc11c\ub294 \ucef4\ud30c\uc77c \uac80\uc99d\ubd80\ud130 \uc9c4\ud589\ud588\ub2e4.\\n\\n```bash\\ncargo test -p js-sys --target wasm32-unknown-unknown --no-run\\n```\\n\\n\uc774 \ub2e8\uacc4\ub294 \ud1b5\uacfc\ud588\ub2e4. \ubb38\uc81c\ub294 \uc804\uccb4 wasm \ud14c\uc2a4\ud2b8\uc600\ub2e4. `cargo test -p js-sys --target wasm32-unknown-unknown`\ub97c \ub05d\uae4c\uc9c0 \ub3cc\ub9ac\ub824\uba74 `wasm-bindgen-test-runner`\uac00 browser test\uae4c\uc9c0 \uc2e4\ud589\ud574\uc57c \ud558\uace0, \uc774\ub97c \uc704\ud574 WebDriver\uac00 \ud544\uc694\ud588\ub2e4.\\n\\nWSL\uc5d0\uc11c \ubc14\ub85c \ub9c9\ud78c \uc774\uc720\ub294 \uc138 \uac00\uc9c0\uc600\ub2e4.\\n\\n- WSL \ub0b4\ubd80\uc5d0 `geckodriver`, `chromedriver`, `msedgedriver`\uac00 \uc5c6\uc5c8\ub2e4.\\n- Windows Chrome/ChromeDriver\ub97c WSL\uc5d0\uc11c \ubd99\uc774\ub824 \ud588\uc9c0\ub9cc loopback\uacfc WSL \ub124\ud2b8\uc6cc\ud06c \uacbd\uacc4 \ub54c\ubb38\uc5d0 \uc548\uc815\uc801\uc73c\ub85c \uc5f0\uacb0\ub418\uc9c0 \uc54a\uc558\ub2e4.\\n- Linux\uc6a9 Chrome for Testing\uacfc ChromeDriver\ub97c WSL \uc548\uc5d0\uc11c \uc9c1\uc811 \ub744\uc6b0\ub294 \ubc29\uc2dd\uc740 \ub9ac\uc18c\uc2a4 \uc0ac\uc6a9\ub7c9\uc774 \ucee4\uc11c \uc2e4\ud589 \uc911 \uac15\uc81c \uc885\ub8cc\ub410\ub2e4.\\n\\n\uadf8\ub798\uc11c \ucd5c\uc885 \uac80\uc99d\uc740 Windows native \ud658\uacbd\uc5d0\uc11c \uc9c4\ud589\ud588\ub2e4. Windows Rust toolchain\uc5d0 wasm target\uc744 \ucd94\uac00\ud558\uace0, ChromeDriver \uacbd\ub85c\ub97c \ud658\uacbd\ubcc0\uc218\ub85c \uc9c0\uc815\ud55c \ub4a4 \uac19\uc740 \ud14c\uc2a4\ud2b8\ub97c \ub2e4\uc2dc \uc2e4\ud589\ud588\ub2e4.\\n\\n```powershell\\nrustup target add wasm32-unknown-unknown\\n$env:CHROMEDRIVER = \\"C:\\\\Users\\\\ChanhoLee\\\\Tools\\\\WebDriver\\\\chromedriver.exe\\"\\ncd D:\\\\code\\\\wasm-bindgen\\ncargo test -p js-sys --target wasm32-unknown-unknown\\n```\\n\\n\uc791\uc5c5 \ubcf4\uace0\uc11c \uae30\uc900 \ucd5c\uc885 \uacb0\uacfc\ub294 \uc544\ub798\uc640 \uac19\uc558\ub2e4.\\n\\n- `tests/browser.rs` \ud1b5\uacfc\\n- `tests/node.rs` \ud1b5\uacfc\\n- `tests/wasm/main.rs` \ud1b5\uacfc\\n- `700 passed`\\n- `0 failed`\\n- `5 ignored`\\n\\n\uc774\ubc88 \ubcc0\uacbd\uacfc \uc9c1\uc811 \uad00\ub828\ub41c `TypedArray::float16array_basic_methods`, `TypedArray::float16array_u16_helpers`, `DataView::test`\ub3c4 \uc774 \ud750\ub984 \uc548\uc5d0\uc11c \ud1b5\uacfc\ud588\ub2e4. \uc989 \ucd5c\uc885 \uc0c1\ud0dc\ub294 \ub2e8\uc21c\ud788 `--no-run` \ucef4\ud30c\uc77c\ub9cc \ub41c \uac83\uc774 \uc544\ub2c8\ub77c, Windows native \ud658\uacbd\uc5d0\uc11c `js-sys` wasm \ud14c\uc2a4\ud2b8\ub97c \uc2e4\uc81c\ub85c \uc2e4\ud589\ud55c \uc0c1\ud0dc\uc600\ub2e4.\\n\\n## \uc9c4\ud589 \uc911 \uc0dd\uae34 CI\uc640 \ub9ac\ubdf0 \uc774\uc288\\n\\nPR \uc911\uac04\uc5d0 CodSpeed regression\uacfc `wasm-bindgen-cli` reference test \uc2e4\ud328\ub3c4 \ud655\uc778\ud588\ub2e4. \uc870\uc0ac \uacb0\uacfc `Float16Array` \ubcc0\uacbd\uc774 `JsValue::from_str` hot path\ub97c \uc9c1\uc811 \uac74\ub4dc\ub9b0 \uac83\uc740 \uc544\ub2c8\uc5c8\uace0, reference test \uc2e4\ud328\ub294 `.wat` type section ordering \ucabd\uc758 snapshot fragility\ub85c \ubcf4\ub294 \ucabd\uc774 \ub354 \uc124\ub4dd\ub825 \uc788\uc5c8\ub2e4.\\n\\nCodSpeed \ucabd\uc5d0\uc11c\ub294 `bench_js_value_from_str`\uac00 \ub290\ub824\uc9c4 \uac83\uc73c\ub85c \ud45c\uc2dc\ub41c \uc801\uc774 \uc788\uc5c8\ub2e4. \uc774\ub54c PR \ucee4\ubc0b\uacfc merge commit\uc744 \ub2e4\uc2dc \ubcf4\uace0, \uc2e4\uc81c\ub85c \uac74\ub4dc\ub9b0 \ud30c\uc77c\ub3c4 \ud655\uc778\ud588\ub2e4. \ubcc0\uacbd \ubc94\uc704\ub294 `js-sys`\uc758 `Float16Array`, `DataView`, test, changelog\uc600\uace0 `JsValue::from_str` \uad00\ub828 hot path\ub97c \uc9c1\uc811 \uc218\uc815\ud558\uc9c0 \uc54a\uc558\ub2e4. \uadf8\ub798\uc11c \ud655\uc815 \uc6d0\uc778\uc744 \ub2e8\uc815\ud558\uc9c0 \uc54a\uace0, \uc774 PR \ucf54\ub4dc\uac00 \ud574\ub2f9 benchmark\ub97c \uc9c1\uc811 \ub290\ub9ac\uac8c \ub9cc\ub4e4\uc5c8\ub2e4\uace0 \ubcf4\uae30\ub294 \uc5b4\ub835\ub2e4\uace0 \ud310\ub2e8\ud588\ub2e4.\\n\\n`wasm-bindgen-cli` reference test \uc2e4\ud328\ub294 `.wat` \ucd9c\ub825\uc758 `type (;N;)` \uc21c\uc11c\uc640 type index \ubc88\ud638 \ucc28\uc774\uc5d0 \uac00\uae4c\uc6e0\ub2e4. \ub85c\uceec \uc870\uc0ac\uc5d0\uc11c\ub294 runtime behavior \ucc28\uc774\ub77c\uae30\ubcf4\ub2e4 snapshot ordering \ubb38\uc81c\ub85c \ubcf4\uc600\ub2e4. `reference.rs`\uac00 import order\uc640 local function order\ub294 \uc548\uc815\ud654\ud558\uc9c0\ub9cc type section ordering\uae4c\uc9c0 canonicalize\ud558\uc9c0\ub294 \uc54a\ub294\ub2e4\ub294 \uc810\ub3c4 \ud655\uc778\ud588\ub2e4. \ube44\uc2b7\ud55c \uc2e4\ud328\uac00 \ub2e4\ub978 open PR\uc5d0\uc11c\ub3c4 \ubcf4\uc600\uae30 \ub54c\ubb38\uc5d0, \uc774 \ubb38\uc81c\ub294 \uc774\ubc88 `Float16Array` \uad6c\ud604 \ubc84\uadf8\ub77c\uae30\ubcf4\ub2e4 upstream reference snapshot fragility\ub85c \ubd84\ub9ac\ud574\uc11c \ubd24\ub2e4.\\n\\n\ub9ac\ubdf0 \ub9c9\ubc14\uc9c0\uc5d0\ub294 `CHANGELOG.md` entry\ub3c4 \ucd94\uac00\ud588\ub2e4. \ub2e8\uc21c \ucf54\ub4dc \ubcc0\uacbd\ub9cc\uc774 \uc544\ub2c8\ub77c public API \ucd94\uac00\uac00 release-facing \uae30\ub85d\uc5d0\ub3c4 \ub0a8\uc544\uc57c \ud588\uae30 \ub54c\ubb38\uc5d0, \ucd5c\uc885 PR\uc5d0\ub294 changelog \ubc18\uc601\uae4c\uc9c0 \ud3ec\ud568\ub410\ub2e4.\\n\\n## merge \ud6c4 \ud6c4\uc18d \uc218\uc815\\n\\n[PR #5033](https://github.com/wasm-bindgen/wasm-bindgen/pull/5033)\uc774 merge\ub41c \ub4a4 [PR #5067](https://github.com/wasm-bindgen/wasm-bindgen/pull/5067)\uc5d0\uc11c `Float16Array::fill_with_f32`\uc5d0 \ube60\uc9c4 `js_name = \\"fill\\"`\uc774 \ubcf4\uc644\ub410\ub2e4.\\n\\n[PR #5067](https://github.com/wasm-bindgen/wasm-bindgen/pull/5067) \ubcf8\ubb38\uc5d0\ub294 \uc6d0\uc778\uc774 \uba85\ud655\ud788 \uc801\ud600 \uc788\uc5c8\ub2e4. `Float16Array::fill_with_f32`\uc5d0 `js_name = \\"fill\\"`\uc774 \ube60\uc838 \uc788\uc5b4\uc11c, binding\uc774 JavaScript \uac1d\uccb4\uc758 native `fill()`\uc774 \uc544\ub2c8\ub77c \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294 `fill_with_f32`\ub77c\ub294 \uba54\uc11c\ub4dc\ub97c \ud638\ucd9c\ud558\uac8c \ub418\ub294 \ubc84\uadf8\uc600\ub2e4. \uc774 \ubb38\uc81c\ub294 \uc55e\uc120 `Float16Array` binding\uc744 \uc870\uc0ac\ud558\ub358 \uc911 \ubc1c\uacac\ub410\uace0, Guy Bedford\uac00 2026\ub144 3\uc6d4 30\uc77c\uc5d0 \ud55c \uc904 \uc218\uc815\uc73c\ub85c merge\ud588\ub2e4.\\n\\n\uc6d0\uc778\uc740 \uc774\ub984 \ubcc0\uacbd \uacfc\uc815\uc5d0 \uc788\uc5c8\ub2e4. \ucc98\uc74c\uc5d0\ub294 Rust \uba54\uc11c\ub4dc \uc774\ub984\ub3c4 `fill`\uc774\uc5c8\ub2e4\uac00, \ub9ac\ubdf0\ub97c \ubc18\uc601\ud558\uba74\uc11c `fill_with_f32`\ub85c \ubc14\ub00c\uc5c8\ub2e4. \uadf8\ub7f0\ub370 `#[wasm_bindgen(method)]`\ub9cc \ub0a8\uc544 \uc788\uc73c\uba74 wasm-bindgen\uc740 Rust \uba54\uc11c\ub4dc \uc774\ub984\uc744 JS \uba54\uc11c\ub4dc \uc774\ub984\uc73c\ub85c \uc0ac\uc6a9\ud558\ub824\uace0 \ud55c\ub2e4. JavaScript\uc758 \uc2e4\uc81c \uba54\uc11c\ub4dc\ub294 `fill`\uc774\ubbc0\ub85c, Rust \ucabd \uc774\ub984\uc744 `fill_with_f32`\ub85c \ubc14\uafe8\ub2e4\uba74 attribute\uc5d0 `js_name = fill`\uc744 \uba85\uc2dc\ud574\uc57c \ud588\ub2e4.\\n\\n[PR #5067](https://github.com/wasm-bindgen/wasm-bindgen/pull/5067)\uc758 \uc218\uc815\uc740 \ud55c \uc904\uc774\uc5c8\ub2e4.\\n\\n```rust\\n#[wasm_bindgen(method, js_name = fill)]\\npub fn fill_with_f32(this: &Float16Array, value: f32, start: u32, end: u32) -> Float16Array;\\n```\\n\\n\uc774 \ud6c4\uc18d \uc218\uc815\uae4c\uc9c0 \ubcf4\uba74, \uc774\ubc88 \uc791\uc5c5\uc5d0\uc11c \ub0a8\uc740 \uc2e4\uc218\ub294 \\"API \uc774\ub984\uc744 Rust \ucabd\uc5d0\uc11c \uba85\uc2dc\uc801\uc73c\ub85c \ubc14\uafb8\ub294 \uacfc\uc815\uc5d0\uc11c JS method mapping\uc744 \ub05d\uae4c\uc9c0 \uac19\uc774 \ub9de\ucd94\uc9c0 \ubabb\ud55c \uac83\\"\uc774\uc5c8\ub2e4. \ud574\uacb0\uc740 `wasm_bindgen` attribute\uc5d0 \uc2e4\uc81c JS \uc774\ub984\uc744 \uba85\uc2dc\ud558\ub294 \ubc29\uc2dd\uc774\uc5c8\ub2e4.\\n\\n## \uacb0\uacfc\\n\\n[PR #5033](https://github.com/wasm-bindgen/wasm-bindgen/pull/5033)\uc740 2026\ub144 3\uc6d4 29\uc77c merge\ub410\ub2e4. \ucd5c\uc885\uc801\uc73c\ub85c `js_sys::Float16Array`, `DataView` float16 accessor, `Float16Array`\uc758 `f32` \uae30\ubc18 \uc22b\uc790 \uba54\uc11c\ub4dc, raw `[u16]` helper API\uac00 \ub4e4\uc5b4\uac14\ub2e4.\\n\\n\uc774 \uc791\uc5c5\uc5d0\uc11c \uc911\uc694\ud55c \ud310\ub2e8\uc740 Rust stable\uc5d0 \uc5c6\ub294 \ud0c0\uc785\uc744 public API\ucc98\ub7fc \uac00\uc7a5\ud558\uc9c0 \uc54a\ub294 \uac83\uc774\uc5c8\ub2e4. JS binding\uc740 \ucd94\uac00\ud558\ub418, Rust \ucabd helper\ub294 `f32`\uc640 `u16`\uc774\ub77c\ub294 \ud604\uc7ac \uc548\uc815\uc801\uc778 \ud45c\ud604\uc73c\ub85c \uc81c\ud55c\ud588\ub2e4. \ub3d9\uc2dc\uc5d0 \uc774\ub984\uc5d0\ub294 \ud0c0\uc785 \uc758\ubbf8\ub97c \ub0a8\uaca8\uc11c, future native `f16` API\uac00 \ub4e4\uc5b4\uc62c \uc790\ub9ac\ub97c \ube44\uc6cc\ub480\ub2e4.\\n\\n## References\\n\\n- [wasm-bindgen repository](https://github.com/wasm-bindgen/wasm-bindgen)\\n- [wasm-bindgen guide](https://wasm-bindgen.github.io/wasm-bindgen/)\\n- [Issue #4984: Float16Array bindings](https://github.com/wasm-bindgen/wasm-bindgen/issues/4984)\\n- [PR #5033: Add Float16Array bindings](https://github.com/wasm-bindgen/wasm-bindgen/pull/5033)\\n- [PR #5067: fix(js-sys): add missing js_name = \\"fill\\" to Float16Array::fill_with_f32](https://github.com/wasm-bindgen/wasm-bindgen/pull/5067)"}]}}')}}]);